  { name: 'Rutas y Despacho', href: `/store/${storeId}/vendors/routes`, icon: MapPin, section: 'Operacion' },
  { name: 'Historial Ventas', href: `/store/${storeId}/vendors/sales`, icon: PackagePlus, section: 'Operacion' },
  { name: translations[lang].addClient, href: `/store/${storeId}/vendors/clients`, icon: Users, section: 'Comercial' },
  { name: 'Gestionar Zonas', href: `/store/${storeId}/vendors/zones`, icon: Map, section: 'Comercial' },
  { name: translations[lang].collections, href: `/store/${storeId}/vendors/collections`, icon: HandCoins, section: 'Comercial' },
  { name: translations[lang].vendorInventory, href: `/store/${storeId}/vendors/inventory`, icon: Boxes, section: 'Comercial' },
  { name: translations[lang].routeStaff, href: `/store/${storeId}/vendors`, icon: UsersRound, section: 'Comercial' },

  { name: translations[lang].help, href: `/store/${storeId}/help`, icon: LifeBuoy, section: 'Apoyo' },
];

const buildNotificationKey = (event: RealtimeEvent | null) => {
  if (!event) return '';
  return [
    event.type,
    event.storeId,
    event.payload?.id,
    event.payload?.productId,
    event.payload?.reference,
    event.payload?.createdAt,
    event.payload?.updatedAt,
  ]
    .filter(Boolean)
    .join(':');
};

const buildRealtimeNotification = (
  event: RealtimeEvent | null,
  currentUserId?: string,
  fallbackStoreId?: string,
  isGlobalAdmin = false,
): Notification | null => {
  if (!event) return null;
  const effectiveStoreId = event.storeId || event.payload?.storeId || fallbackStoreId;
  const baseStorePath = effectiveStoreId ? `/store/${effectiveStoreId}` : null;
  const fallbackHref = isGlobalAdmin ? '/master-admin/monitor' : '/';
  const id = buildNotificationKey(event);

  if (!event.type || !id) {
    return null;
  }

  switch (event.type) {
    case 'NEW_ORDER':
      return {
        id,
        title: 'Nuevo pedido',
        description: `Pedido ${event.payload?.id || ''} por C$ ${Number(event.payload?.total || 0).toFixed(2)}`.trim(),
        href: baseStorePath ? `${baseStorePath}/pending-orders` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    case 'NEW_VISIT':
      return {
        id,
        title: 'Nueva visita',
        description: `Visita registrada${event.payload?.clientId ? ` para cliente ${event.payload.clientId}` : ''}`,
        href: baseStorePath ? `${baseStorePath}/vendors/dashboard` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    case 'PRODUCT_CREATED':
      return {
        id,
        title: 'Producto creado',
        description: event.payload?.description || 'Se registró un producto nuevo.',
        href: baseStorePath ? `${baseStorePath}/products` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    case 'PRODUCT_UPDATED':
      return {
        id,
        title: 'Producto actualizado',
        description: event.payload?.description || 'Se actualizó un producto.',
        href: baseStorePath ? `${baseStorePath}/products` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    case 'NOTIFICATION':
      return {
        id,
        title: event.payload?.title || 'Nuevo Aviso',
        description: event.payload?.message || 'Tienes una nueva notificación.',
        href: fallbackHref, // Notifications aren't always bound to a specific route
        userId: currentUserId || 'system',
        read: false,
      };
    case 'ORDER_STATUS_CHANGE':
      return {
        id,
        title: `Pedido ${event.payload?.orderId?.substring(0, 8)}`,
        description: `Ha cambiado a estado: ${event.payload?.status?.replace('_', ' ')}`,
        href: baseStorePath ? `${baseStorePath}/pending-orders` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    case 'INVENTORY_UPDATE':
      return {
        id,
        title: 'Inventario actualizado',
        description: `Movimiento ${event.payload?.type || ''}${event.payload?.quantity ? ` por ${event.payload.quantity}` : ''}`.trim(),
        href: baseStorePath ? `${baseStorePath}/inventory/movements` : fallbackHref,
        userId: currentUserId || 'system',
        read: false,
      };
    default:
      return null;
  }
};


function MainNav({
  navItems,
  onLinkClick,
}: {
  navItems: NavItem[];
  onLinkClick?: () => void;
}) {
  const location = useLocation();
  const pathname = location.pathname;

  const handleLinkClick = () => {
    if (onLinkClick) {
      onLinkClick();
    }
  };

  return (
    <>
      {navItems.map((item, index) => {
        const Icon = item.icon;
        const isActive = pathname.startsWith(item.href) && item.href !== '/' || (pathname === '/' && item.href === '/');
        const showSectionTitle =
          index === 0 || item.section !== navItems[index - 1]?.section;

        return (
          <div key={item.name} className={cn(showSectionTitle && index !== 0 && 'mt-4')}>
            {/* Section titles temporarily hidden to declutter sidebar
            {showSectionTitle && item.section ? (
              <p className="mb-2 px-3 text-[11px] font-black uppercase tracking-[0.18em] text-muted-foreground/80">
                {item.section}
              </p>
            ) : null}
            */}
            <Link
              to={item.href}
              onClick={handleLinkClick}
              className={cn(
                'flex items-center gap-3 rounded-lg px-3 py-2 text-muted-foreground transition-all hover:text-primary',
                isActive && 'bg-muted text-primary'
              )}
            >
              <Icon className="h-4 w-4" />
              {item.name}
            </Link>
          </div>
        );
      })}
    </>
  );
}


export default function AppLayout({ children }: { children: React.ReactNode }) {
  const { storeId } = useParams();
  const { user } = useAuth();
  const [language, setLanguage] = useState<'es' | 'en'>('es');
  const [storeSettings, setStoreSettings] = useState<StoreSettings>({
    enableDispatcherMode: false,
    enableSalesManagerMode: false,
    enableSupplierManagement: false,
  });
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const seenNotificationIds = useRef<Set<string>>(new Set());
  const location = useLocation();
  const pathname = location.pathname;
  const { lastEvent, connected } = useRealTimeEvents(storeId);

  useEffect(() => {
    if (!storeId) return;
    const fetchStoreSettings = async () => {
      try {
        const res = await apiClient.get(`/stores/${storeId}`);
        if (res.data && res.data.settings) {
          setStoreSettings(res.data.settings);
        }
      } catch (error) {
         // ignore
      }
    };
    fetchStoreSettings();
  }, [storeId]);

  const handleLanguageChange = (lang: string) => {
    setLanguage(lang as 'es' | 'en');
  };

  const handleNotificationClick = (notificationId: string) => {
    setNotifications((prev: Notification[]) =>
      prev.map((n: Notification) => (n.id === notificationId ? { ...n, read: true } : n))
    );
  };

  useEffect(() => {
    seenNotificationIds.current.clear();
    setNotifications([]);
  }, [storeId, user?.id]);

  useEffect(() => {
    const notification = buildRealtimeNotification(
      lastEvent,
      user?.id,
      storeId,
      isGlobalAdminRole(user?.role),
    );

    if (!notification || seenNotificationIds.current.has(notification.id)) {
      return;
    }

    seenNotificationIds.current.add(notification.id);
    setNotifications((prev) => [notification, ...prev].slice(0, 12));
  }, [lastEvent, storeId, user?.id, user?.role]);

  const navItems = useMemo(() => {
    const roleId = normalizeUserRole(user?.role);
    switch (roleId) {
      case 'master-admin':
      case 'owner':
        return getMasterAdminNav(language);
      case 'chain-admin':
        return getChainAdminNav(language);
      case 'store-admin':
        return getStoreAdminNav(storeId || '', language, storeSettings);
      case 'inventory':
        return getBodegueroNav(storeId || '', language);
      case 'cashier':
        return getCashierNav(storeId || '', language, storeSettings);
      case 'dispatcher':
        return getDespachoNav(storeId || '', language);
      case 'rutero':
        return getRuteroNav(storeId || '', language, storeSettings);
      case 'vendor':
        return getVendedorAmbulanteNav(storeId || '', language);
      case 'sales-manager':
        return getGestorVentasNav(storeId || '', language);
      default:
        // Default to store admin nav for robust fallback if storeId exists
        return storeId ? getStoreAdminNav(storeId, language, storeSettings) : [];
    }
  }, [user, language, storeId, storeSettings]);

  const nav = <MainNav navItems={navItems} onLinkClick={() => {}} />;

  if (pathname === '/' && !isGlobalAdminRole(user?.role)) {
    return <>{children}</>;
  }

  return (
    <div className="grid min-h-screen w-full md:grid-cols-[220px_1fr] lg:grid-cols-[280px_1fr]">
      <div className="hidden border-r bg-muted/40 md:block">
        <div className="flex h-full max-h-screen flex-col gap-2">
          <div className="flex h-16 items-center border-b px-4 lg:h-[60px] lg:px-6">
            <Link to={isGlobalAdminRole(user?.role) ? '/master-admin/dashboard' : (storeId ? `/store/${storeId}/dashboard` : '/')} className="flex items-center gap-2 font-semibold">
              <svg
                xmlns="http://www.w3.org/2000/svg"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                className="h-6 w-6 text-primary"
              >
                <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path>
              </svg>
              <span>MultiTienda</span>
            </Link>
          </div>

          <div className="flex-1 overflow-y-auto">
            <nav className="grid items-start px-2 text-sm font-medium lg:px-4">
              {nav}
            </nav>
          </div>
        </div>
      </div>
      <div className="flex flex-col">
        <AppHeader
          navItems={navItems}
          language={language}
          onLanguageChange={handleLanguageChange}
          exchangeRate={storeSettings.exchangeRate}
          notifications={notifications}
          onNotificationClick={handleNotificationClick}
          isSocketConnected={connected}
        />
        <main className="flex flex-1 flex-col gap-4 p-4 lg:gap-6 lg:p-6 bg-background overflow-x-hidden">
          {children}
        </main>

        <footer className="flex items-center justify-between p-4 text-xs text-muted-foreground border-t">
          <span>© {new Date().getFullYear()} World Wide All in One Programing. Todos los derechos reservados.</span>
        </footer>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Lock } from 'lucide-react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import { API_BASE_URL } from '@/lib/runtime-config';
import { normalizeUserRole } from '@/lib/user-role';
import { useAuth } from '@/contexts/auth-context';

interface AdminAuthDialogProps {
    isOpen: boolean;
    onClose: () => void;
    onConfirm: () => void;
    title?: string;
    description?: string;
    requiredRole?: 'admin' | 'owner';
}

export function AdminAuthDialog({
    isOpen,
    onClose,
    onConfirm,
    title = "Autorización Requerida",
    description = "Esta acción requiere permisos de administrador. Por favor ingrese su clave.",
}: AdminAuthDialogProps) {
    const { user } = useAuth();
    const isCurrentUserPrivileged = ['store-admin', 'master-admin', 'owner'].includes(normalizeUserRole(user?.role));
    const [adminEmail, setAdminEmail] = useState(user?.email || '');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const params = useParams();
    const storeId = params.storeId as string;

    const handleConfirm = async () => {
        setIsLoading(true);
        setError('');

        try {
            if (!storeId) {
                setError('Error: No se identificó la tienda.');
                return;
            }

            const response = await axios.post(`${API_BASE_URL}/auth/login`, {
                email: adminEmail.trim(),
                password,
            });

            const authorizedRole = normalizeUserRole(response.data?.user?.role);
            const authorized =
                requiredRole === 'owner'
                    ? authorizedRole === 'owner' || authorizedRole === 'master-admin'
                    : ['store-admin', 'master-admin', 'owner'].includes(authorizedRole);

            if (!authorized) {
                setError('Las credenciales no corresponden a un usuario autorizado.');
                return;
            }

            onConfirm();
            onClose();
            setPassword('');
            if (isCurrentUserPrivileged) {
                setAdminEmail(user?.email || '');
            }

        } catch (err: any) {
            console.error("Auth error:", err);
            setError(err.response?.data?.message || 'Credenciales inválidas.');
        } finally {
            setIsLoading(false);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            handleConfirm();
        }
    };

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <div className="mx-auto bg-red-100 p-3 rounded-full mb-2">
                        <Lock className="h-6 w-6 text-red-600" />
                    </div>
                    <DialogTitle className="text-center">{title}</DialogTitle>
                    <DialogDescription className="text-center">
                        {description}
                    </DialogDescription>
                </DialogHeader>

                <div className="grid gap-4 py-4">
                    <div className="grid gap-2">
                        <Label htmlFor="admin-email">Correo del administrador</Label>
                        <Input
                            id="admin-email"
                            type="email"
                            value={adminEmail}
                            onChange={(e) => setAdminEmail(e.target.value)}
                            placeholder="admin@multitienda.com"
                            autoFocus
                        />
                    </div>
                    <div className="grid gap-2">
                        <Label htmlFor="admin-password">Contraseña del administrador</Label>
                        <Input
                            id="admin-password"
                            type="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            onKeyDown={handleKeyDown}
                            placeholder="Ingrese contraseña..."
                        />
                        {error && <p className="text-sm text-red-500 font-medium">{error}</p>}
                        <p className="text-xs text-muted-foreground">
                            Se valida contra el login real del sistema sin reemplazar la sesión actual.
                        </p>
                    </div>
                </div>

                <DialogFooter className="sm:justify-between flex-row gap-2">
                    <Button
                        type="button"
                        variant="secondary"
                        className="flex-1"
                        onClick={onClose}
                    >
                        Cancelar
                    </Button>
                    <Button
                        type="button"
                        className="flex-1 bg-red-600 hover:bg-red-700 text-white shadow-lg"
                        onClick={handleConfirm}
                        disabled={isLoading || !password || !adminEmail.trim()}
                    >
                        {isLoading ? 'Verificando...' : 'Autorizar'}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useAuth } from '@/contexts/auth-context';
import { Loader2, Users } from 'lucide-react';

import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { toast } from '@/lib/swalert';
import { logError } from '@/lib/error-logger';

const formSchema = z.object({
    email: z.string().email({
        message: 'Por favor ingresa un correo electrónico válido.',
    }),
    password: z.string().min(6, {
        message: 'La contraseña debe tener al menos 6 caracteres.',
    }),
});

interface UserSwitchDialogProps {
    trigger?: React.ReactNode;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
}

export function UserSwitchDialog({ trigger, open: controlledOpen, onOpenChange: setControlledOpen }: UserSwitchDialogProps) {
    const [internalOpen, setInternalOpen] = useState(false);

    const isControlled = controlledOpen !== undefined;
    const open = isControlled ? controlledOpen : internalOpen;
    const setOpen = (value: boolean) => {
        if (isControlled) {
            setControlledOpen?.(value);
        } else {
            setInternalOpen(value);
        }
    };
    const [isLoading, setIsLoading] = useState(false);
    const { login } = useAuth();

    const form = useForm<z.infer<typeof formSchema>>({
        resolver: zodResolver(formSchema),
        defaultValues: {
            email: '',
            password: '',
        },
    });

    async function onSubmit(values: z.infer<typeof formSchema>) {
        setIsLoading(true);
        try {
            await login(values.email, values.password);
            toast.success('Cambio de usuario exitoso', 'Bienvenido al sistema.');
            setOpen(false);
            form.reset();
        } catch (error: unknown) {
            logError(error, { location: 'user-switch-dialog' });
            const errorMessage = (error as any).response?.data?.message || 'Error al cambiar de usuario.';
            toast.error('Error', errorMessage);
        } finally {
            setIsLoading(false);
        }
    }

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                {trigger || (
                    <Button variant="outline" size="icon" title="Cambiar Usuario">
                        <Users className="h-4 w-4" />
                    </Button>
                )}
            </DialogTrigger>
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Cambio Rápido de Usuario</DialogTitle>
                    <DialogDescription>
                        Ingresa las credenciales del usuario al que deseas cambiar.
                        Se cerrará la sesión actual.
                    </DialogDescription>
                </DialogHeader>
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <FormField
                            control={form.control}
                            name="email"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Correo Electrónico</FormLabel>
                                    <FormControl>
                                        <Input placeholder="usuario@ejemplo.com" {...field} />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />
                        <FormField
                            control={form.control}
                            name="password"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Contraseña</FormLabel>
                                    <FormControl>
                                        <Input type="password" placeholder="******" {...field} />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />
                        <div className="flex justify-end pt-4">
                            <Button type="submit" disabled={isLoading}>
                                {isLoading ? (
                                    <>
                                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                        Cambiando...
                                    </>
                                ) : (
                                    'Iniciar Sesión'
                                )}
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}

import { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { AlertCircle, AlertTriangle, CheckCircle, Users } from 'lucide-react';
import { differenceInDays, parseISO } from 'date-fns';
import apiClient from '@/services/api-client';

interface LicenseStats {
  active: number;
  expiringSoon: number;
  expired: number;
}

interface UserStats {
  total: number;
}

export function MasterAdminDashboardMetrics() {
  const [licenseStats, setLicenseStats] = useState<LicenseStats | null>(null);
  const [userStats, setUserStats] = useState<UserStats | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const [usersRes, storesRes] = await Promise.all([
          apiClient.get('/users'),
          apiClient.get('/stores')
        ]);

        // Calculate User stats
        setUserStats({ total: usersRes.data.length });

        // Calculate License stats
        let active = 0;
        let expiringSoon = 0;
        let expired = 0;

        storesRes.data.forEach((store: any) => {
          // If we have a license object in settings or as a separate property
          const license = store.license || store.settings?.license;
          if (!license || !license.expiryDate) {
            return;
          }

          const expiryDate = parseISO(license.expiryDate);
          const today = new Date();
          const daysUntilExpiry = differenceInDays(expiryDate, today);

          if (daysUntilExpiry < 0) {
            expired++;
          } else if (daysUntilExpiry <= 30) {
            expiringSoon++;
          } else {
            active++;
          }
        });

        setLicenseStats({ active, expiringSoon, expired });
      } catch (error) {
        console.error("Error fetching master admin dashboard data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        {Array.from({ length: 4 }).map((_, i) => (
          <Card key={i}>
            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
              <Skeleton className="h-5 w-32" />
              <Skeleton className="h-6 w-6 rounded-full" />
            </CardHeader>
            <CardContent>
              <Skeleton className="h-8 w-16" />
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Tiendas Activas</CardTitle>
          <CheckCircle className="h-4 w-4 text-green-500" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{licenseStats?.active ?? 0}</div>
        </CardContent>
      </Card>
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Licencias por Vencer</CardTitle>
          <AlertTriangle className="h-4 w-4 text-yellow-500" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{licenseStats?.expiringSoon ?? 0}</div>
        </CardContent>
      </Card>
      <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Licencias Vencidas</CardTitle>
          <AlertCircle className="h-4 w-4 text-red-500" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{licenseStats?.expired ?? 0}</div>
        </CardContent>
      </Card>
       <Card>
        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
          <CardTitle className="text-sm font-medium">Total de Usuarios</CardTitle>
          <Users className="h-4 w-4 text-muted-foreground" />
        </CardHeader>
        <CardContent>
          <div className="text-2xl font-bold">{userStats?.total ?? 0}</div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Package, ShoppingCart, Truck, AlertCircle } from 'lucide-react';
import apiClient from '@/services/api-client';
import { Skeleton } from '@/components/ui/skeleton';
import { Badge } from '@/components/ui/badge';

interface QuickPulseData {
  pendingOrders: number;
  todaySalesCount: number;
  activeDeliveries: number;
  lowStockCount: number;
}

export function QuickOperationalPulse({ storeId }: { storeId: string }) {
  const [data, setData] = useState<QuickPulseData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!storeId) return;

    const fetchPulse = async () => {
      setLoading(true);
      try {
        const [ordersRes, salesRes, deliveriesRes, productsRes] = await Promise.all([
          apiClient.get(`/orders?storeId=${storeId}&status=RECIBIDO`),
          apiClient.get(`/sales?storeId=${storeId}`), // We'll filter today in FE for simplicity if no specific endpoint
          apiClient.get(`/pending-deliveries?storeId=${storeId}`),
          apiClient.get(`/products?storeId=${storeId}`)
        ]);

        const today = new Date().toISOString().split('T')[0];
        const todaySales = salesRes.data.filter((s: any) => s.createdAt.startsWith(today)).length;

        // Simulating low stock check (stock < 10)
        const lowStock = productsRes.data.filter((p: any) => p.currentStock < 10).length;

        setData({
          pendingOrders: ordersRes.data.length,
          todaySalesCount: todaySales,
          activeDeliveries: deliveriesRes.data.filter((d: any) => d.status === 'PENDING' || d.status === 'IN_TRANSIT').length,
          lowStockCount: lowStock,
        });
      } catch (error) {
        console.error("Error fetching pulse data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchPulse();
    const interval = setInterval(fetchPulse, 30000); // Auto refresh every 30s
    return () => clearInterval(interval);
  }, [storeId]);

  if (loading || !data) {
    return (
      <div className="grid gap-3 sm:grid-cols-4">
        {[1, 2, 3, 4].map((i) => (
          <Skeleton key={i} className="h-20 w-full rounded-2xl bg-white/10" />
        ))}
      </div>
    );
  }

  return (
    <div className="grid gap-3 sm:grid-cols-4">
      <PulseItem 
        label="Caja" 
        value={`${data.todaySalesCount} Ventas`} 
        icon={ShoppingCart} 
        description="Hoy"
      />
      <PulseItem 
        label="Bodega" 
        value={`${data.pendingOrders} Pendientes`} 
        icon={Package} 
        color={data.pendingOrders > 0 ? "text-yellow-400" : "text-emerald-400"}
        highlight={data.pendingOrders > 0}
      />
      <PulseItem 
        label="En Ruta" 
        value={`${data.activeDeliveries} Pedidos`} 
        icon={Truck} 
        description="En curso"
      />
      <PulseItem 
        label="Stock" 
        value={`${data.lowStockCount} Alerta`} 
        icon={AlertCircle} 
        color={data.lowStockCount > 0 ? "text-red-400" : "text-emerald-400"}
        highlight={data.lowStockCount > 0}
      />
    </div>
  );
}

function PulseItem({ 
  label, 
  value, 
  icon: Icon, 
  description, 
  color = "text-white",
  highlight = false 
}: { 
  label: string; 
  value: string; 
  icon: any; 
