}

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCcw } from 'lucide-react';
import { Button } from '@/components/ui/button';

interface Props {
  children?: ReactNode;
  fallback?: ReactNode;
}

interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(_: Error): State {
    return { hasError: true };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return this.props.fallback || (
        <div className="flex h-screen w-full flex-col items-center justify-center bg-slate-50 p-6 text-center">
          <div className="mb-6 rounded-full bg-red-100 p-6 shadow-[inset_4px_4px_8px_#d1d9e6,inset_-4px_-4px_8px_#ffffff]">
            <AlertTriangle className="h-12 w-12 text-red-500" />
          </div>
          <h1 className="mb-2 text-2xl font-black uppercase tracking-tighter text-slate-800">Ups! Algo salió mal</h1>
          <p className="mb-8 max-w-md text-sm font-medium text-slate-500">
            La aplicación encontró un error inesperado. Hemos registrado este incidente para solucionarlo.
          </p>
          <Button 
            onClick={() => window.location.reload()} 
            className="h-12 rounded-2xl bg-primary px-8 font-black uppercase tracking-widest shadow-[8px_8px_16px_#ccced1,-8px_-8px_16px_#ffffff] hover:shadow-none"
          >
            <RefreshCcw className="mr-2 h-4 w-4" />
            Recargar Aplicación
          </Button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import apiClient from '@/services/api-client';
import { useToast } from '@/hooks/use-toast';
import { ToastAction } from '@/components/ui/toast';
import { useAuth } from '@/contexts/auth-context';
import { useEffect, useRef } from 'react';
import { normalizeUserRole } from '@/lib/user-role';
import { withAppBase } from '@/lib/runtime-config';

export function GlobalAlertProvider() {
    const { toast } = useToast();
    const audioRef = useRef<HTMLAudioElement | null>(null);
    const previousAlertIds = useRef<Set<string>>(new Set());
    const { user } = useAuth();
    const role = normalizeUserRole(user?.role);
    const storeId = user?.storeIds?.[0];
    const canManageAuthorizations = role === 'store-admin' || role === 'master-admin' || role === 'owner';

    useEffect(() => {
        audioRef.current = new Audio(withAppBase('/sounds/ping.mp3'));
        audioRef.current.load();
    }, []);

    useEffect(() => {
        if (!user || !canManageAuthorizations) return;

        const fetchAlerts = async () => {
            try {
                const res = await apiClient.get('/authorizations', {
                    params: {
                        ...(storeId ? { storeId } : {}),
                        status: 'PENDING',
                    },
                });
                const alerts = res.data || [];

                for (const alert of alerts) {
                    if (!previousAlertIds.current.has(alert.id)) {
                        previousAlertIds.current.add(alert.id);
                        if (previousAlertIds.current.size <= alerts.length) continue;

                        audioRef.current?.play().catch((e) => {
                            console.warn("Audio alerta bloqueado:", e);
                        });

                        toast({
                            title: 'Alerta Administrativa',
                            description: `Nueva solicitud de autorización recibida.`,
                            duration: Infinity,
                            variant: "destructive",
                            action: (
                                <div className="flex flex-col gap-2 sm:flex-row">
                                    <ToastAction
                                        altText="Aprobar"
                                        className="bg-green-600 text-white hover:bg-green-700 border-green-700"
                                        onClick={() => handleAction(alert.id, 'APPROVED')}
                                    >
                                        APROBAR
                                    </ToastAction>
                                    <ToastAction
                                        altText="Rechazar"
                                        className="bg-red-600 text-white hover:bg-red-700 border-red-700"
                                        onClick={() => handleAction(alert.id, 'REJECTED')}
                                    >
                                        RECHAZAR
                                    </ToastAction>
                                </div>
                            ),
                        });
                    }
                }
            } catch (err) {
                // silent
            }
        };

        fetchAlerts();
        const interval = setInterval(fetchAlerts, 10000);
        return () => {
            clearInterval(interval);
            previousAlertIds.current.clear();
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [canManageAuthorizations, storeId, user]);

    const handleAction = async (id: string, status: string) => {
        try {
            await apiClient.patch(`/authorizations/${id}/status`, { status });
            toast({ title: status === 'APPROVED' ? "Alerta Aprobada" : "Alerta Rechazada", duration: 3000 });
        } catch (error) {
            console.error("Error updating alert:", error);
            toast({ variant: "destructive", title: "Error", description: "No se pudo actualizar la alerta." });
        }
    };

    return null;
}

import { useEffect, useState } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { RefreshCw } from 'lucide-react';

export function NetworkStatusIndicator({ isSocketConnected = false }: { isSocketConnected?: boolean }) {
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const isFullyConnected = isOnline && isSocketConnected;

  return (
    <div className="flex items-center gap-2 text-[10px] sm:text-xs font-bold uppercase tracking-widest px-3 py-1.5 rounded-full bg-slate-100/50">
      <span
        className={cn(
          'h-2 w-2 rounded-full relative',
          isFullyConnected ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.5)]'
        )}
      />
      <span className={cn(
        isFullyConnected ? 'text-emerald-700' : 'text-rose-600 font-black'
      )}>
        {isFullyConnected ? 'En Línea' : (isOnline ? 'Reconectando...' : 'Sin Red')}
      </span>
    </div>
  );
}

