            {/* Summary Footer */}
            <div className="p-4 bg-gray-50 border-t space-y-2">
                <div className="flex justify-between items-center text-lg font-bold">
                    <span>Total</span>
                    <span className="text-primary truncate">C$ {total.toFixed(2)}</span>
