import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useLocation as usePathname, useParams } from 'react-router-dom';
import { cn } from '@/lib/utils';
import {
    LayoutDashboard,
    WalletCards,
    ShoppingCart,
    LifeBuoy,
    Menu,
    ChevronLeft
} from 'lucide-react';
import type { ReactNode } from 'react';
import { Button } from '@/components/ui/button';

interface CashierLayoutProps {
    children: ReactNode;
}

const cashierNavItems = [
    { name: 'Panel', href: 'dashboard', icon: LayoutDashboard },
    { name: 'Punto de Venta', href: 'billing', icon: ShoppingCart },
    { name: 'Cuadre de Caja', href: 'cash-register', icon: WalletCards },
];

export function CashierLayout({ children }: CashierLayoutProps) {
    const { pathname } = usePathname();
    const params = useParams();
    const storeId = params.storeId as string;
    const [isCollapsed, setIsCollapsed] = useState(false);

    // Check if we are in the POS (billing) view
    const isPosView = pathname.includes('/billing');

    // Auto-collapse sidebar in POS view by default
    useEffect(() => {
        if (isPosView) {
            setIsCollapsed(true);
        } else {
            setIsCollapsed(false);
        }
    }, [isPosView]);

    return (
        <div className={cn(
            "grid min-h-screen w-full transition-all duration-300",
            isCollapsed ? "md:grid-cols-[60px_1fr]" : "md:grid-cols-[220px_1fr] lg:grid-cols-[250px_1fr]"
        )}>
            <div className="hidden border-r bg-muted/40 md:flex flex-col h-screen sticky top-0 transition-all duration-300">
                <div className={cn(
                    "flex h-16 items-center border-b px-4 lg:h-[60px]",
                    isCollapsed ? "justify-center px-0" : "px-6 justify-between"
                )}>
                    {!isCollapsed && (
                        <Link to={storeId ? `/store/${storeId}/billing` : '/'} className="flex items-center gap-2 font-semibold truncate">
                            <WalletCards className="h-6 w-6 text-primary shrink-0" />
                            <span>PharmaSync</span>
                        </Link>
                    )}
                    {isCollapsed && (
                        <Button variant="ghost" size="icon" onClick={() => setIsCollapsed(false)} title="Expandir menú">
                            <Menu className="h-5 w-5" />
                        </Button>
                    )}
                    {!isCollapsed && (
                        <Button variant="ghost" size="icon" className="-mr-2" onClick={() => setIsCollapsed(true)} title="Contraer menú">
                            <ChevronLeft className="h-5 w-5" />
                        </Button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto py-4">
                    <nav className="grid items-start px-2 text-sm font-medium lg:px-4 gap-1">
                        {cashierNavItems.map((item) => {
                            const href = `/store/${storeId}/${item.href}`;
                            const isActive = pathname.startsWith(href);
                            return (
                                <Link
                                    key={item.name}
                                    to={href}
                                    title={isCollapsed ? item.name : undefined}
                                    className={cn(
                                        'flex items-center gap-3 rounded-lg px-3 py-2 text-muted-foreground transition-all hover:text-primary',
                                        isActive && 'bg-muted text-primary',
                                        isCollapsed && 'justify-center px-2'
                                    )}
                                >
                                    <item.icon className="h-4 w-4 shrink-0" />
                                    {!isCollapsed && <span>{item.name}</span>}
                                </Link>
                            );
                        })}
                    </nav>
                </div>
                <div className="mt-auto p-4 border-t">
                    <div className={cn(
                        "flex items-center gap-2 text-muted-foreground hover:text-foreground cursor-pointer transition-all",
                        isCollapsed && "justify-center"
                    )}>
                        <LifeBuoy className="h-4 w-4 shrink-0" />
                        {!isCollapsed && <span className="text-sm">Ayuda</span>}
                    </div>
                </div>
            </div>

            <main className="flex flex-col h-screen overflow-hidden bg-background">
                {/* Only show top header if NOT in POS view */}
                {!isPosView && (
                    <header className="flex h-14 items-center gap-4 border-b bg-muted/40 px-4 lg:h-[60px] lg:px-6">
                        <Button variant="ghost" size="icon" className="md:hidden">
                            <Menu className="h-5 w-5" />
                            <span className="sr-only">Toggle navigation menu</span>
                        </Button>
                        <div className="w-full flex-1">
                            {/* Top nav content placeholder */}
                            <h1 className="font-semibold text-lg">
                                {cashierNavItems.find(i => pathname.includes(i.href))?.name || 'Panel'}
                            </h1>
                        </div>
                    </header>
                )}
                {children}
            </main>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Loader2, ListOrdered, Eye, ArrowLeft, Package, Search } from 'lucide-react';
import apiClient from '@/services/api-client';
import { format } from 'date-fns';
import { Separator } from '@/components/ui/separator';

interface OrderItem {
  id?: string;
  productId: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  subtotal: number;
}

interface Order {
  id: string;
  total: number;
  status: string;
  paymentType?: string;
  createdAt: string;
  items?: OrderItem[];
  history?: { status: string; userName: string; createdAt: string }[];
}

const statusColor: Record<string, string> = {
  RECIBIDO: 'bg-blue-100 text-blue-800',
  EN_PREPARACION: 'bg-amber-100 text-amber-800',
  ALISTADO: 'bg-sky-100 text-sky-800',
  CARGADO_CAMION: 'bg-emerald-100 text-emerald-800',
  EN_ENTREGA: 'bg-violet-100 text-violet-800',
  ENTREGADO: 'bg-green-100 text-green-800',
  CANCELADO: 'bg-red-100 text-red-800',
  Pagada: 'bg-emerald-100 text-emerald-800',
  'Pendiente de Pago': 'bg-amber-100 text-amber-800',
  PENDING: 'bg-amber-100 text-amber-800',
};

const statusLabel: Record<string, string> = {
  RECIBIDO: 'Recibido',
  EN_PREPARACION: 'Preparando',
  ALISTADO: 'Listo',
  CARGADO_CAMION: 'Cargado',
  EN_ENTREGA: 'En ruta',
  ENTREGADO: 'Entregado',
  CANCELADO: 'Cancelado',
  Pagada: 'Pagada',
  'Pendiente de Pago': 'Pendiente',
  PENDING: 'Pendiente',
};

export function ClientHistoryDialog({
  clientId,
  clientName,
  storeId,
}: {
  clientId: string;
  clientName: string;
  storeId: string;
}) {
  const [open, setOpen] = useState(false);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [headerFilters, setHeaderFilters] = useState({ dateFrom: '', dateTo: '', status: '', payment: '' });

  // Detail view state
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [detailLoading, setDetailLoading] = useState(false);

  useEffect(() => {
    if (open && clientId && storeId) {
      setLoading(true);
      setDetailOrder(null);
      apiClient
        .get('/orders', { params: { storeId, clientId, limit: 50 } })
        .then((res) => {
          setOrders(Array.isArray(res.data) ? res.data : []);
        })
        .catch(() => setOrders([]))
        .finally(() => setLoading(false));
    }
  }, [open, clientId, storeId]);

  const handleViewDetail = async (order: Order) => {
    setDetailLoading(true);
    setDetailOrder(order);
    try {
      const res = await apiClient.get(`/orders/${order.id}`);
      setDetailOrder(res.data);
    } catch {
      // Keep basic order info if detail fails
    } finally {
      setDetailLoading(false);
    }
  };

  const filteredOrders = orders.filter((o) => {
    const fStatus = headerFilters.status.toLowerCase();
    const fPayment = headerFilters.payment.toLowerCase();
    const createdStr = format(new Date(o.createdAt), 'yyyy-MM-dd');
    const matchesFrom = headerFilters.dateFrom ? createdStr >= headerFilters.dateFrom : true;
    const matchesTo = headerFilters.dateTo ? createdStr <= headerFilters.dateTo : true;

    return (
      (statusLabel[o.status] || o.status).toLowerCase().includes(fStatus) &&
      (o.paymentType?.toLowerCase() || '').includes(fPayment) &&
      matchesFrom && matchesTo
    );
  });

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="sm" className="gap-2 text-primary hover:text-primary hover:bg-primary/10">
          <ListOrdered className="h-4 w-4" /> Historial
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-3xl">
        <DialogHeader>
          {detailOrder ? (
            <div className="flex items-center gap-3">
              <Button variant="ghost" size="icon" onClick={() => setDetailOrder(null)}>
                <ArrowLeft className="h-4 w-4" />
              </Button>
              <DialogTitle>Detalle del Pedido</DialogTitle>
              <Badge className={statusColor[detailOrder.status] || 'bg-slate-100 text-slate-800'}>
                {statusLabel[detailOrder.status] || detailOrder.status}
              </Badge>
            </div>
          ) : (
            <DialogTitle>Historial de Compras — {clientName}</DialogTitle>
          )}
        </DialogHeader>

        {loading ? (
          <div className="flex justify-center py-10">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          </div>
        ) : orders.length === 0 ? (
          <div className="text-center py-10 text-muted-foreground">
            Este cliente no tiene pedidos registrados.
          </div>
        ) : detailOrder ? (
          // --- DETAIL VIEW ---
          detailLoading ? (
            <div className="flex justify-center py-10">
              <Loader2 className="h-6 w-6 animate-spin text-primary" />
            </div>
          ) : (
            <div className="space-y-4">
              <div className="flex flex-wrap gap-x-6 gap-y-2 text-sm text-muted-foreground border-b pb-4">
                <p><strong>Fecha:</strong> {format(new Date(detailOrder.createdAt), 'dd/MM/yyyy HH:mm')}</p>
                <p><strong>Tipo de Pago:</strong> <span className={detailOrder.paymentType === 'Crédito' ? 'text-amber-600 font-bold' : ''}>{detailOrder.paymentType || 'CONTADO'}</span></p>
              </div>

              {/* PRODUCTS */}
              {detailOrder.items && detailOrder.items.length > 0 ? (
                <div className="border rounded-md max-h-[30vh] overflow-y-auto">
                  <Table>
                    <TableHeader className="sticky top-0 bg-background z-10">
                      <TableRow>
                        <TableHead>Producto</TableHead>
                        <TableHead className="text-right">Precio</TableHead>
                        <TableHead className="text-center">Cant.</TableHead>
                        <TableHead className="text-right">Subtotal</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {detailOrder.items.map((item, idx) => (
                        <TableRow key={item.id || idx}>
                          <TableCell className="text-sm font-medium">{item.productName}</TableCell>
                          <TableCell className="text-right text-muted-foreground">C$ {Number(item.unitPrice).toFixed(2)}</TableCell>
                          <TableCell className="text-center">{item.quantity}</TableCell>
                          <TableCell className="text-right">C$ {Number(item.subtotal || (item.unitPrice * item.quantity)).toFixed(2)}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              ) : (
                <div className="py-4 text-center flex flex-col items-center text-muted-foreground">
                  <Package className="h-8 w-8 mb-2 opacity-30" />
                  <p>Sin detalle de productos.</p>
                </div>
              )}

              <div className="flex justify-between font-bold text-lg pt-2 pb-4">
                <span>Total del pedido</span>
                <span>C$ {Number(detailOrder.total).toFixed(2)}</span>
              </div>

              {/* HISTORY */}
              {detailOrder.history && detailOrder.history.length > 0 && (
                <div className="border-t pt-4">
                  <h3 className="font-semibold text-sm mb-3">Historial de Estados</h3>
                  <div className="space-y-3">
                    {detailOrder.history.map((h, i) => (
                      <div key={i} className="flex flex-col sm:flex-row sm:items-center gap-1 sm:gap-4 text-sm bg-muted/30 p-2 rounded-md">
                        <span className="font-medium min-w-[120px]">{format(new Date(h.createdAt), 'dd/MM/yyyy HH:mm')}</span>
                        <Badge className={`${statusColor[h.status] || 'bg-slate-100 text-slate-800'} text-[10px] w-fit`}>
                          {statusLabel[h.status] || h.status}
                        </Badge>
                        <span className="text-muted-foreground ml-auto pr-2 text-xs">por {h.userName}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )
        ) : (
          // --- LIST VIEW ---
          <div className="overflow-y-auto max-h-[60vh] border rounded-md">
            <Table>
              <TableHeader className="sticky top-0 bg-background z-10">
                <TableRow>
                  <TableHead>
                    Fecha
                    <div className="flex flex-col gap-1 mt-1">
                      <Input type="date" className="h-6 text-xs p-1 font-normal w-full" value={headerFilters.dateFrom} onChange={e => setHeaderFilters({...headerFilters, dateFrom: e.target.value})} title="Desde" />
                      <Input type="date" className="h-6 text-xs p-1 font-normal w-full" value={headerFilters.dateTo} onChange={e => setHeaderFilters({...headerFilters, dateTo: e.target.value})} title="Hasta" />
                    </div>
                  </TableHead>
                  <TableHead>
                    Estado
                    <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.status} onChange={e => setHeaderFilters({...headerFilters, status: e.target.value})} />
                  </TableHead>
                  <TableHead>
                    Pago
                    <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.payment} onChange={e => setHeaderFilters({...headerFilters, payment: e.target.value})} />
                  </TableHead>
                  <TableHead className="text-right align-top pt-4">Total</TableHead>
                  <TableHead className="w-12 align-top pt-4"></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredOrders.map((o) => (
                  <TableRow key={o.id} className="cursor-pointer hover:bg-muted/50" onClick={() => handleViewDetail(o)}>
                    <TableCell className="text-sm">
                      {format(new Date(o.createdAt), 'dd/MM/yyyy HH:mm')}
                    </TableCell>
                    <TableCell>
                      <Badge className={statusColor[o.status] || 'bg-slate-100 text-slate-800'}>
                        {statusLabel[o.status] || o.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-sm">
                      <span className={o.paymentType === 'Crédito' ? 'text-amber-600 font-semibold' : 'text-muted-foreground'}>
                        {o.paymentType}
                      </span>
                    </TableCell>
                    <TableCell className="text-right font-medium">
                      C$ {Number(o.total).toFixed(2)}
                    </TableCell>
                    <TableCell>
                      <Eye className="h-4 w-4 text-muted-foreground" />
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from '@/components/ui/dialog';
import { Search, User, Check, Loader2, Plus } from 'lucide-react';
import { Client } from '@/types';
import { cn } from '@/lib/utils';
import { useParams } from 'react-router-dom';
import apiClient from '@/services/api-client';
import { toast } from '@/lib/swalert';

interface ClientSelectionDialogProps {
    currentClient: Client | null;
    onSelectClient: (client: Client) => void;
    trigger?: React.ReactNode;
}

export function ClientSelectionDialog({ currentClient, onSelectClient, trigger }: ClientSelectionDialogProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [clients, setClients] = useState<Client[]>([]);
    const [loading, setLoading] = useState(false);
    const params = useParams();
    const storeId = params.storeId as string;
    const genericClient: Client = {
        id: 'generic',
        storeId: storeId || '',
        name: 'Cliente Genérico',
        phone: '',
        address: '',
        email: '',
    };

    const loadClients = async () => {
        setLoading(true);
        try {
            const response = await apiClient.get('/clients', { params: { storeId } });
            setClients(Array.isArray(response.data) ? response.data : []);
        } catch (error) {
            console.error("Error loading clients:", error);
            toast.error("Error", "No se pudieron cargar los clientes.");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (isOpen) {
            void loadClients();
        }
    }, [isOpen, storeId]);

    const normalizedSearchTerm = searchTerm.trim().toLowerCase();
    const filteredClients = [genericClient, ...clients].filter((client) => {
        if (!normalizedSearchTerm) return true;
        return [
            client.name,
            client.phone,
            client.address,
            client.email,
        ].some((value) => value?.toLowerCase().includes(normalizedSearchTerm));
    });

    const handleSelect = (client: Client) => {
        onSelectClient(client);
        setSearchTerm('');
        setIsOpen(false);
    };

    return (
        <Dialog open={isOpen} onOpenChange={setIsOpen}>
            <DialogTrigger asChild>
                {trigger || (
                    <Button variant="outline" className="w-full justify-between h-12 shadow-sm border-slate-200">
                        <span className="flex items-center gap-2 font-bold text-slate-700">
                            <User className="h-5 w-5 text-blue-500" />
                            {currentClient?.name || 'CLIENTE GENÉRICO'}
                        </span>
                        <Search className="h-4 w-4 opacity-50" />
                    </Button>
                )}
            </DialogTrigger>
            <DialogContent className="sm:max-w-[500px] border-none shadow-2xl bg-white">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-black uppercase text-slate-800">Seleccionar Cliente</DialogTitle>
                    <DialogDescription className="font-medium text-slate-400">
                        Busca un cliente por nombre o teléfono.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-4 py-4">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
                        <Input
                            placeholder="Nombre / Teléfono / Cédula..."
                            className="h-12 pl-10 text-lg border-2 focus-visible:ring-blue-500 shadow-inner bg-slate-50"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            autoFocus
                        />
                    </div>

                    <div className="border-2 border-slate-100 rounded-xl overflow-hidden bg-slate-50 min-h-[300px] max-h-[400px] overflow-y-auto">
                        {loading ? (
                            <div className="flex flex-col justify-center items-center h-[300px] text-slate-400 gap-4">
                                <Loader2 className="h-10 w-10 animate-spin text-blue-500" />
                                <p className="font-bold uppercase tracking-widest text-xs">Cargando Clientes...</p>
                            </div>
                        ) : filteredClients.length === 0 ? (
                            <div className="flex flex-col justify-center items-center h-[300px] text-slate-300 gap-4">
                                <User className="h-16 w-16 opacity-20" />
                                <p className="font-black uppercase text-sm">No hay resultados</p>
                                <p className="text-xs font-medium text-slate-400">Usa el bot&oacute;n de nuevo cliente si necesitas registrarlo.</p>
                            </div>
                        ) : (
                            <div className="divide-y-2 divide-white">
                                {filteredClients.map((client) => (
                                    <div
                                        key={client.id}
                                        className={cn(
                                            "flex items-center justify-between p-4 cursor-pointer hover:bg-blue-500 hover:text-white transition-all group",
                                            currentClient?.id === client.id && "bg-blue-100 text-blue-900 border-l-4 border-blue-600"
                                        )}
                                        onClick={() => handleSelect(client)}
                                    >
                                        <div className="flex items-center gap-4">
                                            <div className="h-10 w-10 rounded-full bg-white shadow-sm flex items-center justify-center font-black text-blue-600 group-hover:bg-blue-400 group-hover:text-white">
                                                {client.name.charAt(0).toUpperCase()}
                                            </div>
                                            <div>
                                                <p className="font-black text-base uppercase leading-none">{client.name}</p>
                                                {client.phone && <p className="text-xs mt-1 opacity-70 font-mono">{client.phone}</p>}
                                            </div>
                                        </div>
                                        {currentClient?.id === client.id && <Check className="h-6 w-6 text-blue-600 group-hover:text-white" />}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

