import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
} from '@/components/ui/dialog';
import { Banknote, CreditCard, CheckCircle2, ArrowLeft } from 'lucide-react';
import { cn } from '@/lib/utils';
import { toast, alert } from '@/lib/swalert';

export interface PaymentData {
    method: 'Efectivo' | 'Tarjeta';
    amountReceived: number;
    paymentCurrency: 'NIO' | 'USD';
    change: number;
}

interface PaymentDialogProps {
    total: number;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onConfirm: (data: PaymentData) => void;
    exchangeRate?: number;
}

export function PaymentDialog({ total, open, onOpenChange, onConfirm, exchangeRate = 36.62 }: PaymentDialogProps) {
    const [amountStr, setAmountStr] = useState('');
    const [currency, setCurrency] = useState<'NIO' | 'USD'>('NIO');
    const [method, setMethod] = useState<'Efectivo' | 'Tarjeta'>('Efectivo');

    useEffect(() => {
        if (open) {
            setAmountStr('');
            setCurrency('NIO');
            setMethod('Efectivo');
        }
    }, [open]);

    const totalInCurrency = currency === 'NIO' ? total : total / exchangeRate;
    const amountNum = parseFloat(amountStr) || 0;
    const amountReceivedInNIO = currency === 'NIO' ? amountNum : amountNum * exchangeRate;
    const change = Math.max(0, amountReceivedInNIO - total);
    const missing = Math.max(0, total - amountReceivedInNIO);

    const handleDigit = (digit: string) => {
        if (amountStr.includes('.') && digit === '.') return;
        if (amountStr.length > 8) return;
        setAmountStr(prev => prev + digit);
    };

    const handleBackspace = () => {
        setAmountStr(prev => prev.slice(0, -1));
    };

    const handleQuickCash = (val: number) => {
        setAmountStr(val.toString());
    };

    const handleConfirm = async () => {
        const result = await alert.confirm(
            "¿Confirmar Pago?",
            `Método: ${method}\nTotal: C$ ${total.toFixed(2)}\nRecibido: ${currency} ${amountNum}\nCambio: C$ ${change.toFixed(2)}`
        );

        if (result.isConfirmed) {
            onConfirm({
                method,
                amountReceived: amountNum,
                paymentCurrency: currency,
                change: change
            });
            onOpenChange(false);
            toast.success("Venta Finalizada", "El pago ha sido procesado con éxito.");
        }
    };

    const quickNIO = [50, 100, 200, 500, 1000];
    const quickUSD = [1, 5, 10, 20, 50, 100];
    const isScaleValid = method === 'Tarjeta' || amountReceivedInNIO >= total - 0.5;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-5xl h-[85vh] p-0 flex flex-col gap-0 overflow-hidden border-none shadow-2xl bg-white rounded-2xl">
                <div className="flex h-full">
                    {/* LEFT PANEL */}
                    <div className="w-1/3 bg-slate-50 border-r p-8 flex flex-col">
                        <DialogHeader className="mb-8 shrink-0">
                            <DialogTitle className="text-3xl font-black uppercase text-slate-800 tracking-tighter">Cobrar Venta</DialogTitle>
                            <DialogDescription className="text-slate-400 font-bold">Completa la transacción</DialogDescription>
                        </DialogHeader>

                        <div className="space-y-6 flex-1">
                            <div className="p-6 bg-white rounded-2xl border-2 border-blue-100 text-center shadow-sm">
                                <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Total a Pagar</p>
                                <p className="text-5xl font-black text-blue-600 font-mono">C$ {total.toFixed(2)}</p>
                                {currency === 'USD' && (
                                    <p className="text-lg text-slate-400 font-bold mt-2">≈ $ {totalInCurrency.toFixed(2)}</p>
                                )}
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <Button
                                    variant={method === 'Efectivo' ? 'default' : 'outline'}
                                    className={cn("h-24 flex flex-col gap-2 rounded-2xl border-2 transition-all", 
                                        method === 'Efectivo' ? "bg-blue-600 border-blue-600 shadow-lg scale-105" : "border-slate-200 text-slate-400")}
                                    onClick={() => setMethod('Efectivo')}
                                >
                                    <Banknote className="h-8 w-8" />
                                    <span className="font-black uppercase text-xs">Efectivo</span>
                                </Button>
                                <Button
                                    variant={method === 'Tarjeta' ? 'default' : 'outline'}
                                    className={cn("h-24 flex flex-col gap-2 rounded-2xl border-2 transition-all", 
                                        method === 'Tarjeta' ? "bg-purple-600 border-purple-600 shadow-lg scale-105 hover:bg-purple-700" : "border-slate-200 text-slate-400")}
                                    onClick={() => {
                                        setMethod('Tarjeta');
                                        setAmountStr(currency === 'NIO' ? total.toFixed(2) : (total / exchangeRate).toFixed(2));
                                    }}
                                >
                                    <CreditCard className="h-8 w-8" />
                                    <span className="font-black uppercase text-xs">Tarjeta</span>
                                </Button>
                            </div>

                            <div className="bg-white p-6 rounded-2xl border-2 border-slate-100 shadow-inner space-y-4">
                                <div className="flex justify-between items-center">
                                    <span className="text-xs font-black text-slate-400 uppercase">Moneda:</span>
                                    <div className="flex bg-slate-100 rounded-xl p-1 gap-1">
                                        {(['NIO', 'USD'] as const).map((c) => (
                                            <button
                                                key={c}
                                                type="button"
                                                className={cn("px-4 py-2 rounded-lg text-xs font-black transition-all", 
                                                    currency === c ? "bg-white shadow-md text-blue-600" : "text-slate-400")}
                                                onClick={() => { setCurrency(c); setAmountStr(''); }}
                                            >
                                                {c}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                {method === 'Efectivo' && (
                                    <div className="space-y-4 pt-4 border-t-2 border-slate-50 border-dashed">
                                        <div className="flex justify-between items-center">
                                            <span className="text-xs font-black text-slate-400 uppercase">Recibido:</span>
                                            <span className="text-3xl font-black text-slate-800 font-mono">{currency === 'USD' ? '$' : 'C$'} {amountStr || '0'}</span>
                                        </div>
                                        <div className="flex justify-between items-center bg-emerald-50 p-4 rounded-xl">
                                            <span className={cn("text-xs font-black uppercase", missing > 0 ? "text-red-600" : "text-emerald-600")}>
                                                {missing > 0 ? 'Faltante:' : 'Cambio:' }
                                            </span>
                                            <span className={cn("text-3xl font-black font-mono", missing > 0 ? "text-red-600" : "text-emerald-600")}>
                                                C$ {missing > 0 ? missing.toFixed(2) : change.toFixed(2)}
                                            </span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="pt-8 shrink-0">
                            <Button
                                size="lg"
                                className="w-full h-20 text-2xl font-black shadow-2xl rounded-2xl bg-emerald-500 hover:bg-emerald-600 uppercase tracking-tighter"
                                disabled={!isScaleValid}
                                onClick={handleConfirm}
                            >
                                <CheckCircle2 className="mr-3 h-8 w-8" />
                                FINALIZAR
                            </Button>
                        </div>
                    </div>

                    {/* RIGHT PANEL: KEYPAD */}
                    <div className="w-2/3 bg-white p-8 flex flex-col">
                        {method === 'Efectivo' ? (
                            <div className="flex flex-col h-full gap-6">
                                <div className="grid grid-cols-6 gap-3">
                                    {(currency === 'NIO' ? quickNIO : quickUSD).map(val => (
                                        <Button
                                            key={val}
                                            variant="secondary"
                                            className="h-16 text-xl font-black bg-slate-50 text-slate-700 hover:bg-blue-500 hover:text-white rounded-xl border-2 border-slate-100 transition-all shadow-sm"
                                            onClick={() => handleQuickCash(val)}
                                        >
                                            {val}
                                        </Button>
                                    ))}
                                    <Button
                                        variant="secondary"
                                        className="h-16 text-xl font-black bg-blue-50 text-blue-600 hover:bg-blue-600 hover:text-white rounded-xl border-2 border-blue-100 uppercase"
                                        onClick={() => setAmountStr(currency === 'NIO' ? total.toFixed(2) : (total / exchangeRate).toFixed(2))}
                                    >
                                        Exacto
                                    </Button>
                                </div>

                                <div className="flex-1 grid grid-cols-3 gap-4">
                                    {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                                        <Button
                                            key={num}
                                            variant="outline"
                                            className="h-full text-5xl font-black bg-slate-50 border-2 border-slate-100 hover:bg-white hover:border-blue-500 hover:text-blue-600 rounded-2xl transition-all shadow-sm active:scale-95"
                                            onClick={() => handleDigit(num.toString())}
                                        >
                                            {num}
                                        </Button>
                                    ))}
                                    <Button
                                        variant="outline"
                                        className="h-full text-5xl font-black bg-slate-50 border-2 border-slate-100 rounded-2xl"
                                        onClick={() => handleDigit('.')}
                                    >
                                        .
                                    </Button>
                                    <Button
                                        variant="outline"
                                        className="h-full text-5xl font-black bg-slate-50 border-2 border-slate-100 rounded-2xl"
                                        onClick={() => handleDigit('0')}
                                    >
                                        0
                                    </Button>
                                    <Button
                                        variant="outline"
                                        className="h-full bg-red-50 hover:bg-red-500 hover:text-white text-red-500 border-2 border-red-100 rounded-2xl transition-all"
                                        onClick={handleBackspace}
                                    >
                                        <ArrowLeft className="h-12 w-12" />
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <div className="flex flex-col items-center justify-center h-full text-slate-300 space-y-8">
                                <div className="p-12 bg-slate-50 rounded-full">
                                    <CreditCard className="h-40 w-40 opacity-40 text-purple-600" />
                                </div>
                                <div className="text-center space-y-4">
                                    <h3 className="text-4xl font-black text-slate-800 uppercase tracking-tighter">Procesando Tarjeta</h3>
                                    <p className="text-xl font-bold text-slate-400">Verifica el monto de <span className="text-purple-600">C$ {total.toFixed(2)}</span> en el POS.</p>
                                    <div className="flex gap-2 justify-center pt-8">
                                        <div className="w-3 h-3 bg-purple-600 rounded-full animate-bounce" style={{animationDelay: '0s'}}></div>
                                        <div className="w-3 h-3 bg-purple-600 rounded-full animate-bounce" style={{animationDelay: '0.1s'}}></div>
                                        <div className="w-3 h-3 bg-purple-600 rounded-full animate-bounce" style={{animationDelay: '0.2s'}}></div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { Button } from "@/components/ui/button";
import { usePos } from "@/contexts/pos-context";
import { ArrowLeft, CreditCard, Banknote, Loader2 } from "lucide-react";
import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/auth-context';
import { useParams } from 'react-router-dom';
import { toast } from '@/lib/swalert';
import apiClient from '@/services/api-client';

export function PaymentGrid() {
    const { setMode, cart, clearCart } = usePos();
    const { user } = useAuth();
    const params = useParams();
    const storeId = params.storeId as string;
    const [isProcessing, setIsProcessing] = useState(false);
    const [activeShift, setActiveShift] = useState<any>(null);

    const total = cart.reduce((sum, item) => sum + (item.salePrice * item.quantity), 0);
    const tax = total * 0.15; // IVA
    const finalTotal = total + tax;

    // Fetch Active Shift
    useEffect(() => {
        if (!storeId) return;
        
        const fetchShift = async () => {
            try {
                const response = await apiClient.get(`/cash-shifts/active?storeId=${storeId}`);
                setActiveShift(response.data);
            } catch (error) {
                console.error("Error fetching active shift:", error);
            }
        };

        fetchShift();
    }, [storeId]);

    const handlePayment = async (method: 'CASH' | 'CARD') => {
        if (!user || !activeShift) {
            toast.error('Error', 'No hay turno de caja activo o usuario no identificado.');
            return;
        }
        if (cart.length === 0) return;

        setIsProcessing(true);
        try {
            await apiClient.post('/sales/process', {
                storeId,
                cashShiftId: activeShift.id,
                cashierId: user.id,
                ticketNumber: `TKT-${Date.now().toString().slice(-8)}`,
                items: cart.map(({ id, quantity, salePrice }) => ({ 
                    productId: id, 
                    quantity, 
                    unitPrice: salePrice 
                })),
                paymentMethod: method
            });

            toast.success('Venta Exitosa', `Cobro de C$ ${finalTotal.toFixed(2)} registrado.`);

            clearCart();
            setMode('products');

        } catch (error: any) {
            console.error(error);
            const msg = error.response?.data?.message || 'No se pudo procesar la venta.';
            toast.error('Error de Venta', msg);
        } finally {
            setIsProcessing(false);
        }
    };

    return (
        <div className="h-full flex flex-col bg-white">
            <div className="p-4 border-b flex items-center gap-4">
                <Button variant="ghost" size="icon" onClick={() => setMode('products')}>
                    <ArrowLeft className="h-6 w-6" />
                </Button>
                <h2 className="text-2xl font-bold">Procesar Pago</h2>
            </div>

            <div className="flex-1 flex flex-col items-center justify-center px-4 md:px-20 lg:px-40 gap-8">
                <div className="text-center space-y-2">
                    <p className="text-muted-foreground text-lg">Total a Pagar</p>
                    <div className="text-6xl font-black text-primary font-mono">C$ {finalTotal.toFixed(2)}</div>
                    {!activeShift && (
                        <div className="mt-4 p-3 bg-red-50 border border-red-200 text-red-600 rounded-lg font-bold flex items-center gap-2">
                            <span className="animate-pulse">●</span> CAJA CERRADA
                        </div>
                    )}
                </div>

                <div className="grid grid-cols-2 gap-6 w-full max-w-2xl">
                    <Button
                        variant="outline"
                        className="h-40 flex flex-col gap-4 text-2xl font-black shadow-lg shadow-slate-100 hover:bg-green-50 hover:text-green-700 hover:border-green-200"
                        onClick={() => handlePayment('CASH')}
                        disabled={isProcessing || !activeShift}
                    >
                        {isProcessing ? <Loader2 className="h-10 w-10 animate-spin" /> : <Banknote className="h-16 w-16" />}
                        EFECTIVO
                    </Button>
                    <Button
                        variant="outline"
                        className="h-40 flex flex-col gap-4 text-2xl font-black shadow-lg shadow-slate-100 hover:bg-blue-50 hover:text-blue-700 hover:border-blue-200"
                        onClick={() => handlePayment('CARD')}
                        disabled={isProcessing || !activeShift}
                    >
                        {isProcessing ? <Loader2 className="h-10 w-10 animate-spin" /> : <CreditCard className="h-16 w-16" />}
                        TARJETA
                    </Button>
                </div>
            </div>
        </div>
    );
}

import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useState } from 'react';
import { FileText, Loader2, Search, Trash2, CheckCircle2 } from 'lucide-react';
import { useParams } from 'react-router-dom';
import { useAuth } from '@/contexts/auth-context';
import { logError } from '@/lib/error-logger';
import { ScrollArea } from '../ui/scroll-area';
import { Checkbox } from '../ui/checkbox';
import { Separator } from '../ui/separator';
import apiClient from '@/services/api-client';
import { toast, alert } from '@/lib/swalert';
import { cn } from '@/lib/utils';

interface SaleItem {
    id: string;
    description: string;
    quantity: number;
    salePrice: number;
    returnedQty?: number;
}

interface Sale {
    id: string;
    total: number;
    items: SaleItem[];
    createdAt: string;
}

export function ReturnsDialog() {
    const params = useParams();
    const storeId = params.storeId as string;
    const { user } = useAuth();

    const [ticketId, setTicketId] = useState('');
    const [isSearching, setIsSearching] = useState(false);
    const [isProcessing, setIsProcessing] = useState(false);
    const [sale, setSale] = useState<Sale | null>(null);
    const [selectedItems, setSelectedItems] = useState<Record<string, boolean>>({});
    const [selectedQuantities, setSelectedQuantities] = useState<Record<string, number>>({});

    const handleSearch = async () => {
        if (!ticketId) return;
        setIsSearching(true);
        setSale(null);
        setSelectedItems({});
        setSelectedQuantities({});
        try {
            const response = await apiClient.get(`/sales/${ticketId}?storeId=${storeId}`);
            const saleData = response.data;
            
            setSale(saleData);
            const initialQtys: Record<string, number> = {};
            saleData.items.forEach((_item: any, idx: number) => {
                initialQtys[idx] = 1;
            });
            setSelectedQuantities(initialQtys);
        } catch (error: any) {
            logError(error, { location: 'returns-dialog-search', additionalInfo: { ticketId, storeId } });
            toast.error('Error', error.response?.data?.message || 'Venta no encontrada.');
        } finally {
            setIsSearching(false);
        }
    };

    const handleReturn = async () => {
        if (!sale || !user) return;

        const itemsToReturn = Object.entries(selectedItems)
            .filter(([, isSelected]) => isSelected)
            .map(([index]) => {
                const idx = parseInt(index, 10);
                return {
                    ...sale.items[idx],
                    qtyToReturn: selectedQuantities[idx] || 1,
                    originalIndex: idx
                };
            });

        if (itemsToReturn.length === 0) {
            toast.error('Error', 'Selecciona al menos un producto.');
            return;
        }

        const confirmResult = await alert.confirm(
            "¿Confirmar Devolución?",
            `Se generará una Nota de Crédito por C$ ${refundTotal.toFixed(2)}`
        );

        if (!confirmResult.isConfirmed) return;

        setIsProcessing(true);
        try {
            await apiClient.post('/returns', {
                storeId,
                saleId: sale.id,
                items: itemsToReturn.map(item => ({
                    productId: item.id,
                    quantity: item.qtyToReturn
                })),
                cashierId: user.id
            });

            toast.success('Éxito', 'Nota de Crédito generada e inventario actualizado.');
            setTicketId('');
            setSale(null);
            setSelectedItems({});
            setSelectedQuantities({});
        } catch (error) {
            logError(error, { location: 'returns-dialog-process', additionalInfo: { saleId: sale.id } });
            toast.error('Error', 'No se pudo procesar la devolución.');
        } finally {
            setIsProcessing(false);
        }
    }

    const handleCheckboxChange = (index: number) => {
        setSelectedItems(prev => ({ ...prev, [index]: !prev[index] }));
    };

    const handleQuantityChange = (index: number, qty: number, max: number) => {
        const validQty = Math.max(1, Math.min(qty, max));
        setSelectedQuantities(prev => ({ ...prev, [index]: validQty }));
    };

    const returnableItems = sale?.items.map((item, idx) => ({ ...item, originalIndex: idx })).filter(item => (item.returnedQty || 0) < item.quantity) || [];
    const refundTotal = returnableItems
        .filter((item) => selectedItems[item.originalIndex])
        .reduce((acc, item) => acc + (item.salePrice * (selectedQuantities[item.originalIndex] || 1)), 0);

    return (
        <Dialog onOpenChange={(open) => !open && setSale(null)}>
            <DialogTrigger asChild>
                <Button className="flex-1 bg-[#673ab7] hover:bg-[#5e35b1] text-white flex flex-col gap-0.5 rounded-md shadow-sm border-0 p-0 h-full">
                    <FileText className="h-3 w-3" />
                    <span className="text-[8px] font-bold leading-none text-center">NOTA DE<br />CRÉDITO</span>
                </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-xl border-none shadow-2xl bg-white p-0 overflow-hidden rounded-2xl">
                <div className="bg-purple-600 p-6 text-white">
                    <DialogHeader>
                        <DialogTitle className="text-2xl font-black uppercase tracking-tight flex items-center gap-2">
                            <Trash2 className="w-6 h-6" /> Devoluciones
                        </DialogTitle>
                        <DialogDescription className="text-purple-100 font-medium">
                            Ingresa el ticket para generar una nota de crédito.
                        </DialogDescription>
                    </DialogHeader>
                </div>
                
                <div className="p-6 space-y-6">
                    {!sale ? (
                        <div className="flex gap-4">
                            <div className="relative flex-1">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-400" />
                                <Input
                                    id="ticketId"
                                    placeholder="Nº DE TICKET (EJ: T-123456)"
                                    value={ticketId}
                                    className="h-14 pl-10 text-xl font-bold uppercase border-2 focus-visible:ring-purple-500"
                                    onChange={(e) => setTicketId(e.target.value)}
                                    onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
                                    autoFocus
                                />
                            </div>
                            <Button type="button" className="h-14 px-8 bg-purple-600 hover:bg-purple-700 shadow-lg font-black" onClick={handleSearch} disabled={isSearching}>
                                {isSearching ? <Loader2 className="animate-spin" /> : 'BUSCAR'}
                            </Button>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            <div className="flex justify-between items-center bg-slate-50 p-4 rounded-xl border border-slate-100">
                                <div>
                                    <p className="text-xs font-black text-slate-400 uppercase">TICKET ENCONTRADO</p>
                                    <p className="text-xl font-black text-slate-800">#{sale.id}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-xs font-black text-slate-400 uppercase">TOTAL ORIGINAL</p>
                                    <p className="text-xl font-black text-slate-800">C$ {sale.total.toFixed(2)}</p>
                                </div>
                            </div>

                            <ScrollArea className="h-64 border-2 border-slate-100 rounded-xl p-4 bg-slate-50 shadow-inner">
                                <div className="space-y-3">
                                    {returnableItems.map((item) => {
                                        const maxReturnable = item.quantity - (item.returnedQty || 0);
                                        const idx = item.originalIndex;
                                        return (
                                            <div key={idx} className={cn(
                                                "flex flex-col gap-3 p-4 rounded-xl transition-all border-2",
                                                selectedItems[idx] ? "bg-white border-purple-500 shadow-md" : "bg-white/50 border-white"
                                            )}>
                                                <div className="flex items-center justify-between">
                                                    <div className="flex items-center space-x-3">
                                                        <Checkbox
                                                            id={`item-${idx}`}
                                                            checked={!!selectedItems[idx]}
                                                            onCheckedChange={() => handleCheckboxChange(idx)}
                                                            className="w-6 h-6 border-2 data-[state=checked]:bg-purple-600"
                                                        />
                                                        <label htmlFor={`item-${idx}`} className="text-base font-black text-slate-700 leading-tight cursor-pointer uppercase">
                                                            {item.description}
                                                        </label>
                                                    </div>
                                                    <span className="text-lg font-black text-purple-600 font-mono">C$ {item.salePrice.toFixed(2)}</span>
                                                </div>

                                                {selectedItems[idx] && (
                                                    <div className="flex items-center justify-between pl-9 pt-2 border-t border-slate-50">
                                                        <span className="text-xs font-black text-slate-400 uppercase">Deolver:</span>
                                                        <div className="flex items-center gap-4 bg-slate-100 rounded-xl p-1">
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 hover:bg-white text-purple-600 shadow-sm"
                                                                onClick={() => handleQuantityChange(idx, (selectedQuantities[idx] || 1) - 1, maxReturnable)}
                                                            >-</Button>
                                                            <span className="w-8 text-center text-lg font-black text-slate-800 font-mono">{selectedQuantities[idx] || 1}</span>
                                                            <Button
                                                                variant="ghost"
                                                                size="icon"
                                                                className="h-8 w-8 hover:bg-white text-purple-600 shadow-sm"
                                                                onClick={() => handleQuantityChange(idx, (selectedQuantities[idx] || 1) + 1, maxReturnable)}
                                                            >+</Button>
                                                            <span className="text-[10px] font-black text-slate-400 mr-2">/ {maxReturnable}</span>
                                                        </div>
                                                    </div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </ScrollArea>
                            
                            <div className="flex justify-between items-center bg-emerald-500 p-6 rounded-2xl text-white shadow-xl">
                                <span className="text-sm font-black uppercase tracking-widest">Total Reembolso</span>
                                <span className="text-4xl font-black font-mono">C$ {refundTotal.toFixed(2)}</span>
                            </div>

                            <DialogFooter className="gap-2 pt-4">
                                <Button variant="ghost" className="flex-1 font-black text-slate-400" onClick={() => setSale(null)}>CANCELAR</Button>
                                <Button className="flex-2 h-16 px-12 bg-emerald-500 hover:bg-emerald-600 text-white font-black text-xl shadow-xl rounded-xl uppercase" onClick={handleReturn} disabled={isProcessing || refundTotal === 0}>
                                    {isProcessing ? <Loader2 className="animate-spin" /> : <><CheckCircle2 className="mr-2" /> PROCESAR</>}
                                </Button>
                            </DialogFooter>
                        </div>
                    )}
                </div>
            </DialogContent>
        </Dialog>
    );
}

import apiClient from '@/services/api-client';

import { useEffect, useState } from "react";
import { format } from 'date-fns';
import { es } from 'date-fns/locale';

interface Movement {
    id: string;
    timestamp: any;
    productDescription: string;
    movement: string;
    type: string;
    had: number;
    quantity: number;
    has: number;
}

interface Settings {
  headerLine1?: string;
  headerLine2?: string;
  headerLine3?: string;
  headerLine4?: string;
  footerLine1?: string;
  footerLine2?: string;
  fontFamily?: string;
  fontSize?: number;
  columns?: number;
}

interface PrintableTicketProps {
    storeId: string;
    movements: Movement[];
    date?: Date;
}

async function fetchStoreSettings(storeId: string): Promise<Settings | null> {
    try {
        const res = await apiClient.get(`/stores/${storeId}`);
        if (res.data && res.data.settings) {
            return res.data.settings;
        }
        return null;
    } catch (error) {
        console.error("Failed to fetch store settings:", error);
        return null;
    }
}

function parseTimestamp(ts: any): Date {
    if (!ts) return new Date();
    if (ts instanceof Date) return ts;
    if (typeof ts === 'string') return new Date(ts);
    if (ts.toDate) return ts.toDate();
    return new Date();
}

export async function generatePlainTextTicket(storeId: string, movements: Movement[], date?: Date): Promise<string> {
    const settings = await fetchStoreSettings(storeId);
    const columns = settings?.columns || 32;

    const center = (text: string) => text.padStart((columns + text.length) / 2, ' ').padEnd(columns, ' ');
    const line = '-'.repeat(columns);

    let output = '';
    
    // Header
    if (settings?.headerLine1) output += center(settings.headerLine1) + '\n';
    if (settings?.headerLine2) output += center(settings.headerLine2) + '\n';
    if (settings?.headerLine3) output += center(settings.headerLine3) + '\n';
    if (settings?.headerLine4) output += center(settings.headerLine4) + '\n';
    output += '\n';

    // Info
    output += line + '\n';
    output += 'Reporte de Movimientos'.padEnd(columns, ' ') + '\n';
    const dateStr = date ? format(date, 'PPP', { locale: es }) : 'N/A';
    output += `Fecha: ${dateStr}`.padEnd(columns, ' ') + '\n';
    output += line + '\n';

    // Items Header
    output += 'HORA'.padEnd(8) + 'PRODUCTO'.padEnd(columns - 16) + 'CANT.'.padStart(8) + '\n';
    output += line + '\n';

    // Items
    for (const item of movements) {
        const dateObj = parseTimestamp(item.timestamp);
        const time = item.timestamp ? format(dateObj, 'p', { locale: es }) : '';
        const desc = item.productDescription;
        const qty = item.quantity.toFixed(2);
        
        output += time.padEnd(8) + desc.substring(0, columns - 17).padEnd(columns - 16) + qty.padStart(8) + '\n';
    }
    output += line + '\n';

    // Footer Totals
    const totalMovements = `No. de Movs: ${movements.length}`;
    const totalItems = `Total de Pzas: ${movements.reduce((acc, mov) => acc + Math.abs(mov.quantity), 0).toFixed(2)}`;
    output += totalMovements.padStart(columns, ' ') + '\n';
    output += totalItems.padStart(columns, ' ') + '\n\n';

    // Footer Text
    if (settings?.footerLine1) output += center(settings.footerLine1) + '\n';
    if (settings?.footerLine2) output += center(settings.footerLine2) + '\n';

    return output;
}

export function PrintableTicket({ storeId, movements, date }: PrintableTicketProps) {
  const [settings, setSettings] = useState<Settings | null>(null);

  useEffect(() => {
    async function loadSettings() {
      const fetchedSettings = await fetchStoreSettings(storeId);
      setSettings(fetchedSettings);
    }
    loadSettings();
  }, [storeId]);
  
  const totalItems = movements.reduce((acc, mov) => acc + Math.abs(mov.quantity), 0);
  const dateStr = date ? format(date, 'PPP', { locale: es }) : 'N/A';

  return (
    <div 
        id="printable-content" 
        className="hidden print:block font-mono text-black bg-white p-2"
        style={{ fontFamily: settings?.fontFamily || 'monospace', fontSize: `${settings?.fontSize || 10}pt` }}
    >
        <div className="text-center space-y-1 mb-4">
            {settings?.headerLine1 && <p>{settings.headerLine1}</p>}
            {settings?.headerLine2 && <p>{settings.headerLine2}</p>}
            {settings?.headerLine3 && <p>{settings.headerLine3}</p>}
            {settings?.headerLine4 && <p>{settings.headerLine4}</p>}
        </div>

        <div className="border-t border-b border-dashed border-gray-600 py-1">
            <p>Reporte de Movimientos</p>
            <p>Fecha: {dateStr}</p>
        </div>

        <div className="my-2">
          <div className="grid grid-cols-12 gap-2 font-bold">
            <span className="col-span-2">HORA</span>
            <span className="col-span-7">PRODUCTO</span>
            <span className="col-span-3 text-right">CANT.</span>
          </div>
          <div className="border-t border-b border-dashed border-gray-600 my-1 py-1 space-y-1">
            {movements.map((item, idx) => {
                const dateObj = parseTimestamp(item.timestamp);
                return (
                    <div key={item.id || idx.toString()} className="grid grid-cols-12 gap-2">
                        <span className="col-span-2">{item.timestamp ? format(dateObj, 'p', { locale: es }) : ''}</span>
                        <span className="col-span-7">{item.productDescription}</span>
                        <span className="col-span-3 text-right">{item.quantity.toFixed(2)}</span>
                    </div>
                );
            })}
          </div>
        </div>
        
        <div className="flex justify-end mt-2">
          <div className="w-1/2">
            <div className="flex justify-between">
              <span>No. de Movs:</span>
              <span>{movements.length}</span>
            </div>
             <div className="flex justify-between">
              <span>Total de Pzas:</span>
              <span>{totalItems.toFixed(2)}</span>
            </div>
          </div>
        </div>

        <div className="text-center mt-4 space-y-1">
            {settings?.footerLine1 && <p>{settings.footerLine1}</p>}
            {settings?.footerLine2 && <p>{settings.footerLine2}</p>}
        </div>
    </div>
  );
}

import { useState } from 'react';
import Papa from 'papaparse';
