interface ImportProductsDialogProps {
  storeId: string;
  departments: { id: string; name: string }[];
}

const HEADER_MAPPING: Record<string, string> = {
  'Código de Barras': 'barcode',
  'Descripción': 'description',
  'Precio de Costo': 'costPrice',
