import { useState, useEffect, createContext, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import apiClient from '../services/api-client';
import { User } from '../types';
import { getRedirectPath } from '../lib/redirect-logic';

interface AuthContextType {
  user: User | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<User>;
  logout: () => void;
  isAuthenticated: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<User | null>(() => {
    const savedUser = localStorage.getItem('user');
    if (savedUser) {
      try {
        return JSON.parse(savedUser);
      } catch (e) {
        localStorage.removeItem('access_token');
        localStorage.removeItem('user');
        return null;
      }
    }
    return null;
  });

  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const initAuth = async () => {
      const token = localStorage.getItem('access_token');
      if (token) {
        apiClient.defaults.headers.common['Authorization'] = `Bearer ${token}`;
        try {
          const res = await apiClient.get('/auth/profile');
          setUser(res.data);
        } catch (error) {
          console.error("Token expirado o inválido");
          localStorage.removeItem('access_token');
          localStorage.removeItem('user');
          setUser(null);
        }
      }
      setLoading(false);
    };
    initAuth();
  }, []);

  const login = async (email: string, password: string) => {
    try {
      const response = await apiClient.post('/auth/login', { email, password });
      const { accessToken, user: userData } = response.data;
      
      localStorage.setItem('access_token', accessToken);
      localStorage.setItem('user', JSON.stringify(userData));
      setUser(userData);
      
      // Manejar redirección automática
      const redirectPath = getRedirectPath(userData);
      if (redirectPath) {
        navigate(redirectPath);
      }
      
      return userData;
    } catch (error) {
      throw error;
    }
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('user');
    setUser(null);
    navigate('/login');
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, isAuthenticated: !!user }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import { createContext, useContext, useState, ReactNode, useMemo } from 'react';
import { Product } from '../types';
import { toast } from '@/lib/swalert';

export interface CartItem extends Product {
    uniqueId: string; // for React keys
    quantity: number;
}

interface PosContextType {
    cart: CartItem[];
    addToCart: (product: Product) => void;
    removeFromCart: (uniqueId: string) => void;
    clearCart: () => void;
    mode: 'products' | 'payment';
    setMode: (mode: 'products' | 'payment') => void;
    handleHoldBill: () => void;
    handleCreditNoteClick: () => void;
    setIsHeldBillsOpen: (open: boolean) => void;
    isHeldBillsOpen: boolean;
    setShowQuickSwitch: (open: boolean) => void;
    showQuickSwitch: boolean;
    handleOpenDrawer: () => void;
    handlePayment: () => void;
    client: { name: string; id?: string } | null;
    setClient: (client: { name: string; id?: string } | null) => void;
    isLoading: boolean;
    setIsLoading: (loading: boolean) => void;
}

const PosContext = createContext<PosContextType | undefined>(undefined);

export function PosProvider({ children }: { children: ReactNode }) {
    const [cart, setCart] = useState<CartItem[]>([]);
    const [mode, setMode] = useState<'products' | 'payment'>('products');
    const [isHeldBillsOpen, setIsHeldBillsOpen] = useState(false);
    const [showQuickSwitch, setShowQuickSwitch] = useState(false);
    const [client, setClient] = useState<{ name: string; id?: string } | null>(null);
    const [isLoading, setIsLoading] = useState(false);

    const addToCart = (product: Product) => {
        setCart((prev) => {
            const existing = prev.find((item) => item.id === product.id);
            if (existing) {
                return prev.map((item) =>
                    item.id === product.id
                        ? { ...item, quantity: item.quantity + 1 }
                        : item
                );
            }
            return [...prev, { ...product, quantity: 1, uniqueId: crypto.randomUUID() }];
        });
    };

    const removeFromCart = (uniqueId: string) => {
        setCart((prev) => prev.filter((item) => item.uniqueId !== uniqueId));
    };

    const clearCart = () => {
        if (confirm("¿Estás seguro de limpiar el carrito?")) {
            setCart([]);
        }
    };

    const handleHoldBill = () => {
        setCart([]);
        setMode('products');
    };

    const handleCreditNoteClick = () => {
        toast.info(
            'Nota de crédito',
            'El flujo formal de nota de crédito quedará en la siguiente fase operativa.'
        );
    };

    const handleOpenDrawer = () => {
        toast.info(
            'Abrir gaveta',
            'La integración directa con hardware de caja se habilitará en la fase de dispositivos.'
        );
    };

    const handlePayment = () => {
        setMode('payment');
    };

    const contextValue = useMemo(() => ({
        cart,
        addToCart,
        removeFromCart,
        clearCart,
        mode,
        setMode,
        handleHoldBill,
        handleCreditNoteClick,
        setIsHeldBillsOpen,
        isHeldBillsOpen,
        setShowQuickSwitch,
        showQuickSwitch,
        handleOpenDrawer,
        handlePayment,
        client,
        setClient,
        isLoading,
        setIsLoading,
    }), [
        cart,
        mode,
        isHeldBillsOpen,
        showQuickSwitch,
        client,
        isLoading,
        // function refs are stable since they aren't recreation on render now
        addToCart,
        removeFromCart,
        clearCart,
        handleHoldBill,
        handlePayment
    ]);

    return (
        <PosContext.Provider value={contextValue}>
            {children}
        </PosContext.Provider>
    );
}

export function usePos() {
    const context = useContext(PosContext);
    if (context === undefined) {
        throw new Error('usePos must be used within a PosProvider');
    }
    return context;
}

/**
 * useOfflineOperation Hook
 * 
 * Custom hook for executing operations with offline support
 * Automatically enqueues operations when offline and processes them when online
 */


import { useState } from 'react';
import { syncService, type OperationType, type OperationPriority } from '@/lib/sync-service';
import { logError } from '@/lib/error-logger';

interface UseOfflineOperationOptions {
    storeId: string;
    type: OperationType;
    priority?: OperationPriority;
    onSuccess?: () => void;
    onError?: (error: Error) => void;
}

interface UseOfflineOperationReturn {
    execute: (operation: () => Promise<void>) => Promise<void>;
    isPending: boolean;
    error: Error | null;
}

export function useOfflineOperation(
    options: UseOfflineOperationOptions
): UseOfflineOperationReturn {
    const [isPending, setIsPending] = useState(false);
    const [error, setError] = useState<Error | null>(null);

    const execute = async (operation: () => Promise<void>) => {
        setIsPending(true);
        setError(null);

        try {
            const isOnline = syncService.getIsOnline();

            if (isOnline) {
                // Try to execute immediately
                try {
                    await operation();
                    options.onSuccess?.();
                } catch (execError: any) {
                    // If execution fails, enqueue for retry
                    await syncService.enqueuePendingOperation({
                        storeId: options.storeId,
                        type: options.type,
                        priority: options.priority || 'medium',
                        operation: operation.toString(), // Note: This is a simplified approach
                    });

                    throw execError;
                }
            } else {
                // Offline: enqueue immediately
                await syncService.enqueuePendingOperation({
                    storeId: options.storeId,
                    type: options.type,
                    priority: options.priority || 'medium',
                    operation: operation.toString(),
                });

                // Call success callback even when offline (operation is queued)
                options.onSuccess?.();
            }
        } catch (err: any) {
            const error = err instanceof Error ? err : new Error(String(err));
            setError(error);

            await logError(error, {
                location: 'use-offline-operation',
                additionalInfo: {
                    storeId: options.storeId,
                    type: options.type,
                },
            });

            options.onError?.(error);
            throw error;
        } finally {
            setIsPending(false);
        }
    };

    return {
        execute,
        isPending,
        error,
    };
}

