import { useCallback, useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { toast } from '@/lib/swalert';
import { clearCache } from '@/services/api-client';
import { SOCKET_PATH, SOCKET_URL } from '@/lib/runtime-config';

export const useRealTimeEvents = (storeId?: string) => {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [lastEvent, setLastEvent] = useState<any>(null);
  const [connected, setConnected] = useState(false);

  const isRelevantEvent = useCallback(
    (event: any) => {
      if (!storeId || !event?.storeId) {
        return true;
      }

      return event.storeId === storeId;
    },
    [storeId],
  );

  const handleNotification = useCallback((event: any) => {
    switch (event.type) {
      case 'NEW_ORDER':
        toast.success(
          '¡Nuevo Pedido!',
          `Se ha recibido una orden por C$ ${Number(event.payload?.total || 0).toFixed(2)}`
        );
        break;
      case 'NEW_VISIT':
        toast.info(
          'Nueva Visita en Ruta',
          `El vendedor ha registrado una visita en: ${event.payload?.clientId || 'Cliente desconocido'}`
        );
        break;
      case 'NOTIFICATION':
        toast.info(
          event.payload?.title || 'Notificación',
          event.payload?.message || 'Tienes un nuevo aviso.'
        );
        break;
      case 'ORDER_STATUS_CHANGE':
        toast.info(
          `Pedido ${event.payload?.orderId?.substring(0, 8)}`,
          `Ha cambiado de estado a: ${event.payload?.status?.replace('_', ' ')}`
        );
        break;
      default:
        break;
    }
  }, []);

  useEffect(() => {
    const newSocket = io(SOCKET_URL, {
      transports: ['websocket'],
      autoConnect: true,
      path: SOCKET_PATH,
    });

    const handleRealtimeEvent = (data: any) => {
      if (!isRelevantEvent(data)) {
        return;
      }

      clearCache();
      setLastEvent(data);
      handleNotification(data);
    };

    newSocket.on('connect', () => {
      setConnected(true);
      if (storeId) {
        newSocket.emit('join_store', storeId);
      }
    });

    newSocket.on('disconnect', () => {
      setConnected(false);
    });

    newSocket.on('sync_update', handleRealtimeEvent);
    newSocket.on('store_update', handleRealtimeEvent);

    setSocket(newSocket);

    return () => {
      newSocket.off('sync_update', handleRealtimeEvent);
      newSocket.off('store_update', handleRealtimeEvent);
      newSocket.close();
    };
  }, [handleNotification, isRelevantEvent, storeId]);

  return { socket, lastEvent, connected };
};

"use client"

// Inspired by react-hot-toast library
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

