      text,
      icon: 'error',
      confirmButtonColor: '#2196f3',
      background: '#f8fafc',
      customClass: {
        popup: 'rounded-2xl border-none shadow-2xl',
        title: 'text-2xl font-black uppercase tracking-tight'
      }
    });
  }
};

export default Swal;

/**
 * Sync Service for Offline Operations Management (Postgres Edition)
 * 
 * Handles queuing and synchronization of offline operations
 * pointing to the NestJS Batch API (/api/sync/batch).
 */

import { indexedDBService, type PendingOperation, type SyncStatus } from './indexed-db-service';
import apiClient from '../services/api-client';
import { withAppBase } from './runtime-config';

const BATCH_SIZE = 15; 

export type OperationType = PendingOperation['type'];
export type OperationPriority = PendingOperation['priority'];

class SyncService {
    private isProcessing = false;
    private syncListeners: Map<string, Set<(status: SyncStatus) => void>> = new Map();
    private networkStatusListeners: Set<(isOnline: boolean) => void> = new Set();
    private isOnline = navigator.onLine;

    constructor() {
        this.initNetworkListeners();
    }

    private initNetworkListeners() {
        if (typeof window === 'undefined') return;

        window.addEventListener('online', () => this.updateOnlineStatus(true));
        window.addEventListener('offline', () => this.updateOnlineStatus(false));
        
        // Heartbeat cada 30s para verificar internet real
        setInterval(async () => {
            try {
                await fetch(withAppBase('/favicon.svg'), { method: 'HEAD', cache: 'no-cache' });
                this.updateOnlineStatus(true);
            } catch (e) {
                this.updateOnlineStatus(false);
            }
        }, 30000);
    }

    private updateOnlineStatus(isOnline: boolean) {
        if (this.isOnline !== isOnline) {
            this.isOnline = isOnline;
            this.networkStatusListeners.forEach(cb => cb(isOnline));

            if (isOnline) {
                setTimeout(() => this.processPendingQueue(), 1000);
            }
        }
    }

    async enqueuePendingOperation(params: { storeId: string, type: OperationType, operation: any, priority?: OperationPriority }): Promise<string> {
        const operationId = `op_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;

        const pendingOp: PendingOperation = {
            id: operationId,
            storeId: params.storeId,
            type: params.type,
            priority: params.priority || 'medium',
            operation: params.operation,
            timestamp: Date.now(),
            retryCount: 0,
            status: 'pending',
        };

        await indexedDBService.savePendingOperation(pendingOp);
        await this.updateStoreSyncStatus(params.storeId);

        if (this.isOnline && !this.isProcessing) {
            this.processPendingQueue();
        }

        return operationId;
    }

    async processPendingQueue(): Promise<void> {
        if (this.isProcessing || !this.isOnline) return;
        this.isProcessing = true;

        try {
            const allOps = await indexedDBService.getAllPendingOperations();
            const pendingOps = allOps.filter(op => op.status === 'pending' || op.status === 'failed');

            if (pendingOps.length === 0) {
                this.isProcessing = false;
                return;
            }

            // Agrupar por tienda para el Batch API
            const stores = Array.from(new Set(pendingOps.map(op => op.storeId)));

            for (const storeId of stores) {
                const storeOps = pendingOps.filter(op => op.storeId === storeId).slice(0, BATCH_SIZE);
                
                try {
                    // LLAMADA AL BATCH API DE NESTJS
                    await apiClient.post('/sync/batch', {
                        storeId,
                        operations: storeOps.map(op => ({
                            type: op.type,
                            data: op.operation,
                            localId: op.id
                        }))
                    });

                    // Si tiene éxito, eliminar de IndexedDB
                    for (const op of storeOps) {
                        await indexedDBService.removePendingOperation(op.id);
                    }
                } catch (error: any) {
                    for (const op of storeOps) {
                        await indexedDBService.updateOperationStatus(op.id, 'failed', error.message);
                    }
                }
                await this.updateStoreSyncStatus(storeId);
            }
        } catch (error) {
            console.error(error);
        } finally {
            this.isProcessing = false;
        }
    }

    private async updateStoreSyncStatus(storeId: string): Promise<void> {
        const pendingCount = await indexedDBService.getPendingCount(storeId);
        const failedCount = await indexedDBService.getFailedCount(storeId);

        const status: SyncStatus = {
            storeId,
            lastSyncTimestamp: Date.now(),
            pendingCount,
            failedCount,
            isOnline: this.isOnline,
        };

        await indexedDBService.updateSyncStatus(status);
        const listeners = this.syncListeners.get(storeId);
        if (listeners) listeners.forEach(cb => cb(status));
    }

    onSyncStatusChange(storeId: string, callback: (status: SyncStatus) => void) {
        if (!this.syncListeners.has(storeId)) this.syncListeners.set(storeId, new Set());
        this.syncListeners.get(storeId)!.add(callback);
        return () => this.syncListeners.get(storeId)?.delete(callback);
    }

    getIsOnline(): boolean {
        return this.isOnline;
    }
}

export const syncService = new SyncService();

import { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { Store, Users, DollarSign, TrendingUp } from 'lucide-react';
import apiClient from '@/services/api-client';
import { useAuth } from '@/contexts/auth-context';
import { formatCurrency } from '@/lib/utils';
import { Store as StoreModel, User } from '@/types';

interface ChainStats {
    totalStores: number;
    totalUsers: number;
    dailySalesVolume: number;
    monthlySalesVolume: number;
}

export default function ChainDashboardPage() {
    const { user } = useAuth();
    const [stats, setStats] = useState<ChainStats | null>(null);
    const [stores, setStores] = useState<StoreModel[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                // 1. Obtener tiendas a las que tiene acceso / su cadena
                const storesRes = await apiClient.get('/stores');
                const storeList: StoreModel[] = storesRes.data || [];
                setStores(storeList);

                // 2. Usuarios totales asignados a estas tiendas (esto se podria depurar, pero simulamos aqui /users endpoint scopeado)
                let userList: User[] = [];
                try {
                    const usersRes = await apiClient.get('/users');
                    userList = usersRes.data || [];
                } catch (e) {}

                // 3. Obtener ventas por tienda
                let dailyTotal = 0;
                let monthlyTotal = 0;

                const storeIds = storeList.map(s => s.id);
                // Si la cantidad de tiendas es razonable, hacemos fetch concurrente
                if (storeIds.length > 0) {
                    const statsPromises = storeIds.map(id =>
                        apiClient.get('/sales/dashboard-stats', { params: { storeId: id } })
                            .then(res => res.data)
                            .catch(() => ({ dailyTotal: 0, monthlyTotal: 0, weeklyTotal: 0 }))
                    );
                    const allStats = await Promise.all(statsPromises);
                    dailyTotal = allStats.reduce((acc, curr) => acc + (curr.dailyTotal || 0), 0);
                    monthlyTotal = allStats.reduce((acc, curr) => acc + (curr.monthlyTotal || 0), 0);
                }

                setStats({
                    totalStores: storeList.length,
                    totalUsers: userList.length,
                    dailySalesVolume: dailyTotal,
                    monthlySalesVolume: monthlyTotal
                });

            } catch (err) {
                console.error("Error loading chain dashboard:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchDashboardData();
        const interval = setInterval(fetchDashboardData, 60000);
        return () => clearInterval(interval);
    }, []);

    if (loading) {
        return (
            <div className="space-y-6">
                <h1 className="text-2xl font-bold tracking-tight">Dashboard Corporativo Multisucursal</h1>
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                    {Array.from({ length: 4 }).map((_, i) => (
                        <Card key={i}>
                            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                                <Skeleton className="h-5 w-24" />
                                <Skeleton className="h-4 w-4" />
                            </CardHeader>
                            <CardContent><Skeleton className="h-8 w-20" /></CardContent>
                        </Card>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold tracking-tight">Dashboard Corporativo</h1>
                <p className="text-muted-foreground">Monitor en tiempo real de operaciones consolidado de la cadena multi-tienda.</p>
            </div>

            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                <Card className="border-l-4 border-l-blue-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Volumen Diario Bruto</CardTitle>
                        <DollarSign className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{formatCurrency(stats?.dailySalesVolume || 0)}</div>
                        <p className="text-xs text-muted-foreground mt-1">Facturación consolidada global de hoy.</p>
                    </CardContent>
                </Card>

                <Card className="border-l-4 border-l-emerald-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Volumen del Mes</CardTitle>
                        <TrendingUp className="h-4 w-4 text-emerald-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{formatCurrency(stats?.monthlySalesVolume || 0)}</div>
                        <p className="text-xs text-muted-foreground mt-1">Suma global en curso en toda la cadena.</p>
                    </CardContent>
                </Card>

                <Card className="border-l-4 border-l-purple-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Sucursales Activas</CardTitle>
                        <Store className="h-4 w-4 text-purple-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{stats?.totalStores || 0}</div>
                        <p className="text-xs text-muted-foreground mt-1">Tiendas operativas bajo el paraguas.</p>
                    </CardContent>
                </Card>

                <Card className="border-l-4 border-l-orange-500">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Planilla Corporativa</CardTitle>
                        <Users className="h-4 w-4 text-orange-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{stats?.totalUsers || 0}</div>
                        <p className="text-xs text-muted-foreground mt-1">Total de usuarios operando el sistema.</p>
                    </CardContent>
                </Card>
            </div>

            <h2 className="text-xl font-bold mt-8 mb-4 tracking-tight">Rendimiento por Sucursal</h2>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                {stores.map(store => (
                    <Card key={store.id} className="cursor-pointer hover:bg-slate-50 transition-colors" onClick={() => window.open(`/store/${store.id}/dashboard`, '_blank')}>
                        <CardHeader>
                            <CardTitle className="text-lg flex items-center justify-between">
                                {store.name}
                                <Store className="h-4 w-4 text-muted-foreground" />
                            </CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="text-sm text-muted-foreground mb-4">{store.address || 'Sin dirección registrada'}</div>
                            <div className="flex gap-2">
                                <span className="inline-flex items-center rounded-md bg-blue-50 px-2 py-1 text-xs font-medium text-blue-700 ring-1 ring-inset ring-blue-700/10">Abierta</span>
                            </div>
                        </CardContent>
                    </Card>
                ))}
                {stores.length === 0 && !loading && (
                    <div className="col-span-full border border-dashed rounded-lg p-12 text-center text-muted-foreground">
                        <Store className="h-8 w-8 mx-auto mb-2 opacity-50" />
                        Aún no hay tiendas creadas en esta cadena.
                    </div>
                )}
            </div>
        </div>
    );
}

