import { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { AlertCircle, AlertTriangle, CheckCircle, Users } from 'lucide-react';
import { differenceInDays, parseISO } from 'date-fns';
import apiClient from '@/services/api-client';

interface LicenseStats { active: number; expiringSoon: number; expired: number; }

export default function MasterDashboardPage() {
    const [licenseStats, setLicenseStats] = useState<LicenseStats | null>(null);
    const [totalUsers, setTotalUsers] = useState(0);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [usersRes, storesRes] = await Promise.all([apiClient.get('/users'), apiClient.get('/stores')]);
                setTotalUsers((usersRes.data || []).length);
                let active = 0, expiringSoon = 0, expired = 0;
                (storesRes.data || []).forEach((store: any) => {
                    if (!store.license?.expiryDate) return;
                    const days = differenceInDays(parseISO(store.license.expiryDate), new Date());
                    if (days < 0) expired++; else if (days <= 30) expiringSoon++; else active++;
                });
                setLicenseStats({ active, expiringSoon, expired });
            } catch { } finally { setLoading(false); }
        };
        fetchData();
        const interval = setInterval(fetchData, 60000);
        return () => clearInterval(interval);
    }, []);

    if (loading) return (
        <div className="space-y-6"><h1 className="text-2xl font-bold tracking-tight">Panel de Master-Admin</h1>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">{Array.from({ length: 4 }).map((_, i) => (
                <Card key={i}><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><Skeleton className="h-5 w-32" /><Skeleton className="h-6 w-6 rounded-full" /></CardHeader><CardContent><Skeleton className="h-8 w-16" /></CardContent></Card>
            ))}</div>
        </div>
    );

    return (
        <div>
            <h1 className="text-2xl font-bold tracking-tight mb-4">Panel de Master-Admin</h1>
            <p className="text-muted-foreground mb-6">Métricas importantes para la gestión de todas las tiendas.</p>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Tiendas Activas</CardTitle><CheckCircle className="h-4 w-4 text-green-500" /></CardHeader><CardContent><div className="text-2xl font-bold">{licenseStats?.active ?? 0}</div></CardContent></Card>
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Licencias por Vencer</CardTitle><AlertTriangle className="h-4 w-4 text-yellow-500" /></CardHeader><CardContent><div className="text-2xl font-bold">{licenseStats?.expiringSoon ?? 0}</div></CardContent></Card>
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Licencias Vencidas</CardTitle><AlertCircle className="h-4 w-4 text-red-500" /></CardHeader><CardContent><div className="text-2xl font-bold">{licenseStats?.expired ?? 0}</div></CardContent></Card>
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Total de Usuarios</CardTitle><Users className="h-4 w-4 text-muted-foreground" /></CardHeader><CardContent><div className="text-2xl font-bold">{totalUsers}</div></CardContent></Card>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { FileWarning } from 'lucide-react';
import { differenceInDays, parseISO } from 'date-fns';
import apiClient from '@/services/api-client';

type LicenseStatus = 'Activa' | 'Pronto a expirar' | 'Expirada' | 'Sin Licencia';
interface Store { id: string; name: string; address: string; phone: string; ownerEmail: string; license?: { type: string; startDate: string; expiryDate: string; numberOfUsers: number; status: string; }; computedStatus?: LicenseStatus; }

export default function MasterLicensesPage() {
    const [stores, setStores] = useState<Store[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const getComputedStatus = (license?: Store['license']): LicenseStatus => {
        if (!license || license.status === 'Inactiva') return 'Sin Licencia';
        if (license.type === 'Fijo') return 'Activa';
        if (!license.expiryDate) return 'Sin Licencia';
        const days = differenceInDays(parseISO(license.expiryDate), new Date());
        if (days < 0) return 'Expirada'; if (days <= 30) return 'Pronto a expirar'; return 'Activa';
    };

    useEffect(() => {
        const fetchStores = async () => {
            try { const res = await apiClient.get('/stores'); setStores((res.data || []).map((s: any) => ({ ...s, computedStatus: getComputedStatus(s.license) }))); }
            catch { setError('No se pudieron cargar las licencias.'); } finally { setLoading(false); }
        };
        fetchStores();
    }, []);

    const getStatusClass = (status?: LicenseStatus) => {
        switch (status) { case 'Activa': return 'bg-green-600 text-white'; case 'Pronto a expirar': return 'bg-yellow-500 text-black'; case 'Expirada': return 'bg-red-600 text-white'; default: return ''; }
    };

    const renderContent = () => {
        if (loading) return (<div className="space-y-2">{Array.from({ length: 3 }).map((_, i) => (<Skeleton key={i} className="h-12 w-full" />))}</div>);
        if (error) return (<Alert variant="destructive"><FileWarning className="h-4 w-4" /><AlertTitle>Error</AlertTitle><AlertDescription>{error}</AlertDescription></Alert>);
        if (stores.length === 0) return (<Alert><FileWarning className="h-4 w-4" /><AlertTitle>No hay tiendas</AlertTitle><AlertDescription>Sin tiendas para mostrar licencias.</AlertDescription></Alert>);
        return (
            <div className="rounded-md border"><Accordion type="single" collapsible className="w-full">
                {stores.map((store) => (<AccordionItem value={store.id} key={store.id}>
                    <AccordionTrigger className="px-6 py-4 hover:no-underline"><div className="flex items-center justify-between w-full"><span className="font-medium text-left">{store.name}</span><Badge className={getStatusClass(store.computedStatus)}>{store.computedStatus || 'Sin Licencia'}</Badge></div></AccordionTrigger>
                    <AccordionContent className="px-6 pb-4 bg-muted/50">
                        <div className="grid gap-4 md:grid-cols-2">
                            <div><h4 className="font-semibold mb-2">Licencia</h4>{store.license ? (<div className="space-y-1"><p className="text-sm"><strong>Tipo:</strong> {store.license.type}</p><p className="text-sm"><strong>Inicio:</strong> {store.license.startDate}</p><p className="text-sm"><strong>Expiración:</strong> {store.license.expiryDate}</p><p className="text-sm"><strong>Usuarios:</strong> {store.license.numberOfUsers}</p></div>) : (<p className="text-sm text-muted-foreground">Sin licencia asignada.</p>)}</div>
                            <div><h4 className="font-semibold mb-2">Tienda</h4><p className="text-sm"><strong>Dirección:</strong> {store.address}</p><p className="text-sm"><strong>Teléfono:</strong> {store.phone}</p><p className="text-sm"><strong>Email:</strong> {store.ownerEmail}</p></div>
                        </div>
                        <div className="mt-4 flex gap-2">
                            {store.license ? (
                                <Button variant="outline" size="sm" disabled title="Renovación aún no implementada">
                                    Renovar Licencia
                                </Button>
                            ) : (
                                <Button size="sm" disabled title="Alta de licencia aún no implementada">
                                    Agregar Licencia
                                </Button>
                            )}
                        </div>
                    </AccordionContent>
                </AccordionItem>))}
            </Accordion></div>
        );
    };

    return (
        <div>
            <div className="mb-6"><h1 className="text-2xl font-bold tracking-tight">Gestión de Licencias</h1><p className="text-muted-foreground">Visualiza y administra el estado de las licencias.</p></div>
            <Card><CardHeader><CardTitle>Todas las Licencias</CardTitle><CardDescription>Resumen de licencias activas, expiradas e inactivas.</CardDescription></CardHeader><CardContent>{renderContent()}</CardContent></Card>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { AlertTriangle, Terminal } from 'lucide-react';
import { formatDistanceToNow, format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Badge } from '@/components/ui/badge';
import apiClient from '@/services/api-client';

interface ErrorLog { id: string; message: string; timestamp: string; context: { location: string; userEmail: string; [key: string]: any; }; }

export default function MasterMonitorPage() {
    const [errorLogs, setErrorLogs] = useState<ErrorLog[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const fetchErrors = async () => { try { const res = await apiClient.get('/errors'); setErrorLogs(res.data || []); } catch { setError('No se pudieron cargar los registros.'); } finally { setLoading(false); } };
        fetchErrors();
        const interval = setInterval(fetchErrors, 30000);
        return () => clearInterval(interval);
    }, []);

    const parseTimestamp = (ts: any): Date | null => {
        if (!ts) return null; if (ts instanceof Date) return ts; if (typeof ts === 'string') return new Date(ts); if (ts._seconds) return new Date(ts._seconds * 1000); return null;
    };

    const renderContent = () => {
        if (loading) return (<div className="space-y-2">{Array.from({ length: 5 }).map((_, i) => (<Skeleton key={i} className="h-12 w-full" />))}</div>);
        if (error) return (<Alert variant="destructive"><Terminal className="h-4 w-4" /><AlertTitle>Error</AlertTitle><AlertDescription>{error}</AlertDescription></Alert>);
        if (errorLogs.length === 0) return (<Alert><Terminal className="h-4 w-4" /><AlertTitle>Todo en orden</AlertTitle><AlertDescription>No se han registrado errores recientemente.</AlertDescription></Alert>);
        return (
            <Accordion type="single" collapsible className="w-full">
                {errorLogs.map((log) => { const ts = parseTimestamp(log.timestamp); return (
                    <AccordionItem value={log.id} key={log.id}>
                        <AccordionTrigger className="hover:no-underline"><div className="flex items-center gap-4 w-full text-left"><AlertTriangle className="h-5 w-5 text-destructive shrink-0" /><div className="flex-grow"><p className="font-medium text-destructive truncate">{log.message}</p><p className="text-xs text-muted-foreground">{ts ? formatDistanceToNow(ts, { addSuffix: true, locale: es }) : 'N/A'}</p></div></div></AccordionTrigger>
                        <AccordionContent className="bg-muted/30 p-4 rounded-md">
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-4 text-sm">
                                <div><h4 className="font-semibold mb-1">Ubicación</h4><Badge variant="secondary">{log.context?.location || 'N/A'}</Badge></div>
                                <div><h4 className="font-semibold mb-1">Usuario</h4><p>{log.context?.userEmail || 'No identificado'}</p></div>
                                <div><h4 className="font-semibold mb-1">Fecha Exacta</h4><p>{ts ? format(ts, 'PPP p', { locale: es }) : 'N/A'}</p></div>
                                {log.context && Object.entries(log.context).filter(([key]) => !['location', 'userEmail'].includes(key)).map(([key, value]) => (
                                    <div key={key}><h4 className="font-semibold mb-1 capitalize">{key}</h4><pre className="text-xs bg-background p-2 rounded-md overflow-x-auto">{typeof value === 'object' ? JSON.stringify(value, null, 2) : String(value)}</pre></div>
                                ))}
                            </div>
                        </AccordionContent>
                    </AccordionItem>
                ); })}
            </Accordion>
        );
    };

    return (
        <div>
            <div className="mb-6"><h1 className="text-2xl font-bold tracking-tight">Monitor del Sistema</h1><p className="text-muted-foreground">Supervisa errores y eventos importantes.</p></div>
            <Card><CardHeader><CardTitle>Registros de Errores</CardTitle><CardDescription>Errores capturados, polling cada 30s.</CardDescription></CardHeader><CardContent>{renderContent()}</CardContent></Card>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { Skeleton } from '@/components/ui/skeleton';
import { differenceInDays, parseISO } from 'date-fns';
import { Edit, Trash2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { FloatingActionButton } from '@/components/floating-action-button';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/components/ui/alert-dialog';
import { useToast } from '@/hooks/use-toast';
import apiClient from '@/services/api-client';

type LicenseStatus = 'Activa' | 'Pronto a expirar' | 'Expirada' | 'Sin Licencia';
interface Store { id: string; name: string; address: string; phone: string; ownerEmail: string; license?: { type: string; startDate: string; expiryDate: string; status: string; }; computedStatus?: LicenseStatus; }

export default function MasterStoresPage() {
    const [stores, setStores] = useState<Store[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const { toast } = useToast();

    const getComputedStatus = (license: any): LicenseStatus => {
        if (!license || license.status === 'Inactiva') return 'Sin Licencia';
        if (license.type === 'Fijo') return 'Activa';
        if (!license.expiryDate) return 'Sin Licencia';
        const days = differenceInDays(parseISO(license.expiryDate), new Date());
        if (days < 0) return 'Expirada'; if (days <= 7) return 'Pronto a expirar'; return 'Activa';
    };

    const fetchStores = async () => {
        try { const res = await apiClient.get('/stores'); setStores((res.data || []).map((s: any) => ({ ...s, computedStatus: getComputedStatus(s.license) }))); }
        catch { setError('No se pudieron cargar las tiendas.'); } finally { setLoading(false); }
    };
    useEffect(() => { fetchStores(); }, []);

    const handleDelete = async (storeId: string, storeName: string) => {
        try { await apiClient.delete(`/stores/${storeId}`); toast({ title: 'Tienda Eliminada', description: `"${storeName}" eliminada.` }); fetchStores(); }
        catch { toast({ variant: 'destructive', title: 'Error', description: 'No se pudo eliminar.' }); }
    };

    const getStatusColor = (status?: LicenseStatus) => {
        switch (status) { case 'Activa': return 'bg-green-500'; case 'Pronto a expirar': return 'bg-yellow-500'; case 'Expirada': return 'bg-destructive'; default: return 'bg-gray-500'; }
    };

    if (loading) return (<div className="space-y-4"><Skeleton className="h-12 w-full" /><Skeleton className="h-12 w-full" /><Skeleton className="h-12 w-full" /></div>);
    if (error) return <div className="p-4 text-red-500 bg-red-100 rounded-md">{error}</div>;

    return (
        <div>
            <div className="mb-6"><h1 className="text-2xl font-bold tracking-tight">Gestión de Tiendas</h1><p className="text-muted-foreground">Administra las tiendas registradas.</p></div>
            {stores.length === 0 ? (<div className="text-center p-8 border rounded-lg bg-muted/20"><p className="text-muted-foreground">No hay tiendas registradas.</p></div>) : (
                <div className="rounded-md border"><Accordion type="single" collapsible className="w-full">
                    {stores.map((store) => (<AccordionItem value={store.id} key={store.id}>
                        <AccordionTrigger className="px-6 py-4 hover:no-underline"><div className="flex items-center justify-between w-full"><span className="font-medium text-left">{store.name}</span><Badge className={getStatusColor(store.computedStatus)}>{store.computedStatus || 'Sin Estado'}</Badge></div></AccordionTrigger>
                        <AccordionContent className="px-6 pb-4 bg-muted/50">
                            <div className="grid gap-4 md:grid-cols-2">
                                <div><h4 className="font-semibold mb-2">Detalles</h4><div className="space-y-1 text-sm"><p><strong>Dirección:</strong> {store.address}</p><p><strong>Teléfono:</strong> {store.phone}</p><p><strong>Email:</strong> {store.ownerEmail}</p></div></div>
                                <div><h4 className="font-semibold mb-2">Licencia</h4>{store.license ? (<div className="space-y-1 text-sm"><p><strong>Tipo:</strong> {store.license.type}</p><p><strong>Inicio:</strong> {new Date(store.license.startDate).toLocaleDateString()}</p><p><strong>Vence:</strong> {store.license.expiryDate ? new Date(store.license.expiryDate).toLocaleDateString() : 'N/A'}</p></div>) : (<p className="text-sm text-muted-foreground">Sin licencia</p>)}</div>
                            </div>
                            <div className="mt-4 flex gap-2 justify-end">
                                <Button asChild variant="outline" size="sm"><Link to={`/master-admin/stores/edit/${store.id}`}><Edit className="mr-2 h-4 w-4" /> Editar</Link></Button>
                                <AlertDialog><AlertDialogTrigger asChild><Button variant="destructive" size="sm"><Trash2 className="mr-2 h-4 w-4" /> Eliminar</Button></AlertDialogTrigger>
                                    <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>¿Estás seguro?</AlertDialogTitle><AlertDialogDescription>Esto eliminará "{store.name}" permanentemente.</AlertDialogDescription></AlertDialogHeader>
                                        <AlertDialogFooter><AlertDialogCancel>Cancelar</AlertDialogCancel><AlertDialogAction onClick={() => handleDelete(store.id, store.name)}>Eliminar</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                </AlertDialog>
                            </div>
                        </AccordionContent>
                    </AccordionItem>))}
                </Accordion></div>
            )}
            <FloatingActionButton href="/master-admin/stores/add" />
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useToast } from '@/hooks/use-toast';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogDescription } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';
import apiClient from '@/services/api-client';

interface Zone {
    id: string;
    name: string;
}

interface SubZone {
    id?: string;
    name: string;
    zoneId: string;
    zoneName?: string;
    description?: string;
    isActive?: boolean;
}

export default function MasterSubZonesPage() {
    const [subZones, setSubZones] = useState<SubZone[]>([]);
    const [zones, setZones] = useState<Zone[]>([]);
    const [loading, setLoading] = useState(true);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [currentSubZone, setCurrentSubZone] = useState<Partial<SubZone>>({});
    const { toast } = useToast();

    const fetchData = async () => {
        try {
            const [zonesRes, subZonesRes] = await Promise.all([
                apiClient.get('/zones'),
                apiClient.get('/sub-zones'),
            ]);
            setZones(zonesRes.data || []);
            setSubZones(subZonesRes.data || []);
        } catch (error) {
            console.error("Error fetching data:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleSave = async () => {
        try {
            if (!currentSubZone.name || !currentSubZone.zoneId) {
                toast({ title: "Nombre y Zona son obligatorios", variant: "destructive" });
                return;
            }

            const payload = {
                name: currentSubZone.name,
                zoneId: currentSubZone.zoneId,
                description: currentSubZone.description || '',
            };

            if (currentSubZone.id) {
                await apiClient.patch(`/sub-zones/${currentSubZone.id}`, payload);
                toast({ title: "SubZona actualizada" });
            } else {
                await apiClient.post('/sub-zones', payload);
                toast({ title: "SubZona creada" });
            }
            setIsDialogOpen(false);
            setCurrentSubZone({});
            fetchData();
        } catch (error) {
            console.error(error);
            toast({ title: "Error al guardar", variant: "destructive" });
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("¿Seguro que deseas eliminar?")) return;
        try {
            await apiClient.delete(`/sub-zones/${id}`);
            toast({ title: "Eliminado correctamente" });
            fetchData();
        } catch (error) {
            toast({ title: "Error al eliminar", variant: "destructive" });
        }
    };

    const getZoneName = (id: string) => zones.find(z => z.id === id)?.name || id;

    if (loading) return <div className="p-8 text-center text-muted-foreground italic">Cargando Barrios...</div>;

    return (
        <div className="p-4 md:p-6 space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold tracking-tight">Gestión de Sub-Zonas (Barrios)</h1>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={() => setCurrentSubZone({})}>Nueva Sub-Zona</Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-lg">
                        <DialogHeader>
                            <DialogTitle>{currentSubZone.id ? 'Editar Sub-Zona' : 'Nueva Sub-Zona'}</DialogTitle>
                            <DialogDescription>
                                Ingrese el nombre del barrio y seleccione el municipio correspondiente.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="space-y-4 py-4">
