import { useEffect, useState, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { RefreshCw, Eye, Clock } from 'lucide-react';
import apiClient from '@/services/api-client';

interface SyncStatus { isOnline: boolean; pendingCount: number; failedCount: number; lastSyncTimestamp: number | null; }
interface StoreInfo { id: string; name: string; syncStatus: SyncStatus | null; }

export default function MasterSyncMonitorPage() {
    const [stores, setStores] = useState<StoreInfo[]>([]);
    const [loading, setLoading] = useState(true);
    const [forcingSyncId, setForcingSyncId] = useState<string | null>(null);
    const { toast } = useToast();

    const fetchStoresAndStatus = useCallback(async () => {
        try {
            setLoading(true);
            const storesRes = await apiClient.get('/stores');
            const storesData = (storesRes.data || []).map((s: any) => ({ id: s.id, name: s.name || 'Sin nombre' }));
            // In REST mode, sync status comes from a separate endpoint
            let syncStatuses: Record<string, SyncStatus> = {};
            try { const syncRes = await apiClient.get('/sync/statuses'); syncStatuses = syncRes.data || {}; } catch { }
            setStores(storesData.map((store: any) => ({ ...store, syncStatus: syncStatuses[store.id] || null })));
        } catch { toast({ variant: 'destructive', title: 'Error', description: 'No se pudieron cargar las tiendas' }); }
        finally { setLoading(false); }
    }, [toast]);

    useEffect(() => { fetchStoresAndStatus(); const i = setInterval(fetchStoresAndStatus, 30000); return () => clearInterval(i); }, [fetchStoresAndStatus]);

    const handleForceSync = async (storeId: string) => {
        setForcingSyncId(storeId);
        try { await apiClient.post(`/sync/force/${storeId}`); toast({ title: 'Sincronización Iniciada' }); setTimeout(fetchStoresAndStatus, 2000); }
        catch { toast({ variant: 'destructive', title: 'Error' }); } finally { setForcingSyncId(null); }
    };

    const getStatusBadge = (status: SyncStatus | null) => {
        if (!status) return <Badge variant="secondary">Sin datos</Badge>;
        if (!status.isOnline) return <Badge variant="secondary" className="bg-gray-100 text-gray-700">Offline</Badge>;
        if (status.failedCount > 0) return <Badge variant="destructive">Con errores</Badge>;
        if (status.pendingCount > 0) return <Badge className="bg-orange-100 text-orange-700">Pendiente</Badge>;
        return <Badge className="bg-green-100 text-green-700">Sincronizado</Badge>;
    };

    const formatLastSync = (timestamp: number | null) => {
        if (!timestamp) return 'Nunca';
        const diff = Date.now() - timestamp;
        if (diff < 60000) return 'Hace un momento'; if (diff < 3600000) return `Hace ${Math.floor(diff / 60000)} min`;
        if (diff < 86400000) return `Hace ${Math.floor(diff / 3600000)} h`; return new Date(timestamp).toLocaleString();
    };

    const stats = {
        total: stores.length,
        online: stores.filter(s => s.syncStatus?.isOnline).length,
        offline: stores.filter(s => !s.syncStatus?.isOnline).length,
        withErrors: stores.filter(s => s.syncStatus && s.syncStatus.failedCount > 0).length,
        totalPending: stores.reduce((acc, s) => acc + (s.syncStatus?.pendingCount || 0), 0),
    };

    return (
        <div className="space-y-6">
            <div><h1 className="text-3xl font-bold">Monitor de Sincronización</h1><p className="text-muted-foreground mt-2">Estado de sincronización de todas las tiendas</p></div>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-5">
                <Card><CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-muted-foreground">Total Tiendas</CardTitle></CardHeader><CardContent><div className="text-2xl font-bold">{stats.total}</div></CardContent></Card>
                <Card><CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-muted-foreground">En Línea</CardTitle></CardHeader><CardContent><div className="text-2xl font-bold text-green-600">{stats.online}</div></CardContent></Card>
                <Card><CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-muted-foreground">Sin Conexión</CardTitle></CardHeader><CardContent><div className="text-2xl font-bold text-gray-600">{stats.offline}</div></CardContent></Card>
                <Card><CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-muted-foreground">Con Errores</CardTitle></CardHeader><CardContent><div className="text-2xl font-bold text-red-600">{stats.withErrors}</div></CardContent></Card>
                <Card><CardHeader className="pb-2"><CardTitle className="text-sm font-medium text-muted-foreground">Ops. Pendientes</CardTitle></CardHeader><CardContent><div className="text-2xl font-bold text-orange-600">{stats.totalPending}</div></CardContent></Card>
            </div>
            <Card>
                <CardHeader><div className="flex items-center justify-between"><div><CardTitle>Tiendas</CardTitle><CardDescription>Estado de sincronización por tienda</CardDescription></div><Button variant="outline" size="sm" onClick={fetchStoresAndStatus} disabled={loading}><RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} />Actualizar</Button></div></CardHeader>
                <CardContent>
                    {loading ? (<div className="flex items-center justify-center py-8"><RefreshCw className="h-8 w-8 animate-spin text-muted-foreground" /></div>)
                    : stores.length === 0 ? (<div className="text-center py-8 text-muted-foreground">No hay tiendas registradas</div>)
                    : (<Table><TableHeader><TableRow><TableHead>Tienda</TableHead><TableHead>Estado</TableHead><TableHead className="text-center">Pendientes</TableHead><TableHead className="text-center">Errores</TableHead><TableHead>Última Sync</TableHead><TableHead className="text-right">Acciones</TableHead></TableRow></TableHeader>
                        <TableBody>{stores.map((store) => (<TableRow key={store.id}>
                            <TableCell className="font-medium">{store.name}</TableCell>
                            <TableCell>{getStatusBadge(store.syncStatus)}</TableCell>
                            <TableCell className="text-center">{store.syncStatus?.pendingCount || 0}</TableCell>
                            <TableCell className="text-center">{store.syncStatus?.failedCount || 0}</TableCell>
                            <TableCell className="text-sm text-muted-foreground"><div className="flex items-center gap-2"><Clock className="h-3 w-3" />{formatLastSync(store.syncStatus?.lastSyncTimestamp || null)}</div></TableCell>
                            <TableCell className="text-right"><div className="flex items-center justify-end gap-2">
                                {store.syncStatus?.isOnline && (store.syncStatus.pendingCount > 0 || store.syncStatus.failedCount > 0) && (
                                    <Button variant="outline" size="sm" onClick={() => handleForceSync(store.id)} disabled={forcingSyncId === store.id}><RefreshCw className={`h-4 w-4 mr-1 ${forcingSyncId === store.id ? 'animate-spin' : ''}`} />Forzar Sync</Button>
                                )}
                            </div></TableCell>
                        </TableRow>))}</TableBody></Table>)}
                </CardContent>
            </Card>
        </div>
    );
}

'use client';

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { FloatingActionButton } from '@/components/floating-action-button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Users, Edit } from 'lucide-react';
import { Button } from '@/components/ui/button';
import apiClient from '@/services/api-client';

interface User {
  uid: string;
  name: string;
  email: string;
  role: string;
  storeId?: string;
  storeName?: string;
}

export default function MasterUsersPage() {
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      const token = localStorage.getItem('access_token');
      if (!token) {
        setLoading(false);
        return;
      }

      try {
        const [usersRes, storesRes] = await Promise.all([
          apiClient.get('/users'),
          apiClient.get('/stores'),
        ]);
        
        const storesMap = new Map<string, string>();
        (storesRes.data || []).forEach((s: any) => storesMap.set(s.id, s.name));

        const usersData: User[] = (usersRes.data || []).map((u: any) => ({
          uid: u.id || u.uid,
          name: u.name,
          email: u.email,
          role: u.role,
          storeId: u.storeId || (u.storeIds && u.storeIds[0]),
          storeName: u.storeId ? storesMap.get(u.storeId) : (u.storeIds?.[0] ? storesMap.get(u.storeIds[0]) : undefined),
        }));
        setUsers(usersData);
      } catch (err) {
        console.error('Error fetching users:', err);
        setError('No se pudieron cargar los usuarios. Inténtalo de nuevo más tarde.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const getRoleVariant = (role: string) => {
    switch (role?.toLowerCase()) {
      case 'master-admin': return 'default';
      case 'store administrator': 
      case 'admin': return 'secondary';
      default: return 'outline';
    }
  };

  const getRoleClass = (role: string) => {
    switch (role?.toLowerCase()) {
      case 'master-admin': return 'bg-primary text-primary-foreground';
      case 'store administrator':
      case 'admin': return 'bg-secondary text-secondary-foreground';
      default: return 'border-primary text-primary';
    }
  };

  const renderContent = () => {
    if (loading) {
      return (
        <div className="space-y-2">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-12 w-full" />
          ))}
        </div>
      );
    }

    if (error) {
      return (
        <Alert variant="destructive">
          <Users className="h-4 w-4" />
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      );
    }

    if (users.length === 0) {
      return (
        <Alert>
          <Users className="h-4 w-4" />
          <AlertTitle>No hay usuarios</AlertTitle>
          <AlertDescription>Aún no hay usuarios registrados. ¡Agrega el primero!</AlertDescription>
        </Alert>
      );
    }

    return (
      <div className="rounded-md border">
        <Accordion type="single" collapsible className="w-full">
          {users.map((user) => (
            <AccordionItem value={user.uid} key={user.uid}>
              <AccordionTrigger className="px-6 py-4 hover:no-underline">
                <div className="flex items-center justify-between w-full">
                  <span className="font-medium text-left">{user.name}</span>
                  <Badge variant={getRoleVariant(user.role)} className={getRoleClass(user.role)}>
                    {user.role}
                  </Badge>
                </div>
              </AccordionTrigger>
              <AccordionContent className="px-6 pb-4 bg-muted/50">
                <div className="grid gap-4 md:grid-cols-2 mt-2">
                  <div>
                    <h4 className="font-semibold mb-2 text-sm text-muted-foreground uppercase tracking-tight">Información de Usuario</h4>
                    <div className="space-y-1">
                      <p className="text-sm"><strong>Correo:</strong> {user.email}</p>
                      <p className="text-sm"><strong>Rol:</strong> {user.role}</p>
                    </div>
                  </div>
                  <div>
                    <h4 className="font-semibold mb-2 text-sm text-muted-foreground uppercase tracking-tight">Tienda Asignada</h4>
                    <p className="text-sm">{user.storeName || 'N/A (Acceso Global)'}</p>
                  </div>
                </div>
                <div className="mt-4 pt-4 border-t flex gap-2">
                  <Button asChild variant="outline" size="sm">
                    <Link to={`/master-admin/users/edit/${user.uid}`}>
                      <Edit className="mr-2 h-4 w-4" /> Editar Usuario
                    </Link>
                  </Button>
                </div>
              </AccordionContent>
            </AccordionItem>
          ))}
        </Accordion>
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-1">
        <h1 className="text-2xl font-bold tracking-tight">Gestión de Usuarios</h1>
        <p className="text-muted-foreground">Crea, edita y gestiona los usuarios del sistema.</p>
      </div>
      <Card>
        <CardHeader>
          <CardTitle>Todos los Usuarios</CardTitle>
          <CardDescription>Una lista de todos los usuarios registrados en el sistema.</CardDescription>
        </CardHeader>
        <CardContent>{renderContent()}</CardContent>
      </Card>
      <FloatingActionButton href="/master-admin/users/add" />
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useToast } from '@/hooks/use-toast';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogDescription } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import apiClient from '@/services/api-client';

interface Zone {
    id?: string;
    name: string;
    description?: string;
    code?: string;
    isActive?: boolean;
}

export default function MasterZonesPage() {
    const [zones, setZones] = useState<Zone[]>([]);
    const [loading, setLoading] = useState(true);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [currentZone, setCurrentZone] = useState<Partial<Zone>>({});
    const { toast } = useToast();

    const fetchZones = async () => {
        try {
            const res = await apiClient.get('/zones');
            setZones(res.data || []);
        } catch (error) {
            console.error("Error fetching zones:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchZones();
    }, []);

    const handleSave = async () => {
        try {
            if (!currentZone.name) {
                toast({ title: "El nombre es obligatorio", variant: "destructive" });
                return;
            }

            if (currentZone.id) {
                await apiClient.patch(`/zones/${currentZone.id}`, {
                    name: currentZone.name,
                    description: currentZone.description || currentZone.code || '',
                });
                toast({ title: "Zona actualizada" });
            } else {
                await apiClient.post('/zones', {
                    name: currentZone.name,
                    description: currentZone.description || currentZone.code || '',
                });
                toast({ title: "Zona creada" });
            }
            setIsDialogOpen(false);
            setCurrentZone({});
            fetchZones();
        } catch (error) {
            console.error(error);
            toast({ title: "Error al guardar", variant: "destructive" });
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm("¿Seguro que deseas eliminar esta zona?")) return;
        try {
            await apiClient.delete(`/zones/${id}`);
            toast({ title: "Zona eliminada" });
            fetchZones();
        } catch (error) {
            toast({ title: "Error al eliminar", variant: "destructive" });
        }
    };

    if (loading) return <div className="p-8 text-center text-muted-foreground italic">Cargando Zonas...</div>;

    return (
        <div className="p-4 md:p-6 space-y-6">
            <div className="flex justify-between items-center">
                <h1 className="text-3xl font-bold tracking-tight">Gestión de Zonas (Municipios)</h1>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={() => setCurrentZone({})}>Nueva Zona</Button>
                    </DialogTrigger>
                    <DialogContent>
                        <DialogHeader>
                            <DialogTitle>{currentZone.id ? 'Editar Zona' : 'Nueva Zona'}</DialogTitle>
                            <DialogDescription>
                                Ingrese el nombre y código opcional para identificar la zona geográfica.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="space-y-4 py-4">
                            <div className="space-y-2">
                                <Label>Nombre</Label>
                                <Input
                                    value={currentZone.name || ''}
                                    onChange={(e) => setCurrentZone({ ...currentZone, name: e.target.value })}
                                    placeholder="Ej: San Salvador"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Código (Opcional)</Label>
                                <Input
                                    value={currentZone.code || ''}
                                    onChange={(e) => setCurrentZone({ ...currentZone, code: e.target.value })}
                                    placeholder="Ej: Z01"
                                />
                            </div>
                            <Button onClick={handleSave} className="w-full">Guardar</Button>
                        </div>
                    </DialogContent>
                </Dialog>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Listado de Zonas</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="overflow-x-auto">
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Nombre</TableHead>
                                    <TableHead>Descripción</TableHead>
                                    <TableHead className="text-right">Acciones</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {zones.map((zone) => (
                                    <TableRow key={zone.id}>
                                        <TableCell className="font-medium">{zone.name}</TableCell>
                                        <TableCell>{zone.description || zone.code || '-'}</TableCell>
                                        <TableCell className="text-right space-x-2 whitespace-nowrap">
                                            <Button variant="outline" size="sm" onClick={() => {
                                                setCurrentZone(zone);
                                                setIsDialogOpen(true);
                                            }}>Editar</Button>
                                            <Button variant="destructive" size="sm" onClick={() => zone.id && handleDelete(zone.id)}>Eliminar</Button>
                                        </TableCell>
                                    </TableRow>
                                ))}
                                {zones.length === 0 && (
                                    <TableRow>
                                        <TableCell colSpan={3} className="text-center py-4 text-muted-foreground">No hay zonas registradas</TableCell>
                                    </TableRow>
                                )}
                            </TableBody>
                        </Table>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

import { useEffect, useMemo, useState } from 'react';
import {
  BarChart3,
  Loader2,
  RefreshCw,
  Store,
  TrendingUp,
} from 'lucide-react';
import { startOfDay, startOfMonth, format, parseISO, isToday } from 'date-fns';
import { es } from 'date-fns/locale';

import apiClient from '@/services/api-client';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';

interface StoreData {
  id: string;
  name: string;
  dailySales: number;
  monthlySales: number;
  dailyCount: number;
  monthlyCount: number;
  pendingOrders: number;
}

export default function MultiStoreComparisonPage() {
  const [stores, setStores] = useState<StoreData[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const storesRes = await apiClient.get('/stores');
      const storeList = Array.isArray(storesRes.data) ? storesRes.data : [];

      const results: StoreData[] = await Promise.all(
        storeList.map(async (store: any) => {
          try {
            const [salesRes, ordersRes] = await Promise.all([
              apiClient.get('/sales', { params: { storeId: store.id } }),
              apiClient.get('/orders', { params: { storeId: store.id } }),
            ]);

            const sales = Array.isArray(salesRes.data) ? salesRes.data : [];
            const orders = Array.isArray(ordersRes.data) ? ordersRes.data : [];

            const todayStart = startOfDay(new Date());
            const monthStart = startOfMonth(new Date());

            const todaySales = sales.filter((s: any) => {
              const d = parseISO(s.createdAt);
              return d >= todayStart;
            });

            const monthSales = sales.filter((s: any) => {
              const d = parseISO(s.createdAt);
              return d >= monthStart;
            });

            const pendingOrders = orders.filter(
              (o: any) => !['ENTREGADO', 'CANCELADO', 'RECHAZADO'].includes(o.status),
            );

            return {
              id: store.id,
              name: store.name || 'Sin nombre',
              dailySales: todaySales.reduce((s: number, x: any) => s + Number(x.total || 0), 0),
              monthlySales: monthSales.reduce((s: number, x: any) => s + Number(x.total || 0), 0),
              dailyCount: todaySales.length,
              monthlyCount: monthSales.length,
              pendingOrders: pendingOrders.length,
            };
          } catch {
            return {
              id: store.id,
              name: store.name || 'Sin nombre',
              dailySales: 0,
              monthlySales: 0,
              dailyCount: 0,
              monthlyCount: 0,
              pendingOrders: 0,
            };
          }
        }),
      );

      setStores(results.sort((a, b) => b.monthlySales - a.monthlySales));
    } catch {
      setStores([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const totals = useMemo(
    () => ({
      dailySales: stores.reduce((s, st) => s + st.dailySales, 0),
      monthlySales: stores.reduce((s, st) => s + st.monthlySales, 0),
      dailyCount: stores.reduce((s, st) => s + st.dailyCount, 0),
      monthlyCount: stores.reduce((s, st) => s + st.monthlyCount, 0),
      pendingOrders: stores.reduce((s, st) => s + st.pendingOrders, 0),
    }),
    [stores],
  );

