  phone: '',
  address: '',
  email: ''
};

function QuantityPromptDialog({
  isOpen,
  onClose,
  product,
  onConfirm,
}: {
  isOpen: boolean;
  onClose: () => void;
  product: Product;
  onConfirm: (quantity: number) => void;
}) {
  const [quantity, setQuantity] = useState(1);

  const handleConfirm = () => {
    if (quantity > 0) {
      onConfirm(quantity);
      setQuantity(1);
    }
  };

  if (!isOpen) return null;

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Ingresar Cantidad</DialogTitle>
          <DialogDescription>
            ¿Cuántas unidades de &quot;{product.description}&quot; deseas agregar?
          </DialogDescription>
        </DialogHeader>
        <div className="py-4">
          <Label htmlFor="quantity">Cantidad</Label>
          <Input
            id="quantity"
            type="number"
            value={quantity}
            onChange={(e) => setQuantity(Number(e.target.value))}
            className="text-2xl h-14 text-center"
            autoFocus
            onKeyPress={(e) => e.key === 'Enter' && handleConfirm()}
          />
        </div>
        <DialogFooter>
          <Button variant="outline" onClick={onClose}>
            Cancelar
          </Button>
          <Button onClick={handleConfirm}>Agregar a la Venta</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}


export default function BillingPage() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [settings, setSettings] = useState<StoreSettings>({ applyVAT: false, billingMode: 'scan-and-add', exchangeRate: 36.6 });
  const [activeShift, setActiveShift] = useState<Shift | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedClient, setSelectedClient] = useState<Client>(genericClient);
  const [productForQuantityPrompt, setProductForQuantityPrompt] = useState<Product | null>(null);
  const [amountReceived, setAmountReceived] = useState<number | string>('');
  const [paymentCurrency, setPaymentCurrency] = useState<'NIO' | 'USD'>('NIO');
  const [isPaymentProcessing, setIsPaymentProcessing] = useState(false);
  const [isPaymentDialogOpen, setIsPaymentDialogOpen] = useState(false);
  const [saleToPrint, setSaleToPrint] = useState<any>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const ticketRef = useRef<any>(null);

  const params = useParams();
  const storeId = params.storeId as string;
  const { user, loading: authLoading } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!authLoading && !user) {
      navigate('/login');
    }
  }, [authLoading, user, navigate]);

  useEffect(() => {
    if (!storeId || !user?.id) return;

    const fetchSettings = async () => {
      try {
        const response = await apiClient.get(`/stores/${storeId}`);
        if (response.data && response.data.settings) {
          setSettings(response.data.settings as StoreSettings);
        }
      } catch (error) {
        console.error("Failed to fetch store settings:", error);
      }
    };
    fetchSettings();

    let intervalId: any;
    const fetchActiveShift = async () => {
      try {
        const response = await apiClient.get('/cash-shifts', {
          params: { storeId, cashierId: user.id, status: 'open' }
        });
        if (response.data && response.data.length > 0) {
          setActiveShift(response.data[0]);
        } else {
          setActiveShift(null);
        }
      } catch (error) {
         console.error("Error fetching shifts:", error);
         setActiveShift(null);
      } finally {
        setLoading(false);
      }
    }
    fetchActiveShift();
    intervalId = setInterval(fetchActiveShift, 30000);

    return () => clearInterval(intervalId);
  }, [storeId, user?.id]);


  const handleAddProduct = useCallback((product: Product, quantity: number = 1) => {
    setCart((prevCart) => {
      const existingItem = prevCart.find((item) => item.id === product.id);
      if (existingItem) {
        return prevCart.map((item) =>
          item.id === product.id
            ? { ...item, quantity: item.quantity + quantity }
            : item
        );
      }
      return [...prevCart, { ...product, quantity }];
    });
  }, []);

  const handleProductSelect = useCallback((product: Product) => {
    if (settings.billingMode === 'scan-and-prompt') {
      setProductForQuantityPrompt(product);
    } else {
      handleAddProduct(product, 1);
    }
  }, [settings.billingMode, handleAddProduct]);


  const handleQuantityChange = (productId: string, amount: number) => {
    setCart((prevCart) =>
      prevCart
        .map((item) =>
          item.id === productId
            ? { ...item, quantity: Math.max(0, item.quantity + amount) }
            : item
        )
        .filter((item) => item.quantity > 0)
    );
  };

  const subtotal = cart.reduce((acc, item) => acc + item.salePrice * item.quantity, 0);
  const tax = settings?.applyVAT ? subtotal * 0.15 : 0;
  const total = subtotal + tax;

  const handleDialogChange = (open: boolean) => {
    if (!open) {
      setAmountReceived('');
      setPaymentCurrency('NIO');
    }
    setIsPaymentDialogOpen(open);
  }

  const resetSale = () => {
    setCart([]);
    setSelectedClient(genericClient);
    setAmountReceived('');
    setPaymentCurrency('NIO');
    setIsPaymentDialogOpen(false);
  }

  const handleFinalizeSale = async (methodOrData: 'Efectivo' | 'Tarjeta' | PaymentData) => {
    if (!user || !activeShift) {
      toast.error('Error', 'No se pudo identificar al cajero o el turno de caja.');
      return;
    }

    let paymentMethod: 'Efectivo' | 'Tarjeta';
    let finalAmountReceived: number;
    let finalPaymentCurrency: 'NIO' | 'USD';
    let finalChange: number;

    if (typeof methodOrData === 'object' && 'method' in methodOrData) {
      paymentMethod = methodOrData.method as any;
      finalAmountReceived = methodOrData.amountReceived;
      finalPaymentCurrency = methodOrData.paymentCurrency as any;
      finalChange = methodOrData.change;
    } else {
      paymentMethod = methodOrData as 'Efectivo' | 'Tarjeta';
      finalAmountReceived = Number(amountReceived);
      finalPaymentCurrency = paymentCurrency;
      finalChange = change;
    }

    setIsPaymentProcessing(true);
    try {
      const salePayload = {
        storeId,
        shiftId: activeShift.id,
        cashierId: user.id,
        cashierName: user.name,
        clientId: selectedClient.id,
        clientName: selectedClient.name,
        items: cart.map(({ id, description, quantity, salePrice, costPrice, usesInventory, currentStock }) => ({ 
           id, description, quantity, salePrice, costPrice: costPrice || 0, usesInventory, currentStock 
        })),
        paymentMethod,
        paymentCurrency: finalPaymentCurrency,
        amountReceived: finalAmountReceived,
        change: finalChange,
      };

      const response = await apiClient.post('/sales/process', salePayload);
      const saleToPrintData = response.data;

      setSaleToPrint(saleToPrintData);

      toast.success('Venta Completada', 'La venta ha sido registrada exitosamente.');
      resetSale();
    } catch (error) {
      logError(error, {
        location: 'billing-page-finalize-sale',
        additionalInfo: { storeId, cartSize: cart.length }
      });
      toast.error('Error al Guardar', 'No se pudo registrar la venta. Inténtalo de nuevo.');
    } finally {
      setIsPaymentProcessing(false);
    }
  };

  const change = useMemo(() => {
    const received = Number(amountReceived);
    if (isNaN(received) || received <= 0) return 0;

    let receivedInNIO = received;
    if (paymentCurrency === 'USD') {
      receivedInNIO = received * (settings.exchangeRate || 36.6);
    }

    if (receivedInNIO < total) {
      return 0;
    }
    return receivedInNIO - total;
  }, [amountReceived, total, paymentCurrency, settings.exchangeRate]);


  if (loading || authLoading) {
    return (
      <div className="flex items-center justify-center h-full">
        <Loader2 className="animate-spin h-8 w-8 text-primary" />
      </div>
    );
  }

  if (!user) return null;

  if (!activeShift) {
    return (
      <div className="flex items-center justify-center h-full p-4">
        <Card className="max-w-md w-full">
          <CardHeader className="text-center">
            <CardTitle className="text-xl font-bold text-red-600">Caja cerrada</CardTitle>
            <CardDescription>
              Abre caja antes de facturar.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button asChild className="w-full h-12" variant="default">
              <Link to={`/store/${storeId}/cash-register`}>
                Abrir Caja
              </Link>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Check for Cashier role to render specific layout
  // Check for Cashier role to render specific layout
  if (user?.role === 'Cashier' || user?.role === 'Cajero' || user?.role === 'store-admin') {
    return (
      <>
        <CashierBillingView
          cart={cart}
          subtotal={subtotal}
          tax={tax}
          total={total}
          onAddProduct={handleAddProduct}
          onRemoveProduct={(productId) => {
            const item = cart.find(i => i.id === productId);
            if (item) handleQuantityChange(productId, -item.quantity);
          }}
          onUpdateQuantity={handleQuantityChange}
          client={selectedClient}
          onSelectClient={setSelectedClient}
          onFinalize={handleFinalizeSale}
          activeShift={activeShift}
          onClearCart={() => setCart([])}
          onSetCart={(newCart) => setCart(newCart as any)}
          lastSale={saleToPrint}
        />
        <div className="fixed top-0 left-0 -z-50 opacity-0 pointer-events-none">
          <PrintableSaleTicket ref={ticketRef} storeId={storeId} sale={saleToPrint} />
        </div>
      </>
    );
  }

  // The rest of the return would follow, but we are standardizing on CashierBillingView for better UX
  return null;
}

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { 
  Banknote, 
  DoorOpen, 
  Lock, 
  FileText, 
  Wallet, 
  ChevronRight, 
  CheckCircle2,
  AlertCircle,
  ShoppingCart,
  Printer
} from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { 
    Dialog, 
    DialogContent, 
    DialogHeader, 
} from '@/components/ui/dialog';
import { Skeleton } from '@/components/ui/skeleton';
import { useAuth } from '@/contexts/auth-context';
import apiClient from '@/services/api-client';
import { toast } from '@/lib/swalert';
import { format, parseISO } from 'date-fns';
import { es } from 'date-fns/locale';
import { cn } from '@/lib/utils';

interface CashShift {
  id: string;
  status: 'OPEN' | 'CLOSED';
  openedAt: string;
  closedAt?: string;
  startingCash: number;
  actualCash: number;
}

export default function CashRegisterPage() {
  const { storeId } = useParams();
  const { user } = useAuth();
  const [activeShift, setActiveShift] = useState<CashShift | null>(null);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ cashSales: 0, cardSales: 0, totalSales: 0 });
  const [isOpeningShift, setIsOpeningShift] = useState(false);
  const [isClosingShift, setIsClosingShift] = useState(false);
  const [startingCash, setStartingCash] = useState('0');
  const [actualCashInput, setActualCashInput] = useState('0');

  useEffect(() => {
    fetchActiveShift();
  }, [storeId]);

  const fetchActiveShift = async () => {
    if (!storeId) return;
    setLoading(true);
    try {
      const response = await apiClient.get(`/cash-shifts/active?storeId=${storeId}`);
      setActiveShift(response.data);
      if (response.data) {
        fetchShiftStats(response.data.id);
      }
    } catch (error) {
      console.error('Error fetching shift:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchShiftStats = async (shiftId: string) => {
    try {
      const response = await apiClient.get(`/cash-shifts/stats/${shiftId}`);
      setStats(response.data);
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleOpenShift = async () => {
    if (!user || !storeId) return;
    try {
      const response = await apiClient.post('/cash-shifts', {
        storeId,
        userId: user.id,
        startingCash: parseFloat(startingCash)
      });
      setActiveShift(response.data);
      setIsOpeningShift(false);
      toast.success('Caja Abierta', 'Turno de caja iniciado correctamente.');
    } catch (error) {
      toast.error('Error', 'No se pudo abrir el turno de caja.');
    }
  };

  const handleCloseShift = async () => {
    if (!activeShift || !storeId || !user) return;
    const expectedCash = activeShift.startingCash + stats.cashSales;
    const actualCash = parseFloat(actualCashInput);
    const difference = actualCash - expectedCash;

    try {
      await apiClient.post('/cash-shifts/close', {
        shiftId: activeShift.id,
        storeId,
        expectedCash,
        actualCash,
        difference,
        userId: user.id
      });
      toast.success('Caja Cerrada', 'Turno finalizado y reporte generado.');
      setActiveShift(null);
      setIsClosingShift(false);
    } catch (error) {
      toast.error('Error', 'No se pudo cerrar el turno de caja.');
    }
  };

  if (loading) {
    return (
      <div className="p-6 space-y-6">
        <Skeleton className="h-20 w-1/3 rounded-2xl" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {[1,2,3,4].map(i => <Skeleton key={i} className="h-32 rounded-[24px]" />)}
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-8 max-w-6xl mx-auto">
      <div className="flex flex-col gap-2 items-center text-center">
        <h1 className="text-4xl font-black tracking-tight text-slate-800 flex items-center gap-3">
          <Banknote className="h-10 w-10 text-primary" />
          Control de Caja
        </h1>
        <p className="text-slate-500 font-bold uppercase tracking-[0.3em] text-xs underline decoration-primary decoration-4 underline-offset-8">Operaciones de Ventas</p>
      </div>

      {!activeShift ? (
        <div className="py-20 flex flex-col items-center justify-center">
           <Card className="max-w-md w-full border-none shadow-[30px_30px_60px_#ccced1,-30px_-30px_60px_#ffffff] bg-[#f0f2f5] rounded-[40px] overflow-hidden group">
              <div className="h-3 bg-red-400"></div>
              <CardContent className="p-10 flex flex-col items-center text-center space-y-6">
                 <div className="w-24 h-24 bg-red-50 rounded-[32px] flex items-center justify-center text-red-500 shadow-sm mb-4">
                    <Lock className="h-12 w-12" />
                 </div>
                 <h2 className="text-2xl font-black text-slate-800 uppercase leading-none">Caja Inactiva</h2>
                 <p className="text-slate-500 font-medium">No hay un turno de caja abierto para tu usuario en esta tienda.</p>
                 <Button 
                  onClick={() => setIsOpeningShift(true)}
                  className="w-full h-16 rounded-[24px] text-lg font-black tracking-widest shadow-xl shadow-primary/20 hover:scale-[1.02] transition-all bg-primary uppercase"
                 >
                    <DoorOpen className="mr-3 h-6 w-6" />
                    Abrir Caja Ahora
                 </Button>
              </CardContent>
           </Card>
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in duration-700">
           {/* Resumen Superior */}
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              <Card className="border-none shadow-[20px_20px_40px_#ccced1,-20px_-20px_40px_#ffffff] bg-[#f0f2f5] rounded-[32px] p-6 group hover:translate-y-[-4px] transition-all">
                 <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 rounded-2xl bg-blue-50 flex items-center justify-center text-blue-500 shadow-sm">
                       <CheckCircle2 className="h-6 w-6" />
                    </div>
                    <div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Turno Abierto</p>
                       <p className="font-bold text-slate-800">{format(parseISO(activeShift.openedAt), 'Pp', { locale: es })}</p>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <p className="text-xs font-bold text-slate-400 uppercase">Fondo Inicial</p>
                    <p className="text-2xl font-black text-slate-900 font-mono italic">C$ {activeShift.startingCash.toFixed(2)}</p>
                 </div>
              </Card>

              <Card className="border-none shadow-[20px_20px_40px_#ccced1,-20px_-20px_40px_#ffffff] bg-[#f0f2f5] rounded-[32px] p-6 group hover:translate-y-[-4px] transition-all">
                 <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 rounded-2xl bg-green-50 flex items-center justify-center text-green-500 shadow-sm">
                       <ShoppingCart className="h-6 w-6" />
                    </div>
                    <div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ventas Efectivo</p>
                       <p className="font-bold text-slate-800">Total Acumulado</p>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <p className="text-xs font-bold text-slate-400 uppercase">Neto Caja</p>
                    <p className="text-2xl font-black text-green-600 font-mono italic">C$ {stats.cashSales.toFixed(2)}</p>
                 </div>
              </Card>

              <Card className="border-none shadow-[20px_20px_40px_#ccced1,-20px_-20px_40px_#ffffff] bg-[#f0f2f5] rounded-[32px] p-6 group hover:translate-y-[-4px] transition-all border-l-8 border-primary">
                 <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary shadow-sm">
                       <Wallet className="h-6 w-6" />
                    </div>
                    <div>
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Efectivo Estimado</p>
                       <p className="font-bold text-slate-800">Fondo + Ventas</p>
                    </div>
                 </div>
                 <div className="space-y-1">
                    <p className="text-xs font-bold text-slate-400 uppercase">Monto en Gaveta</p>
                    <p className="text-3xl font-black text-primary font-mono italic tracking-tighter">C$ {(activeShift.startingCash + stats.cashSales).toFixed(2)}</p>
                 </div>
              </Card>
           </div>

           {/* Acciones de Operación */}
           <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <Card className="border-none shadow-[20px_20px_60px_#ccced1,-20px_-20px_60px_#ffffff] bg-[#f0f2f5] rounded-[32px] overflow-hidden">
                 <CardHeader className="bg-slate-800 py-6">
                    <CardTitle className="text-white text-lg font-black uppercase flex items-center gap-2 tracking-widest">
                       <FileText className="h-5 w-5" />
                       Reportes Rápidos
                    </CardTitle>
                 </CardHeader>
                 <CardContent className="p-8 space-y-4">
                    <Button variant="outline" className="w-full h-14 rounded-2xl font-bold justify-between px-6 border-slate-200">
                       <div className="flex items-center gap-3">
                          <Printer className="h-5 w-5 text-slate-400" />
                          <span>IMPRIMIR CORTE X (LECTURA)</span>
                       </div>
                       <ChevronRight className="h-4 w-4" />
                    </Button>
                    <Button variant="outline" className="w-full h-14 rounded-2xl font-bold justify-between px-6 border-slate-200">
                       <div className="flex items-center gap-3">
                          <FileText className="h-5 w-5 text-slate-400" />
                          <span>ÚLTIMAS 50 VENTAS</span>
                       </div>
                       <ChevronRight className="h-4 w-4" />
                    </Button>
                 </CardContent>
              </Card>

              <Card className="border-none shadow-[20px_20px_60px_#ccced1,-20px_-20px_60px_#ffffff] bg-[#f0f2f5] rounded-[32px] overflow-hidden">
                 <CardHeader className="bg-red-500 py-6">
                    <CardTitle className="text-white text-lg font-black uppercase flex items-center gap-2 tracking-widest">
                       <Lock className="h-5 w-5" />
                       Cierre de Operaciones
                    </CardTitle>
                 </CardHeader>
                 <CardContent className="p-8">
                    <div className="flex flex-col items-center text-center space-y-6">
                       <p className="text-slate-500 font-medium italic">Al cerrar la caja se emitirá el Reporte Z y se bloqueará la terminal para nuevas ventas hasta el siguiente turno.</p>
                       <Button 
                        onClick={() => {
                            setActualCashInput((activeShift.startingCash + stats.cashSales).toString());
                            setIsClosingShift(true);
                        }}
                        className="w-full h-16 rounded-[24px] text-lg font-black tracking-widest bg-red-600 hover:bg-red-700 shadow-xl shadow-red-100 uppercase"
                       >
                          Finalizar Turno Actual
                       </Button>
                    </div>
                 </CardContent>
              </Card>
           </div>
        </div>
      )}

      {/* DIALOGS */}
      
      {/* Apertura de Caja */}
      <Dialog open={isOpeningShift} onOpenChange={setIsOpeningShift}>
         <DialogContent className="rounded-[40px] border-none shadow-2xl p-0 overflow-hidden max-w-md">
            <div className="bg-primary p-8 text-white">
                <h2 className="text-2xl font-black uppercase tracking-tight flex items-center gap-3 text-white">
                    <DoorOpen className="h-7 w-7 text-white" />
                    Apertura de Turno
                </h2>
                <p className="text-primary-foreground/80 font-medium mt-1">Ingresa el dinero inicial en gaveta.</p>
            </div>
            <div className="p-8 space-y-6">
                <div className="space-y-3">
                    <Label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Fondo de Caja (NIO)</Label>
                    <div className="relative">
                        <span className="absolute left-6 top-1/2 -translate-y-1/2 text-2xl font-black text-slate-300">C$</span>
                        <Input 
                            type="number"
                            className="h-20 pl-16 rounded-[24px] text-3xl font-black bg-[#f0f2f5] border-none shadow-[inset_4px_4px_8px_#ccced1,inset_-4px_-4px_8px_#ffffff] transition-all font-mono"
                            value={startingCash}
                            onChange={(e) => setStartingCash(e.target.value)}
                        />
                    </div>
                </div>
                <Button 
                    onClick={handleOpenShift}
                    className="w-full h-16 rounded-[24px] text-lg font-black tracking-widest bg-primary shadow-lg shadow-primary/20 uppercase"
                >
                    Confirmar Apertura
                </Button>
            </div>
         </DialogContent>
      </Dialog>

      {/* Cierre de Caja (Cuadre) */}
      <Dialog open={isClosingShift} onOpenChange={setIsClosingShift}>
         <DialogContent className="rounded-[40px] border-none shadow-2xl p-0 overflow-hidden max-w-lg">
            <div className="bg-red-500 p-8 text-white">
                <h2 className="text-2xl font-black uppercase tracking-tight flex items-center gap-3 text-white">
                    <Lock className="h-7 w-7 text-white" />
                    Cuadre y Cierre
                </h2>
                <p className="text-white/80 font-medium mt-1 italic">Verifica el efectivo físico contra el sistema.</p>
            </div>
            <div className="p-8 space-y-8">
                <div className="grid grid-cols-2 gap-6">
                    <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Monto Esperado</p>
                        <p className="text-xl font-black text-slate-800 font-mono">C$ {(activeShift?.startingCash! + stats.cashSales).toFixed(2)}</p>
                    </div>
                   <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                        <p className="text-[10px] font-bold text-slate-400 uppercase">Ventas Tarjeta</p>
                        <p className="text-xl font-black text-blue-600 font-mono">C$ {stats.cardSales.toFixed(2)}</p>
                    </div>
                </div>

                <div className="space-y-3">
                    <Label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Efectivo Físico en Gaveta</Label>
                    <Input 
                        type="number"
                        className="h-20 rounded-[24px] text-3xl font-black bg-[#f0f2f5] border-none shadow-[inset_4px_4px_8px_#ccced1,inset_-4px_-4px_8px_#ffffff] transition-all font-mono text-center"
                        value={actualCashInput}
                        onChange={(e) => setActualCashInput(e.target.value)}
                    />
                </div>

                {activeShift && (parseFloat(actualCashInput) - (activeShift.startingCash + stats.cashSales)) !== 0 && (
                    <div className={cn(
                        "p-4 rounded-2xl flex items-center gap-3 font-bold",
                        (parseFloat(actualCashInput) - (activeShift.startingCash + stats.cashSales)) < 0 
                            ? "bg-red-50 text-red-600 border border-red-100" 
                            : "bg-amber-50 text-amber-600 border border-amber-100"
                    )}>
                        <AlertCircle className="h-5 w-5" />
                        <span>Diferencia: C$ {(parseFloat(actualCashInput) - (activeShift.startingCash + stats.cashSales)).toFixed(2)}</span>
                    </div>
                )}

                <Button 
                    onClick={handleCloseShift}
                    className="w-full h-16 rounded-[24px] text-lg font-black tracking-widest bg-red-600 hover:bg-red-700 shadow-lg shadow-red-100 uppercase"
                >
                    Finalizar y Generar Z
                </Button>
            </div>
         </DialogContent>
      </Dialog>
    </div>
  );
}

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { ClipboardCheck, Hourglass, Map } from 'lucide-react';
import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/contexts/auth-context';
import apiClient from '@/services/api-client';

interface DeliveryItem { id: string; description: string; quantity: number; salePrice: number; }
interface PendingDelivery { id: string; clientName: string; clientAddress?: string; salesManagerName: string; items: DeliveryItem[]; total: number; paymentType: string; status: string; createdAt: string; }

export default function DeliveryRoutePage() {
    const { storeId } = useParams<{ storeId: string }>();
    const { toast } = useToast();
    const { user } = useAuth();

    const [deliveries, setDeliveries] = useState<PendingDelivery[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchDeliveries = async () => {
        if (!storeId || !user?.id) return;
        try {
            const res = await apiClient.get('/pending-deliveries', { params: { storeId, status: 'Pendiente', ruteroId: user.id } });
            setDeliveries(res.data || []);
        } catch (err) {
            console.error('Error fetching deliveries:', err);
            setError('No se pudieron cargar los pedidos pendientes de entrega.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchDeliveries();
        const interval = setInterval(fetchDeliveries, 30000);
        return () => clearInterval(interval);
    }, [storeId, user]);

    const handleUpdateStatus = async (deliveryId: string, newStatus: 'Entregado' | 'No Entregado') => {
        try {
            await apiClient.patch(`/pending-deliveries/${deliveryId}`, { status: newStatus });
            toast({ title: 'Estado Actualizado', description: `El pedido ha sido marcado como "${newStatus}".` });
            fetchDeliveries();
        } catch (err) {
            console.error(err);
            toast({ variant: 'destructive', title: 'Error', description: 'No se pudo actualizar el estado del pedido.' });
        }
    };

    const isCoordinates = (address: string) => /^-?\d+(\.\d+)?,\s*-?\d+(\.\d+)?$/.test(address);

    const renderContent = () => {
        if (loading) return (<div className="space-y-2">{Array.from({ length: 3 }).map((_, i) => (<Skeleton key={i} className="h-20 w-full" />))}</div>);
        if (error) return (<Alert variant="destructive"><Hourglass className="h-4 w-4" /><AlertTitle>Error</AlertTitle><AlertDescription>{error}</AlertDescription></Alert>);
        if (deliveries.length === 0) return (<Alert><ClipboardCheck className="h-4 w-4" /><AlertTitle>No hay entregas asignadas</AlertTitle><AlertDescription>Por el momento no tienes pedidos en tu ruta.</AlertDescription></Alert>);
        return (
            <Accordion type="single" collapsible className="w-full">
                {deliveries.map((delivery) => (
                    <AccordionItem value={delivery.id} key={delivery.id}>
                        <AccordionTrigger className="hover:no-underline">
                            <div className="flex items-center justify-between w-full text-left">
                                <div className="flex-grow"><p className="font-medium text-primary">{delivery.clientName}</p><p className="text-xs text-muted-foreground">Pedido por {delivery.salesManagerName} - {delivery.createdAt ? format(new Date(delivery.createdAt), 'PPP', { locale: es }) : ''}</p></div>
                                <div className="font-semibold text-lg pr-4">C$ {delivery.total.toFixed(2)}</div>
                            </div>
                        </AccordionTrigger>
                        <AccordionContent className="bg-muted/30 p-4 rounded-md">
                            {delivery.clientAddress && (
                                <div className="flex items-center gap-2 mb-2"><strong>Dirección:</strong>
                                    {isCoordinates(delivery.clientAddress) ? (
                                        <a href={`https://www.google.com/maps/search/?api=1&query=${delivery.clientAddress}`} target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-blue-600 hover:underline"><Map className="h-4 w-4" /> Ver en mapa</a>
                                    ) : (<span className="text-sm">{delivery.clientAddress}</span>)}
                                </div>
                            )}
                            <p className="text-sm mb-2"><strong>Tipo de Pago:</strong> {delivery.paymentType}</p>
                            <h4 className="font-semibold mb-2">Productos:</h4>
                            <ul className="list-disc pl-5 space-y-1 text-sm">{delivery.items?.map(item => (<li key={item.id}>({item.quantity}) {item.description}</li>))}</ul>
                            <div className="mt-4 flex gap-2">
                                <Button onClick={() => handleUpdateStatus(delivery.id, 'Entregado')}>Marcar como Entregado</Button>
                                <Button variant="destructive" onClick={() => handleUpdateStatus(delivery.id, 'No Entregado')}>No Entregado</Button>
                            </div>
                        </AccordionContent>
                    </AccordionItem>
                ))}
            </Accordion>
        );
    };

    return (
        <div>
            <div className="mb-6"><h1 className="text-2xl font-bold tracking-tight">Mi Ruta de Entrega</h1><p className="text-muted-foreground">Aquí se muestran los pedidos que te fueron asignados.</p></div>
            <Card><CardHeader><CardTitle>Mis Pedidos Pendientes</CardTitle><CardDescription>Selecciona un pedido para ver los detalles y actualizar su estado.</CardDescription></CardHeader><CardContent>{renderContent()}</CardContent></Card>
        </div>
    );
}

