const dateOnlyFormatter = new Intl.DateTimeFormat('es-NI', { dateStyle: 'medium' });

function formatDate(value?: string) {
  if (!value) return 'Sin fecha';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return 'Fecha inválida';
  return dateOnlyFormatter.format(parsed);
}

function getStatusVariant(status?: string): 'default' | 'secondary' | 'destructive' | 'outline' {
  switch (status) {
    case 'PAID': return 'default';
    case 'PARTIAL': return 'secondary';
    case 'PENDING': return 'outline';
    default: return 'outline';
  }
}

export default function PayablesPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { user } = useAuth();
  const { lastEvent } = useRealTimeEvents(storeId);

  const [accounts, setAccounts] = useState<AccountPayable[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  // Payment Dialog State
  const [selectedAccount, setSelectedAccount] = useState<AccountPayable | null>(null);
  const [paymentAmount, setPaymentAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('CASH');
  const [paymentNotes, setPaymentNotes] = useState('');
  const [processingPayment, setProcessingPayment] = useState(false);

  const loadData = async (silent = false) => {
    if (!storeId) return;
    if (silent) setRefreshing(true);
    else setLoading(true);

    try {
      const data = await financeService.listPayables(storeId, { pending: true });
      setAccounts(data);
    } catch (error) {
      console.error(error);
      toast.error('Error', 'No se pudieron cargar las cuentas por pagar.');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => { loadData(); }, [storeId]);
  useEffect(() => { if (lastEvent && lastEvent.type !== 'PING') loadData(); }, [lastEvent]);

  const pendingTotal = useMemo(() => accounts.reduce((acc, a) => acc + Number(a.remainingAmount || 0), 0), [accounts]);
  const partialCount = useMemo(() => accounts.filter(a => a.status === 'PARTIAL').length, [accounts]);

  const openPaymentDialog = (account: AccountPayable) => {
    setSelectedAccount(account);
    setPaymentAmount(String(account.remainingAmount || 0));
    setPaymentMethod('CASH');
    setPaymentNotes('');
  };

  const resetPaymentDialog = () => {
    setSelectedAccount(null);
    setPaymentAmount('');
    setPaymentMethod('CASH');
    setPaymentNotes('');
  };

  const submitPayment = async () => {
    if (!selectedAccount) return;
    const amount = Number(paymentAmount);
    const remaining = Number(selectedAccount.remainingAmount || 0);

    if (!Number.isFinite(amount) || amount <= 0) {
      toast.error('Monto inválido', 'El pago debe ser mayor a cero.');
      return;
    }
    if (amount > remaining) {
      toast.error('Monto inválido', 'El pago no puede superar el saldo pendiente.');
      return;
    }

    setProcessingPayment(true);
    try {
      await financeService.registerPayablePayment(selectedAccount.id, {
        amount,
        paymentMethod,
        notes: paymentNotes || undefined,
        paidBy: user?.name,
      });
      toast.success('Pago registrado', `Se abonaron ${formatCurrency(amount)} a ${selectedAccount.supplierName}.`);
      resetPaymentDialog();
      await loadData(true);
    } catch (error: any) {
      console.error(error);
      toast.error('Error al registrar pago', error?.response?.data?.message || 'No se pudo procesar el abono.');
    } finally {
      setProcessingPayment(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Cuentas por Pagar</h1>
          <p className="text-muted-foreground">Control de saldos pendientes, deudas a proveedores y abonos registrados.</p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline" onClick={() => loadData(true)} disabled={refreshing}>
            {refreshing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <RefreshCw className="mr-2 h-4 w-4" />}
            Actualizar
          </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-l-4 border-l-rose-500">
          <CardHeader className="pb-2">
            <CardDescription>Deuda Total</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(pendingTotal)}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            {accounts.length} facturas pendientes de pago.
          </CardContent>
        </Card>
        <Card className="border-l-4 border-l-amber-500">
          <CardHeader className="pb-2">
            <CardDescription>En Gestión Parcial</CardDescription>
            <CardTitle className="text-2xl">{partialCount}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            Cuentas con abonos previos pero aún no canceladas.
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Briefcase className="h-5 w-5 text-rose-500" />
            Cartera de Proveedores
          </CardTitle>
          <CardDescription>Facturas pendientes e historial de deuda activa.</CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex justify-center py-12"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>
          ) : accounts.length === 0 ? (
            <Alert>
              <Wallet className="h-4 w-4" />
              <AlertTitle>Libre de deuda</AlertTitle>
              <AlertDescription>No hay cuentas por pagar activas en tienda en este momento.</AlertDescription>
            </Alert>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Proveedor</TableHead>
                    <TableHead>Factura / Detalle</TableHead>
                    <TableHead>Emisión</TableHead>
                    <TableHead>Vencimiento</TableHead>
                    <TableHead>Estado</TableHead>
                    <TableHead className="text-right">Total Acordado</TableHead>
                    <TableHead className="text-right text-rose-600 font-bold">Saldo Pendiente</TableHead>
                    <TableHead className="text-right">Acción</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {accounts.map((acc) => (
                    <TableRow key={acc.id}>
                      <TableCell className="font-medium">{acc.supplierName || 'Desconocido'}</TableCell>
                      <TableCell className="max-w-[200px] text-sm text-muted-foreground">
                        {acc.invoiceId ? <Badge variant="outline" className="mb-1">{acc.invoiceId}</Badge> : null}
                        <div className="line-clamp-2">{acc.description || 'Sin descripción'}</div>
                      </TableCell>
                      <TableCell>{formatDate(acc.createdAt)}</TableCell>
                      <TableCell className={acc.dueDate && new Date(acc.dueDate) < new Date() ? 'text-rose-600 font-medium' : ''}>
                        {formatDate(acc.dueDate)}
                      </TableCell>
                      <TableCell><Badge variant={getStatusVariant(acc.status)}>{acc.status}</Badge></TableCell>
                      <TableCell className="text-right">{formatCurrency(acc.totalAmount)}</TableCell>
                      <TableCell className="text-right font-bold text-rose-600">{formatCurrency(acc.remainingAmount)}</TableCell>
                      <TableCell className="text-right">
                        <Button size="sm" variant="outline" onClick={() => openPaymentDialog(acc)}>
                          Abonar
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={Boolean(selectedAccount)} onOpenChange={(open) => !open && resetPaymentDialog()}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Registrar Pago a Proveedor</DialogTitle>
            <DialogDescription>
              {selectedAccount ? `Saldo pendiente de ${selectedAccount.supplierName}: ${formatCurrency(selectedAccount.remainingAmount)}.` : ''}
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-2">
            <div className="grid gap-2">
              <Label htmlFor="payAmount">Monto a cancelar</Label>
              <Input
                id="payAmount"
                type="number"
                min="0"
                step="0.01"
                value={paymentAmount}
                onChange={(e) => setPaymentAmount(e.target.value)}
              />
            </div>
            <div className="grid gap-2">
              <Label>Origen del dinero</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                <SelectTrigger><SelectValue placeholder="Selecciona" /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="CASH">Caja / Efectivo</SelectItem>
                  <SelectItem value="TRANSFER">Transferencia / Banco</SelectItem>
                  <SelectItem value="CHEQUE">Cheque</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="grid gap-2">
              <Label htmlFor="payNotes">Referencia / Comentarios</Label>
              <Textarea
                id="payNotes"
                placeholder="Número de cheque o transferencia, recibo, etc."
                value={paymentNotes}
                onChange={(e) => setPaymentNotes(e.target.value)}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="ghost" onClick={resetPaymentDialog}>Cancelar</Button>
            <Button onClick={submitPayment} disabled={processingPayment}>
              {processingPayment ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Wallet className="mr-2 h-4 w-4" />}
              Registrar Egreso
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import { CalendarDays, CreditCard, Download, HandCoins, Loader2, RefreshCw, Wallet } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Textarea } from '@/components/ui/textarea';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { useAuth } from '@/contexts/auth-context';
import { formatCurrency } from '@/lib/utils';
import { toast } from '@/lib/swalert';
import financeService, {
  type AccountReceivable,
  type CollectionRecord,
  type CollectionSummary,
} from '@/services/finance-service';
import { useRealTimeEvents } from '@/hooks/use-real-time-events';
import { exportToExcel } from '@/lib/export-excel';

const dateOnlyFormatter = new Intl.DateTimeFormat('es-NI', {
  dateStyle: 'medium',
});

const dateTimeFormatter = new Intl.DateTimeFormat('es-NI', {
  dateStyle: 'medium',
  timeStyle: 'short',
});

function formatDateInput(date = new Date()) {
  return date.toISOString().slice(0, 10);
}

function formatDate(value?: string, withTime = false) {
  if (!value) return 'Sin fecha';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return 'Fecha inválida';
  return withTime ? dateTimeFormatter.format(parsed) : dateOnlyFormatter.format(parsed);
}

function getStatusVariant(status?: string): 'default' | 'secondary' | 'destructive' | 'outline' {
  switch (status) {
    case 'PAID':
      return 'default';
    case 'PARTIAL':
      return 'secondary';
    case 'PENDING':
      return 'outline';
    default:
      return 'outline';
  }
}

export default function ReceivablesPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { user } = useAuth();
  const { lastEvent } = useRealTimeEvents(storeId);

  const [accounts, setAccounts] = useState<AccountReceivable[]>([]);
  const [collections, setCollections] = useState<CollectionRecord[]>([]);
  const [summary, setSummary] = useState<CollectionSummary>({
    totalCount: 0,
    totalAmount: 0,
    cashTotal: 0,
    otherTotal: 0,
  });
  const [selectedDate, setSelectedDate] = useState<string>(formatDateInput());
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedAccount, setSelectedAccount] = useState<AccountReceivable | null>(null);
  const [paymentAmount, setPaymentAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('CASH');
  const [paymentNotes, setPaymentNotes] = useState('');
  const [processingPayment, setProcessingPayment] = useState(false);

  const loadData = async (silent = false) => {
    if (!storeId) return;
    if (silent) {
      setRefreshing(true);
    } else {
      setLoading(true);
    }

    try {
      const [accountsData, collectionsData, summaryData] = await Promise.all([
        financeService.listReceivables(storeId, true),
        financeService.listCollections(storeId, { date: selectedDate }),
        financeService.getCollectionsSummary(storeId, { date: selectedDate }),
      ]);
      setAccounts(accountsData);
      setCollections(collectionsData);
      setSummary(summaryData);
    } catch (error) {
      console.error(error);
      toast.error('Error', 'No se pudo cargar la cartera ni el historial de cobros.');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [storeId, selectedDate]);

  useEffect(() => {
    if (lastEvent && lastEvent.type !== 'PING') {
      loadData();
    }
  }, [lastEvent]);

  const pendingTotal = useMemo(
    () => accounts.reduce((acc, account) => acc + Number(account.pendingAmount || account.remainingAmount || 0), 0),
    [accounts],
  );

  const partialCount = useMemo(
    () => accounts.filter((account) => account.status === 'PARTIAL').length,
    [accounts],
  );

  const openPaymentDialog = (account: AccountReceivable) => {
    setSelectedAccount(account);
    setPaymentAmount(String(account.pendingAmount || account.remainingAmount || 0));
    setPaymentMethod('CASH');
    setPaymentNotes('');
  };

  const resetPaymentDialog = () => {
    setSelectedAccount(null);
    setPaymentAmount('');
    setPaymentMethod('CASH');
    setPaymentNotes('');
  };

  const submitPayment = async () => {
    if (!selectedAccount) return;

    const amount = Number(paymentAmount);
    const remaining = Number(selectedAccount.pendingAmount || selectedAccount.remainingAmount || 0);

    if (!Number.isFinite(amount) || amount <= 0) {
      toast.error('Monto inválido', 'El pago debe ser mayor a cero.');
      return;
    }

    if (amount > remaining) {
      toast.error('Monto inválido', 'El pago no puede superar el saldo pendiente.');
      return;
    }

    setProcessingPayment(true);
    try {
      await financeService.registerReceivablePayment(selectedAccount.id, {
        amount,
        paymentMethod,
        notes: paymentNotes || undefined,
        vendorId: user?.id,
        vendorName: user?.name,
      });
      toast.success('Cobro registrado', `Se abonaron ${formatCurrency(amount)} a ${selectedAccount.clientName}.`);
      resetPaymentDialog();
      await loadData(true);
    } catch (error: any) {
      console.error(error);
      toast.error('Error al registrar pago', error?.response?.data?.message || 'No se pudo registrar el cobro.');
    } finally {
      setProcessingPayment(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 md:flex-row md:items-start md:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Cobranza y cartera</h1>
          <p className="text-muted-foreground">
            Controla saldos pendientes, cobros del día y el ritmo real de recuperación.
          </p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Input
            type="date"
            value={selectedDate}
            onChange={(event) => setSelectedDate(event.target.value)}
            className="w-[180px]"
          />
          <Button variant="outline" onClick={() => loadData(true)} disabled={refreshing}>
            {refreshing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <RefreshCw className="mr-2 h-4 w-4" />}
            Actualizar
          </Button>
          <Button
            variant="outline"
            disabled={accounts.length === 0}
            onClick={() => {
              const rows = accounts.map(a => ({
                'Cliente': a.clientName || 'Sin nombre',
                'Pedido': a.orderId || 'N/A',
                'Descripción': a.description || '',
                'Creada': formatDate(a.createdAt),
                'Estado': a.status,
                'Saldo Pendiente': Number(a.pendingAmount || a.remainingAmount || 0).toFixed(2),
              }));
              exportToExcel(rows, `Cartera_${selectedDate}`, 'Cartera');
            }}
          >
            <Download className="mr-2 h-4 w-4" />
            Exportar
          </Button>
        </div>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
        <Card className="border-l-4 border-l-amber-500">
          <CardHeader className="pb-2">
            <CardDescription>Saldo pendiente</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(pendingTotal)}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            {accounts.length} cuentas activas por cobrar en tienda.
          </CardContent>
        </Card>
        <Card className="border-l-4 border-l-sky-500">
          <CardHeader className="pb-2">
            <CardDescription>Cobrado en fecha</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(summary.totalAmount)}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            {summary.totalCount} cobros registrados para {formatDate(selectedDate)}.
          </CardContent>
        </Card>
        <Card className="border-l-4 border-l-emerald-500">
          <CardHeader className="pb-2">
            <CardDescription>Efectivo</CardDescription>
            <CardTitle className="text-2xl">{formatCurrency(summary.cashTotal)}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            Recuperación inmediata en caja o ruta.
          </CardContent>
        </Card>
        <Card className="border-l-4 border-l-violet-500">
          <CardHeader className="pb-2">
            <CardDescription>Gestión parcial</CardDescription>
            <CardTitle className="text-2xl">{partialCount}</CardTitle>
          </CardHeader>
          <CardContent className="text-sm text-muted-foreground">
            Clientes con saldo parcialmente abonado.
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="accounts" className="space-y-4">
        <TabsList className="grid w-full max-w-md grid-cols-2">
          <TabsTrigger value="accounts">Cartera</TabsTrigger>
          <TabsTrigger value="collections">Cobros</TabsTrigger>
        </TabsList>

        <TabsContent value="accounts">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Wallet className="h-5 w-5 text-amber-500" />
                Cuentas por cobrar
              </CardTitle>
              <CardDescription>
                Lista operativa para registrar abonos y seguir saldos pendientes por cliente.
              </CardDescription>
            </CardHeader>
            <CardContent>
              {loading ? (
                <div className="flex justify-center py-12">
                  <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
              ) : accounts.length === 0 ? (
                <Alert>
                  <HandCoins className="h-4 w-4" />
                  <AlertTitle>Sin cartera pendiente</AlertTitle>
                  <AlertDescription>No hay cuentas activas con saldo por cobrar.</AlertDescription>
                </Alert>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Cliente</TableHead>
                        <TableHead>Detalle</TableHead>
                        <TableHead>Creada</TableHead>
                        <TableHead>Estado</TableHead>
                        <TableHead className="text-right">Saldo</TableHead>
                        <TableHead className="text-right">Acción</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {accounts.map((account) => (
                        <TableRow key={account.id}>
                          <TableCell>
                            <div className="font-medium">{account.clientName || 'Cliente sin nombre'}</div>
                            <div className="text-xs text-muted-foreground">{account.orderId ? `Pedido ${account.orderId}` : 'Sin pedido vinculado'}</div>
                          </TableCell>
                          <TableCell className="max-w-[280px] text-sm text-muted-foreground">
                            {account.description || 'Sin descripción'}
                          </TableCell>
                          <TableCell>{formatDate(account.createdAt)}</TableCell>
                          <TableCell>
                            <Badge variant={getStatusVariant(account.status)}>{account.status}</Badge>
                          </TableCell>
                          <TableCell className="text-right font-semibold">
                            {formatCurrency(Number(account.pendingAmount || account.remainingAmount || 0))}
                          </TableCell>
                          <TableCell className="text-right">
                            <Button size="sm" onClick={() => openPaymentDialog(account)}>
                              <HandCoins className="mr-2 h-4 w-4" />
                              Registrar abono
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="collections">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <CalendarDays className="h-5 w-5 text-sky-500" />
                Cobros del día
              </CardTitle>
              <CardDescription>
                Historial operativo de cobros registrados para {formatDate(selectedDate)}.
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 md:grid-cols-3">
                <Card className="bg-muted/50">
                  <CardHeader className="pb-2">
                    <CardDescription>Total cobrado</CardDescription>
                    <CardTitle>{formatCurrency(summary.totalAmount)}</CardTitle>
                  </CardHeader>
                </Card>
                <Card className="bg-muted/50">
                  <CardHeader className="pb-2">
                    <CardDescription>Cobros en efectivo</CardDescription>
                    <CardTitle>{formatCurrency(summary.cashTotal)}</CardTitle>
                  </CardHeader>
                </Card>
                <Card className="bg-muted/50">
                  <CardHeader className="pb-2">
                    <CardDescription>Otros métodos</CardDescription>
                    <CardTitle>{formatCurrency(summary.otherTotal)}</CardTitle>
                  </CardHeader>
                </Card>
              </div>

              {loading ? (
                <div className="flex justify-center py-12">
                  <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                </div>
              ) : collections.length === 0 ? (
                <Alert>
                  <CreditCard className="h-4 w-4" />
                  <AlertTitle>Sin movimientos</AlertTitle>
                  <AlertDescription>No se registraron cobros para la fecha seleccionada.</AlertDescription>
                </Alert>
              ) : (
                <div className="overflow-x-auto">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Cliente</TableHead>
                        <TableHead>Rutero</TableHead>
                        <TableHead>Método</TableHead>
                        <TableHead>Fecha</TableHead>
                        <TableHead>Notas</TableHead>
                        <TableHead className="text-right">Monto</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {collections.map((collection) => (
                        <TableRow key={collection.id}>
                          <TableCell>{collection.clientName || 'Cliente no identificado'}</TableCell>
                          <TableCell>{collection.ruteroName || collection.ruteroId || 'Sin rutero'}</TableCell>
                          <TableCell>
                            <Badge variant="outline">{collection.paymentMethod}</Badge>
                          </TableCell>
                          <TableCell>{formatDate(collection.createdAt, true)}</TableCell>
                          <TableCell className="max-w-[260px] text-sm text-muted-foreground">
                            {collection.notes || 'Sin notas'}
                          </TableCell>
                          <TableCell className="text-right font-semibold">{formatCurrency(collection.amount)}</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={Boolean(selectedAccount)} onOpenChange={(open) => !open && resetPaymentDialog()}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Registrar abono</DialogTitle>
            <DialogDescription>
              {selectedAccount
                ? `Saldo actual de ${selectedAccount.clientName}: ${formatCurrency(Number(selectedAccount.pendingAmount || selectedAccount.remainingAmount || 0))}.`
                : 'Selecciona una cuenta para registrar el cobro.'}
            </DialogDescription>
          </DialogHeader>

          <div className="grid gap-4 py-2">
            <div className="grid gap-2">
              <Label htmlFor="paymentAmount">Monto</Label>
              <Input
                id="paymentAmount"
                type="number"
                min="0"
                step="0.01"
                value={paymentAmount}
                onChange={(event) => setPaymentAmount(event.target.value)}
              />
            </div>
            <div className="grid gap-2">
              <Label>Método de pago</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecciona método" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="CASH">Efectivo</SelectItem>
                  <SelectItem value="TRANSFER">Transferencia</SelectItem>
                  <SelectItem value="CARD">Tarjeta</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="grid gap-2">
              <Label htmlFor="paymentNotes">Notas</Label>
              <Textarea
                id="paymentNotes"
                placeholder="Observación del cobro, referencia o comentario operativo."
                value={paymentNotes}
                onChange={(event) => setPaymentNotes(event.target.value)}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="ghost" onClick={resetPaymentDialog}>
              Cancelar
            </Button>
            <Button onClick={submitPayment} disabled={processingPayment}>
              {processingPayment ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <HandCoins className="mr-2 h-4 w-4" />}
              Confirmar cobro
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { toast } from '@/lib/swalert';
import { useParams } from 'react-router-dom';
import { useEffect, useState, useMemo } from 'react';
import apiClient from '@/services/api-client';
import { useAuth } from '@/contexts/auth-context';
import { logError } from '@/lib/error-logger';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Wrench } from 'lucide-react';

const adjustmentFormSchema = z.object({
  newStock: z.coerce.number().min(0, 'La cantidad no puede ser negativa.'),
});

type AdjustmentFormValues = z.infer<typeof adjustmentFormSchema>;

interface Product {
  id: string;
  barcode?: string;
  description: string;
  currentStock: number;
  usesInventory: boolean;
}

export default function InventoryAdjustmentsPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const { user } = useAuth();

  const [products, setProducts] = useState<Product[]>([]);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [loadingProducts, setLoadingProducts] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const form = useForm<AdjustmentFormValues>({
    resolver: zodResolver(adjustmentFormSchema) as any,
    defaultValues: {
      newStock: 0,
    }
  });

  useEffect(() => {
    if (!storeId) return;

    let isMounted = true;
    setLoadingProducts(true);

    const fetchProducts = async () => {
      try {
        const response = await apiClient.get('/products', { params: { storeId } });
        if (isMounted) {
          setProducts(response.data);
          setLoadingProducts(false);
        }
      } catch (error) {
        if (isMounted) {
          logError(error, { location: 'adjustments-page-fetch-products' });
          toast.error('Error', 'No se pudieron cargar los productos.');
          setLoadingProducts(false);
        }
      }
    };
    
    fetchProducts();

    return () => { isMounted = false; };
  }, [storeId]);

  useEffect(() => {
    if (selectedProduct) {
      form.setValue('newStock', selectedProduct.currentStock);
    } else {
      form.reset({ newStock: 0 });
    }
  }, [selectedProduct, form]);

  const filteredProducts = useMemo(() => {
    const inventoryProducts = products.filter((product) => product.usesInventory);
    if (!searchTerm) return inventoryProducts;
    const lowercasedFilter = searchTerm.toLowerCase();
    return inventoryProducts.filter(product =>
      product.description.toLowerCase().includes(lowercasedFilter) ||
      product.barcode?.toLowerCase().includes(lowercasedFilter)
    );
  }, [products, searchTerm]);

  async function onSubmit(values: z.infer<typeof adjustmentFormSchema>) {
    if (!selectedProduct || !user) {
      toast.error('Error', 'Debes seleccionar un producto.');
      return;
    }

    setIsSaving(true);
    try {
      const stockDifference = values.newStock - selectedProduct.currentStock;
      
      if (stockDifference === 0) {
        toast.info('Aviso', 'El stock ingresado es el mismo que el actual.');
        setIsSaving(false);
        return;
      }

      await apiClient.post('/inventory/adjust', {
        storeId,
        productId: selectedProduct.id,
        userId: user.id,
        type: stockDifference > 0 ? 'IN' : 'OUT',
        quantity: Math.abs(stockDifference),
        reference: 'Ajuste Manual de Inventario'
      });

      toast.success('Inventario Ajustado', `El stock de "${selectedProduct.description}" ha sido actualizado.`);
      setSelectedProduct(null); // Deselect product after adjustment
      
      // Refresh products to get updated stock
      const response = await apiClient.get('/products', { params: { storeId } });
      setProducts(response.data);
    } catch (error) {
      logError(error, {
        location: 'adjustments-page-submit',
        additionalInfo: { formData: values, storeId, productId: selectedProduct.id },
      })
      toast.error('Error', 'No se pudo ajustar el inventario.');
    } finally {
      setIsSaving(false);
    }
  }

  return (
    <div className="flex flex-col h-full">
      <div className="mb-6">
        <h1 className="text-2xl font-bold tracking-tight">Ajustes de Inventario</h1>
        <p className="text-muted-foreground">
          Busca un producto y modifica su cantidad en stock. Cada cambio se registrará en el historial.
        </p>
      </div>
      <div className="grid md:grid-cols-2 gap-6 flex-grow">
        <Card className="flex flex-col">
          <CardHeader>
            <Input
              placeholder="Buscar por nombre o código de barras..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </CardHeader>
          <CardContent className="flex-grow">
            <ScrollArea className="h-[500px]">
              <div className="space-y-2">
                {loadingProducts ? (
                  Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-12 w-full" />)
                ) : filteredProducts.map(product => (
                  <div
                    key={product.id}
                    onClick={() => setSelectedProduct(product)}
                    className={`p-3 rounded-md cursor-pointer border transition-colors ${selectedProduct?.id === product.id ? 'bg-muted ring-2 ring-primary' : 'hover:bg-muted/50'}`}
                  >
                    <p className="font-semibold">{product.description}</p>
                    <p className="text-sm text-muted-foreground">Stock: {product.currentStock}</p>
                  </div>
                ))}
              </div>
            </ScrollArea>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Detalles del Ajuste</CardTitle>
            <CardDescription>
              Selecciona un producto de la lista para empezar.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {selectedProduct ? (
              <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                  <div className="space-y-2 p-4 border rounded-md bg-muted/20">
                    <p className="text-sm text-muted-foreground">Código del Producto</p>
                    <p className="font-mono">{selectedProduct.barcode || 'N/A'}</p>
                    <p className="text-sm text-muted-foreground mt-2">Descripción</p>
                    <p className="font-semibold">{selectedProduct.description}</p>
                    <p className="text-sm text-muted-foreground mt-2">Cantidad Actual</p>
                    <p className="font-bold text-lg">{selectedProduct.currentStock}</p>
                  </div>
                  <FormField<AdjustmentFormValues>
                    control={form.control}
                    name="newStock"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="text-base">Nueva Cantidad</FormLabel>
                        <FormControl>
                          <Input type="number" step="1" min="0" {...field} className="text-lg h-12" />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <Button
                    type="submit"
                    className="w-full h-12"
                    disabled={isSaving || !selectedProduct}
                  >
                    {isSaving ? (
                      <svg
                        className="animate-spin h-5 w-5 mr-2"
                        xmlns="http://www.w3.org/2000/svg"
                        fill="none"
                        viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                    ) : (
                      <Wrench className="h-5 w-5 mr-2" />
                    )}
                    Ajustar Inventario
                  </Button>
                </form>
              </Form>
            ) : (
              <div className="flex flex-col items-center justify-center text-center text-muted-foreground h-64">
                <Wrench className="h-12 w-12 mb-4" />
                <p>Selecciona un producto de la lista para ajustar su inventario.</p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { Button } from '@/components/ui/button';
