export default function OrdersPipelinePage() {
  const { storeId } = useParams<{ storeId: string }>();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchOrders = async () => {
    if (!storeId) return;
    setLoading(true);
    try {
      const res = await apiClient.get('/orders', { params: { storeId } });
      const data = Array.isArray(res.data) ? res.data : [];
      // Filter out terminal states
      const active = data.filter(
        (o: Order) => !['ENTREGADO', 'CANCELADO', 'RECHAZADO'].includes(o.status),
      );
      setOrders(active);
    } catch {
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOrders();
    const interval = setInterval(fetchOrders, 15000);
    return () => clearInterval(interval);
  }, [storeId]);

  const grouped = PIPELINE_COLUMNS.map((col) => ({
    ...col,
    orders: orders.filter((o) => o.status === col.key),
  }));

  const totalActive = orders.length;

  return (
    <div className="space-y-6">
      {/* HEADER */}
      <section className="rounded-3xl bg-gradient-to-br from-slate-900 via-slate-800 to-sky-800 p-6 text-white shadow-xl">
        <div className="flex flex-col gap-4 xl:flex-row xl:items-center xl:justify-between">
          <div className="space-y-2">
            <Badge className="w-fit border border-white/20 bg-white/10 text-white hover:bg-white/10">
              <Clock className="h-3 w-3 mr-1" /> Pipeline en vivo
            </Badge>
            <h1 className="text-3xl font-black tracking-tight">Pipeline de Pedidos</h1>
            <p className="text-sm text-white/70">
              {totalActive} pedido(s) activo(s) en proceso. Se actualiza automáticamente cada 15 segundos.
            </p>
          </div>
          <Button
            onClick={fetchOrders}
            variant="outline"
            className="border-white/20 text-white hover:bg-white/10 rounded-2xl"
          >
            <RefreshCw className={`h-4 w-4 mr-2 ${loading ? 'animate-spin' : ''}`} /> Actualizar
          </Button>
        </div>
      </section>

      {/* PIPELINE COLUMNS */}
      {loading && orders.length === 0 ? (
        <div className="flex h-48 items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      ) : (
        <>
          {/* STATUS BAR */}
          <div className="flex items-center gap-1 rounded-2xl bg-slate-100 p-2">
            {grouped.map((col, i) => {
              const pct = totalActive > 0 ? (col.orders.length / totalActive) * 100 : 0;
              return (
                <div key={col.key} className="flex items-center gap-1 flex-1">
                  <div
                    className={`h-3 ${col.color} rounded-full transition-all duration-500`}
                    style={{ width: `${Math.max(pct, 5)}%`, minWidth: 12 }}
                    title={`${col.label}: ${col.orders.length}`}
                  />
                  {i < grouped.length - 1 && (
                    <ArrowRight className="h-3 w-3 text-slate-300 shrink-0" />
                  )}
                </div>
              );
            })}
          </div>

          {/* KANBAN GRID */}
          <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
            {grouped.map((col) => {
              const Icon = col.icon;
              return (
                <div key={col.key} className="space-y-3">
                  {/* Column header */}
                  <div className={`flex items-center justify-between rounded-2xl border p-4 ${col.lightBg}`}>
                    <div className="flex items-center gap-2">
                      <Icon className="h-5 w-5" />
                      <span className="font-black">{col.label}</span>
                    </div>
                    <Badge className={`${col.badge} font-black text-lg px-3 py-1`}>
                      {col.orders.length}
                    </Badge>
                  </div>

                  {/* Items */}
                  <div className="space-y-2 min-h-[120px]">
                    {col.orders.length === 0 ? (
                      <div className="flex items-center justify-center h-24 rounded-2xl border-2 border-dashed border-slate-200 text-sm text-muted-foreground">
                        Sin pedidos
                      </div>
                    ) : (
                      col.orders.map((order) => (
                        <Card key={order.id} className="rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                          <CardContent className="p-4 space-y-2">
                            <div className="flex items-center justify-between">
                              <p className="font-bold text-sm truncate">{order.clientName || 'Sin cliente'}</p>
                              <span className="text-xs text-muted-foreground font-mono">
                                #{order.id?.substring(0, 6)}
                              </span>
                            </div>
                            <div className="flex items-center justify-between">
                              <span className="text-lg font-black">
                                C$ {Number(order.total || 0).toFixed(2)}
                              </span>
                              {order.type && (
                                <Badge variant="outline" className="text-[10px] rounded-full">
                                  {order.type}
                                </Badge>
                              )}
                            </div>
                            <div className="flex items-center justify-between text-[11px] text-muted-foreground">
                              <span>{order.vendorName || '—'}</span>
                              <span>
                                {order.createdAt
                                  ? format(new Date(order.createdAt), 'HH:mm', { locale: es })
                                  : ''}
                              </span>
                            </div>
                          </CardContent>
                        </Card>
                      ))
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </>
      )}
    </div>
  );
}

import {
    Card, CardContent, CardDescription, CardHeader, CardTitle,
} from '@/components/ui/card';
import {
    Accordion, AccordionContent, AccordionItem, AccordionTrigger,
} from '@/components/ui/accordion';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { ClipboardCheck, Hourglass } from 'lucide-react';
import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { formatDistanceToNow } from 'date-fns';
import { es } from 'date-fns/locale';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Badge } from '@/components/ui/badge';
import {
    AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
    AlertDialogDescription, AlertDialogFooter, AlertDialogHeader,
    AlertDialogTitle, AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import apiClient from '@/services/api-client';
import { useRealTimeEvents } from '@/hooks/use-real-time-events';

interface OrderItem {
    id: string;
    description: string;
    quantity: number;
    salePrice: number;
}

interface PendingOrder {
    id: string;
    clientName: string;
    dispatcherName: string;
    salesManagerName?: string;
    items: OrderItem[];
    total: number;
    status: string;
    createdAt: string | Date;
}

export default function PendingOrdersPage() {
    const { storeId } = useParams<{ storeId: string }>();
    const { toast } = useToast();
    const { lastEvent } = useRealTimeEvents(storeId);

    const [orders, setOrders] = useState<PendingOrder[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const fetchOrders = async () => {
        try {
            const res = await apiClient.get('/pending-orders', { params: { storeId, status: 'Pendiente' } });
            setOrders(res.data);
            setError(null);
        } catch (err: any) {
            console.error('Error fetching pending orders:', err);
            setError('No se pudieron cargar las comandas pendientes.');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!storeId) return;
        fetchOrders();
        const interval = setInterval(fetchOrders, 15000);
        return () => clearInterval(interval);
    }, [storeId]);

    useEffect(() => {
        if (lastEvent && lastEvent.type !== 'PING') {
            fetchOrders();
        }
    }, [lastEvent]);

    const handleProcessOrder = async (order: PendingOrder) => {
        try {
            await apiClient.patch(`/pending-orders/${order.id}/status`, { status: 'Procesando' });
            toast({
                title: 'Comanda Procesada',
                description: `La comanda para ${order.clientName} ha sido marcada para cobro.`,
            });
            fetchOrders();
        } catch (err) {
            console.error(err);
            toast({ variant: 'destructive', title: 'Error', description: 'No se pudo procesar la comanda.' });
        }
    };

    const renderContent = () => {
        if (loading) {
            return (
                <div className="space-y-2">
                    {Array.from({ length: 3 }).map((_, i) => (
                        <Skeleton key={i} className="h-20 w-full" />
                    ))}
                </div>
            );
        }

        if (error) {
            return (
                <Alert variant="destructive">
                    <Hourglass className="h-4 w-4" />
                    <AlertTitle>Error</AlertTitle>
                    <AlertDescription>{error}</AlertDescription>
                </Alert>
            );
        }

        if (orders.length === 0) {
            return (
                <Alert>
                    <ClipboardCheck className="h-4 w-4" />
                    <AlertTitle>No hay comandas pendientes</AlertTitle>
                    <AlertDescription>Todas las comandas han sido procesadas.</AlertDescription>
                </Alert>
            );
        }

        return (
            <Accordion type="single" collapsible className="w-full">
                {orders.map((order) => (
                    <AccordionItem value={order.id} key={order.id}>
                        <AccordionTrigger className="hover:no-underline">
                            <div className="flex items-center justify-between w-full text-left">
                                <div className="flex-grow">
                                    <p className="font-medium text-primary">{order.clientName}</p>
                                    <p className="text-xs text-muted-foreground">
                                        por {order.dispatcherName || order.salesManagerName || 'N/A'} - {formatDistanceToNow(new Date(order.createdAt), { addSuffix: true, locale: es })}
                                    </p>
                                </div>
                                <div className="font-semibold text-lg pr-4">
                                    C$ {order.total.toFixed(2)}
                                </div>
                            </div>
                        </AccordionTrigger>
                        <AccordionContent className="bg-muted/30 p-4 rounded-md">
                            <h4 className="font-semibold mb-2">Productos en la Comanda:</h4>
                            <ul className="list-disc pl-5 space-y-1 text-sm">
                                {order.items?.map(item => (
                                    <li key={item.id}>
                                        ({item.quantity}) {item.description}
                                    </li>
                                ))}
                            </ul>
                            <div className="mt-4">
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <Button>Cobrar esta Comanda</Button>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader>
                                            <AlertDialogTitle>¿Confirmar para Cobrar?</AlertDialogTitle>
                                            <AlertDialogDescription>
                                                Esta acción eliminará la comanda de la lista de pendientes.
                                            </AlertDialogDescription>
                                        </AlertDialogHeader>
                                        <AlertDialogFooter>
                                            <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                            <AlertDialogAction onClick={() => handleProcessOrder(order)}>
                                                Sí, cobrar ahora
                                            </AlertDialogAction>
                                        </AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>
                            </div>
                        </AccordionContent>
                    </AccordionItem>
                ))}
            </Accordion>
        );
    };

    return (
        <div>
            <div className="mb-6 flex justify-between items-center bg-card p-6 rounded-lg border shadow-sm">
                <div>
                    <h1 className="text-2xl font-bold tracking-tight flex items-center gap-2">
                        <ClipboardCheck className="h-6 w-6 text-primary" />
                        Comandas Pendientes de Cobro
                    </h1>
                    <p className="text-muted-foreground mt-1">
                        Comandas listas para ser facturadas.
                    </p>
                </div>
                <Button onClick={fetchOrders} variant="outline" className="gap-2 shrink-0">
                    <Hourglass className="h-4 w-4" /> Actualizar
                </Button>
            </div>
            <Card>
                <CardHeader>
                    <CardTitle>Lista de Comandas</CardTitle>
                    <CardDescription>
                        Selecciona una comanda para ver los detalles y proceder con el cobro.
                    </CardDescription>
                </CardHeader>
                <CardContent>{renderContent()}</CardContent>
            </Card>
        </div>
    );
}

'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  FormDescription,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Input } from '@/components/ui/input';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { toast } from '@/lib/swalert';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft, Save } from 'lucide-react';
import { useEffect, useState } from 'react';
import { Separator } from '@/components/ui/separator';
import { Checkbox } from '@/components/ui/checkbox';
import apiClient from '@/services/api-client';
import { useAuth } from '@/contexts/auth-context';
import { logError } from '@/lib/error-logger';

const productFormSchema = z.object({
  barcode: z.string().optional(),
  brand: z.string().optional(),
  description: z.string().min(3, { message: 'La descripción es requerida.' }),
  packagingType: z.enum(['UNIT', 'BULTO'], {
    errorMap: () => ({ message: 'Debes seleccionar un tipo de venta.' }),
  }),
  unitsPerBulk: z.coerce.number().optional(),
  costPrice: z.coerce.number().min(0, { message: 'El precio no puede ser negativo.' }),
  price1: z.coerce.number().min(0, { message: 'El precio no puede ser negativo.' }),
  price2: z.coerce.number().min(0, { message: 'El precio no puede ser negativo.' }),
  price3: z.coerce.number().optional(),
  price4: z.coerce.number().optional(),
  price5: z.coerce.number().optional(),
  department: z.string({ required_error: 'Debes seleccionar un departamento.' }),
  subDepartment: z.string().optional(),
  supplierId: z.string().optional(),
  supplierName: z.string().optional(),
  usesInventory: z.boolean().default(true),
  currentStock: z.coerce.number().optional(),
  minStock: z.coerce.number().optional(),
}).refine(data => {
  if (data.packagingType === 'BULTO') {
    return data.unitsPerBulk !== undefined && data.unitsPerBulk > 0;
  }
  return true;
}, {
  message: 'Debes especificar las unidades por bulto.',
  path: ['unitsPerBulk'],
});

interface Department {
  id: string;
  name: string;
}

interface SubDepartment {
  id: string;
  name: string;
  departmentId: string;
}

interface Supplier {
  id: string;
  name: string;
}


export default function AddProductPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const { user } = useAuth();
  const navigate = useNavigate();
  const [departments, setDepartments] = useState<Department[]>([]);
  const [subDepartments, setSubDepartments] = useState<SubDepartment[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  const form = useForm<z.infer<typeof productFormSchema>>({
    resolver: zodResolver(productFormSchema),
    defaultValues: {
      barcode: '',
      brand: '',
      description: '',
      packagingType: 'UNIT',
      department: '',
      subDepartment: '',
      supplierId: '',
      unitsPerBulk: 1,
      usesInventory: true,
      currentStock: 0,
      minStock: 0,
      costPrice: 0,
      price1: 0,
      price2: 0,
      price3: 0,
      price4: 0,
      price5: 0,
    },
  });

  const usesInventory = form.watch('usesInventory');
  const packagingType = form.watch('packagingType');
  const selectedDepartment = form.watch('department');

  useEffect(() => {
    if (!storeId) return;
    let isMounted = true;
    const loadData = async () => {
      try {
        const [deptsRes, subDeptsRes, supRes] = await Promise.all([
          apiClient.get('/departments', { params: { storeId, type: 'main' } }),
          apiClient.get('/sub-departments', { params: { storeId } }).catch(() => ({ data: [] })),
          apiClient.get('/suppliers', { params: { storeId } }).catch(() => ({ data: [] }))
        ]);
        
        if (isMounted) {
          setDepartments(deptsRes.data.map((d: any) => ({ ...d, name: d.name || d.nombre })));
          setSubDepartments((subDeptsRes.data || []).map((sd: any) => ({
            id: sd.id,
            name: sd.name || sd.nombre,
            departmentId: sd.departmentId || sd.parentId || sd.parent_id || '',
          })));
          setSuppliers(supRes.data.map((s: any) => ({ ...s, name: s.name || s.nombre })));
        }
      } catch (err: any) {
        logError(err, { location: 'add-product-page-fetch-data' });
        toast.error('Error', 'No se pudieron cargar los datos iniciales.');
      }
    };
    
    loadData();

    return () => {
      isMounted = false;
    };
  }, [storeId]);

  useEffect(() => {
    form.setValue('subDepartment', '');
  }, [selectedDepartment, form]);

  async function onSubmit(values: z.infer<typeof productFormSchema>) {
    setIsSaving(true);
    if (!storeId || !user) {
      toast.error('Error', 'No se pudo identificar la tienda o el usuario.');
      setIsSaving(false);
      return;
    }
    try {
      const selectedDept = departments.find(d => d.id === values.department);
      const selectedSub = subDepartments.find(s => s.id === values.subDepartment);
      const selectedSup = suppliers.find(s => s.id === values.supplierId);

      const productData = {
        ...values,
        packagingType: values.packagingType,
        unitsPerBulk: values.unitsPerBulk || 1,
        salePrice: values.price1,
        departmentId: values.department,
        department: selectedDept?.name || '',
        subDepartmentId: values.subDepartment === 'none' ? '' : values.subDepartment,
        subDepartment: selectedSub?.name || '',
        supplierId: values.supplierId === 'none' ? '' : (selectedSup?.id || ''),
        supplierName: selectedSup?.name || '',
        storeId,
      };

      if (productData.subDepartmentId === 'none') productData.subDepartmentId = '';
      if (productData.supplierId === 'none') productData.supplierId = '';

      await apiClient.post('/products', productData);

      toast.success('Producto Guardado', `El producto "${values.description}" ha sido agregado al inventario.`);
      navigate(`/store/${storeId}/products`);
    } catch (error) {
      await logError(error, {
        location: 'add-product-page-submit',
        additionalInfo: { formData: values, storeId },
      })
      toast.error('Error', 'No se pudo guardar el producto. Inténtalo de nuevo.');
    } finally {
      setIsSaving(false);
    }
  }

  return (
    <div className="flex-1 space-y-4 p-4 md:p-8 pt-6">
      <div className="mb-6">
        <Button variant="ghost" asChild>
          <Link to={`/store/${storeId}/products`}>
            <ArrowLeft className="mr-2 h-4 w-4" />
            Volver a Productos
          </Link>
        </Button>
      </div>
      <div className="flex justify-center">
        <Card className="w-full max-w-3xl">
          <CardHeader>
            <CardTitle>Nuevo Producto</CardTitle>
            <CardDescription>
              Completa los detalles para agregar un nuevo producto a tu
              inventario.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Form {...form}>
              <form
                onSubmit={form.handleSubmit(onSubmit)}
                className="space-y-6"
              >
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="barcode"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Código de Barras</FormLabel>
                        <FormControl>
                          <Input placeholder="Escanear o ingresar código" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Descripción</FormLabel>
                        <FormControl>
                          <Input placeholder="Ej. Coca-Cola 600ml" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
                <div className="grid grid-cols-1 gap-4">
                  <FormField
                    control={form.control}
                    name="brand"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Marca</FormLabel>
                        <FormControl>
                          <Input placeholder="Ej. Nike, Coca-Cola, etc." {...field} />
                        </FormControl>
                        <FormDescription>Ingresa la marca del producto si deseas rastrearlo por marca.</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
                <FormField
                  control={form.control}
                  name="packagingType"
                  render={({ field }) => (
                    <FormItem className="space-y-3">
                      <FormLabel>Se vende</FormLabel>
                      <FormControl>
                        <RadioGroup
                          onValueChange={field.onChange}
                          defaultValue={field.value}
                          className="flex flex-col md:flex-row space-y-2 md:space-y-0 md:space-x-4"
                        >
                          <FormItem className="flex items-center space-x-3 space-y-0">
                            <FormControl>
                              <RadioGroupItem value="UNIT" />
                            </FormControl>
                            <FormLabel className="font-normal">
                              Por Unidad/Pza
                            </FormLabel>
                          </FormItem>
                          <FormItem className="flex items-center space-x-3 space-y-0">
                            <FormControl>
                              <RadioGroupItem value="BULTO" />
                            </FormControl>
                            <FormLabel className="font-normal">
                              Por Bulto
                            </FormLabel>
                          </FormItem>
                        </RadioGroup>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {packagingType === 'BULTO' && (
                  <FormField
                    control={form.control}
                    name="unitsPerBulk"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Unidades por Bulto</FormLabel>
                        <FormControl>
                          <Input type="number" placeholder="Ej. 12" {...field} />
                        </FormControl>
                        <FormDescription>
                          ¿Cuántas unidades individuales contiene el bulto?
                        </FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <FormField
                    control={form.control}
                    name="costPrice"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio Costo</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="price1"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio 1 (Principal)</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="price2"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio 2 (Oferta)</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <FormField
                    control={form.control}
                    name="price3"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio 3 (Mayoreo)</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="price4"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio 4 (Especial)</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormDescription className="text-xs">Req. Autorización</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="price5"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Precio 5 (Mínimo)</FormLabel>
                        <FormControl>
                          <Input type="number" step="0.01" {...field} />
                        </FormControl>
                        <FormDescription className="text-xs">Req. Autorización</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="department"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Departamento</FormLabel>
                        <Select
                          onValueChange={field.onChange}
                          defaultValue={field.value}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="- Selecciona un Departamento -" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {departments.map((dept) => (
                              <SelectItem key={dept.id} value={dept.id}>
                                {dept.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={form.control}
                    name="subDepartment"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Sub-departamento</FormLabel>
                        <Select
                          onValueChange={field.onChange}
                          value={field.value}
                          disabled={!selectedDepartment}
                        >
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="- Selecciona un Sub-departamento -" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            <SelectItem value="none">Ninguno</SelectItem>
                            {subDepartments
                              .filter(sd => sd.departmentId === selectedDepartment)
                              .map((subDept) => (
                                <SelectItem key={subDept.id} value={subDept.id}>
                                  {subDept.name}
                                </SelectItem>
                              ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="supplierId"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Proveedor</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="- Selecciona un Proveedor -" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="none">Ninguno</SelectItem>
                          {suppliers.map((sup) => (
                            <SelectItem key={sup.id} value={sup.id}>
                              {sup.name}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <Separator />

                <FormField
                  control={form.control}
                  name="usesInventory"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
                      <FormControl>
                        <Checkbox
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                      <div className="space-y-1 leading-none">
                        <FormLabel>
                          Gestión de Inventario
                        </FormLabel>
                        <FormDescription>
                          Activa esta opción para controlar el stock de este producto.
                        </FormDescription>
                      </div>
                    </FormItem>
                  )}
                />

                {usesInventory && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="currentStock"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Cantidad Actual (en unidades)</FormLabel>
                          <FormControl>
                            <Input type="number" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="minStock"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Mínimo en Stock (en unidades)</FormLabel>
                          <FormControl>
                            <Input type="number" {...field} />
                          </FormControl>
                          <FormDescription>
                            Para generar alertas de inventario bajo.
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                )}


                <Button
                  type="submit"
                  className="fixed bottom-8 right-8 h-14 w-14 rounded-full shadow-lg z-50 bg-accent text-accent-foreground hover:bg-accent/90"
                  disabled={isSaving}
                >
                  {isSaving ? (
                    <svg
                      className="animate-spin h-5 w-5 text-white"
                      xmlns="http://www.w3.org/2000/svg"
                      fill="none"
                      viewBox="0 0 24 24"
                    >
                      <circle
                        className="opacity-25"
                        cx="12"
                        cy="12"
                        r="10"
                        stroke="currentColor"
                        strokeWidth="4"
                      ></circle>
                      <path
                        className="opacity-75"
                        fill="currentColor"
                        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                      ></path>
                    </svg>
                  ) : (
                    <Save className="h-6 w-6" />
                  )}
                  <span className="sr-only">Guardar Producto</span>
                </Button>
              </form>
            </Form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { toast } from '@/lib/swalert';
import { Link, useParams } from 'react-router-dom';
import { ArrowLeft, Plus, Trash2, Edit, Check, X } from 'lucide-react';
import { useEffect, useState } from 'react';
import apiClient from '@/services/api-client';
import { logError } from '@/lib/error-logger';
import { Separator } from '@/components/ui/separator';
import { Skeleton } from '@/components/ui/skeleton';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';

const departmentFormSchema = z.object({
  name: z.string().min(2, {
    message: 'El nombre debe tener al menos 2 caracteres.',
  }),
});

interface Department {
  id: string;
  name: string;
}

export default function DepartmentsPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const [isSaving, setIsSaving] = useState(false);
  const [departments, setDepartments] = useState<Department[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');

  const fetchDepartments = async () => {
    try {
      const response = await apiClient.get('/departments', { params: { storeId } });
      setDepartments(response.data.map((d: any) => ({ ...d, name: d.name || d.nombre })));
    } catch (error) {
      logError(error, { location: 'departments-page-fetch' });
      toast.error('Error', 'No se pudieron cargar los departamentos.');
    } finally {
      setLoading(false);
    }
  };

  async function deleteDepartment(id: string) {
    try {
      await apiClient.delete(`/departments/${id}`);
      fetchDepartments(); // Refresh
      toast.success('Departamento Eliminado', 'El departamento ha sido eliminado correctamente.');
    } catch (error) {
      logError(error, {
        location: 'departments-page-delete',
        additionalInfo: { departmentId: id, storeId },
      });
      toast.error('Error', 'No se pudo eliminar el departamento.');
    }
  }

  const handleEditClick = (dept: Department) => {
    setEditingId(dept.id);
    setEditingName(dept.name);
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditingName('');
  };

  const form = useForm<z.infer<typeof departmentFormSchema>>({
    resolver: zodResolver(departmentFormSchema),
    defaultValues: {
      name: '',
    },
  });

  useEffect(() => {
    if (!storeId) return;
    fetchDepartments();
  }, [storeId]);

  async function onSubmit(values: z.infer<typeof departmentFormSchema>) {
    setIsSaving(true);
    if (!storeId) return;
    try {
      await apiClient.post('/departments', {
        name: values.name,
        storeId,
      });
      fetchDepartments(); // Refresh
      toast.success('Departamento Agregado', `"${values.name}" ha sido agregado.`);
      form.reset();
    } catch (error) {
      logError(error, { location: 'departments-page-add', additionalInfo: { values, storeId } });
      toast.error('Error', 'No se pudo agregar el departamento.');
    } finally {
      setIsSaving(false);
    }
  }

  async function handleUpdateDepartment() {
    if (!editingId || !editingName.trim()) return;
    try {
      await apiClient.patch(`/departments/${editingId}`, {
        name: editingName,
      });
      fetchDepartments(); // Refresh
      toast.success('Departamento Actualizado', 'El nombre ha sido actualizado.');
      setEditingId(null);
      setEditingName('');
    } catch (error) {
      logError(error, { location: 'departments-page-update', additionalInfo: { editingId, editingName } });
      toast.error('Error', 'No se pudo actualizar el departamento.');
    }
  }

  return (
    <div>
      <div className="mb-6">
        <Button variant="ghost" asChild>
          <Link to={`/store/${storeId}/products`}>
            <ArrowLeft className="mr-2" />
            Volver a Productos
          </Link>
        </Button>
      </div>
      <div className="flex justify-center">
        <Card className="w-full max-w-md">
          <CardHeader>
            <CardTitle>Departamentos</CardTitle>
          </CardHeader>
          <CardContent>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem className="flex-grow">
                      <FormLabel>Nombre del Departamento</FormLabel>
                      <FormControl>
                        <Input placeholder="Ej. Bebidas" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <Button
                  type="submit"
                  className="fixed bottom-8 right-8 h-14 w-14 rounded-full shadow-lg z-50 bg-accent text-accent-foreground hover:bg-accent/90"
                  disabled={isSaving}
                >
                  {isSaving ? (
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                  ) : (
                    <Plus className="h-6 w-6" />
                  )}
                  <span className="sr-only">Agregar Departamento</span>
                </Button>
              </form>
            </Form>

            <Separator className="my-6" />

            <div>
              <h3 className="text-lg font-medium mb-4">Lista</h3>
              {loading ? (
                <div className="space-y-2">
                  <Skeleton className="h-10 w-full" />
                  <Skeleton className="h-10 w-full" />
                  <Skeleton className="h-10 w-full" />
                </div>
              ) : departments.length > 0 ? (
                <ul className="space-y-2">
                  {departments.map((dept) => (
                    <li key={dept.id} className="flex items-center justify-between p-2 rounded-md border group">
                      {editingId === dept.id ? (
                        <Input
                          value={editingName}
                          onChange={(e) => setEditingName(e.target.value)}
                          className="h-8"
                        />
                      ) : (
                        <span className="text-sm font-medium">{dept.name}</span>
                      )}

                      <div className="flex items-center gap-1">
                        {editingId === dept.id ? (
                          <>
                            <Button variant="ghost" size="icon" onClick={handleUpdateDepartment} className="h-8 w-8">
                              <Check className="h-4 w-4 text-green-600" />
                            </Button>
                            <Button variant="ghost" size="icon" onClick={handleCancelEdit} className="h-8 w-8">
                              <X className="h-4 w-4 text-gray-600" />
                            </Button>
                          </>
                        ) : (
                          <>
                            <Button variant="ghost" size="icon" onClick={() => handleEditClick(dept)} className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                              <Edit className="h-4 w-4" />
                            </Button>
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <Trash2 className="h-4 w-4 text-destructive" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent>
                                <AlertDialogHeader>
                                  <AlertDialogTitle>¿Estás seguro?</AlertDialogTitle>
                                  <AlertDialogDescription>
                                    Esta acción no se puede deshacer. Esto eliminará permanentemente el departamento &quot;{dept.name}&quot;.
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => deleteDepartment(dept.id)}>
                                    Eliminar
                                  </AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </>
                        )}
                      </div>
                    </li>
                  ))}
                </ul>
              ) : (
                <p className="text-sm text-muted-foreground text-center">No hay departamentos agregados todavía.</p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft, Loader2, Save } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from '@/lib/swalert';
import apiClient from '@/services/api-client';

interface Department {
  id: string;
  name: string;
}

interface SubDepartment {
  id: string;
  name: string;
  departmentId: string;
}

interface Supplier {
  id: string;
  name: string;
}

interface ProductResponse {
  id: string;
  barcode?: string;
  brand?: string;
  description: string;
  costPrice: number;
  price1: number;
  price2: number;
  price3: number;
  price4: number;
  price5: number;
  departmentId?: string;
  supplierId?: string;
  subDepartment?: string;
  usesInventory: boolean;
  currentStock: number;
  minStock: number;
  unitsPerBulk?: number;
  stockBulks?: number;
  stockUnits?: number;
}

interface ProductFormState {
  barcode: string;
  brand: string;
  description: string;
  costPrice: string;
  price1: string;
  price2: string;
  price3: string;
  price4: string;
  price5: string;
  departmentId: string;
  supplierId: string;
  subDepartment: string;
  usesInventory: boolean;
  currentStock: string;
  minStock: string;
  unitsPerBulk: string;
  stockBulks: string;
  stockUnits: string;
}

const emptyForm: ProductFormState = {
  barcode: '',
  brand: '',
  description: '',
  costPrice: '0',
  price1: '0',
  price2: '0',
  price3: '0',
  price4: '0',
  price5: '0',
  departmentId: '',
  supplierId: '',
  subDepartment: '',
  usesInventory: true,
  currentStock: '0',
  minStock: '0',
  unitsPerBulk: '1',
  stockBulks: '0',
  stockUnits: '0',
};

function toFormData(product: ProductResponse): ProductFormState {
  return {
    barcode: product.barcode || '',
    brand: product.brand || '',
    description: product.description || '',
    costPrice: String(product.costPrice ?? 0),
    price1: String(product.price1 ?? 0),
    price2: String(product.price2 ?? 0),
    price3: String(product.price3 ?? 0),
    price4: String(product.price4 ?? 0),
    price5: String(product.price5 ?? 0),
    departmentId: product.departmentId || '',
    supplierId: product.supplierId || '',
    subDepartment: product.subDepartment || '',
    usesInventory: product.usesInventory !== false,
    currentStock: String(product.currentStock ?? 0),
    minStock: String(product.minStock ?? 0),
    unitsPerBulk: String(product.unitsPerBulk ?? 1),
    stockBulks: String(product.stockBulks ?? 0),
    stockUnits: String(product.stockUnits ?? 0),
  };
}

export default function EditProductPage() {
  const { storeId, productId } = useParams<{ storeId: string; productId: string }>();
  const navigate = useNavigate();

  const [departments, setDepartments] = useState<Department[]>([]);
  const [subDepartments, setSubDepartments] = useState<SubDepartment[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [formData, setFormData] = useState<ProductFormState>(emptyForm);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!storeId || !productId) return;

    let isMounted = true;
    const loadData = async () => {
      try {
        const [productRes, departmentsRes, subDepartmentsRes, suppliersRes] = await Promise.all([
          apiClient.get(`/products/${productId}`),
          apiClient.get('/departments', { params: { storeId, type: 'main' } }),
          apiClient.get('/sub-departments', { params: { storeId } }).catch(() => ({ data: [] })),
          apiClient.get('/suppliers', { params: { storeId } }).catch(() => ({ data: [] })),
        ]);

        if (!isMounted) return;

        setFormData(toFormData(productRes.data));
        setDepartments((departmentsRes.data || []).map((department: any) => ({
          id: department.id,
          name: department.name || department.nombre,
        })));
        setSubDepartments((subDepartmentsRes.data || []).map((subDepartment: any) => ({
          id: subDepartment.id,
          name: subDepartment.name || subDepartment.nombre,
          departmentId: subDepartment.departmentId || subDepartment.parentId || subDepartment.parent_id || '',
        })));
        setSuppliers((suppliersRes.data || []).map((supplier: any) => ({
          id: supplier.id,
          name: supplier.name || supplier.nombre,
        })));
      } catch (error) {
        console.error(error);
        toast.error('Error', 'No se pudo cargar la información del producto.');
        navigate(`/store/${storeId}/products`);
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };

    loadData();

    return () => {
      isMounted = false;
    };
  }, [storeId, productId, navigate]);

  const updateField = (field: keyof ProductFormState, value: string | boolean) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  useEffect(() => {
    if (!formData.departmentId) {
      if (formData.subDepartment) {
        updateField('subDepartment', '');
      }
      return;
    }

    const belongsToDepartment = subDepartments.some(
      (subDepartment) =>
        subDepartment.departmentId === formData.departmentId && subDepartment.name === formData.subDepartment,
    );

    if (formData.subDepartment && !belongsToDepartment) {
      updateField('subDepartment', '');
    }
  }, [formData.departmentId, formData.subDepartment, subDepartments]);

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (!productId || !storeId) return;

    if (!formData.description.trim()) {
      toast.error('Error', 'La descripción es obligatoria.');
      return;
    }

    setSaving(true);
    try {
      await apiClient.patch(`/products/${productId}`, {
        barcode: formData.barcode || null,
        brand: formData.brand || null,
        description: formData.description.trim(),
        costPrice: Number(formData.costPrice || 0),
        salePrice: Number(formData.price1 || 0),
        price1: Number(formData.price1 || 0),
        price2: Number(formData.price2 || 0),
        price3: Number(formData.price3 || 0),
        price4: Number(formData.price4 || 0),
        price5: Number(formData.price5 || 0),
        departmentId: formData.departmentId || null,
        supplierId: formData.supplierId || null,
        subDepartment: formData.subDepartment || null,
        usesInventory: formData.usesInventory,
        currentStock: Number(formData.currentStock || 0),
        minStock: Number(formData.minStock || 0),
        unitsPerBulk: Math.max(1, Number(formData.unitsPerBulk || 1)),
        stockBulks: Number(formData.stockBulks || 0),
        stockUnits: Number(formData.stockUnits || 0),
      });

      toast.success('Producto actualizado', `Se guardaron los cambios de "${formData.description}".`);
      navigate(`/store/${storeId}/products`);
    } catch (error: any) {
      console.error(error);
      toast.error('Error', error?.response?.data?.message || 'No se pudo actualizar el producto.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex h-[60vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-4 md:p-8">
      <div>
        <Button variant="ghost" asChild>
          <Link to={`/store/${storeId}/products`}>
            <ArrowLeft className="mr-2 h-4 w-4" />
            Volver a productos
          </Link>
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Editar producto</CardTitle>
          <CardDescription>
            Ajusta precios, clasificación e inventario base del producto seleccionado.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="grid gap-6 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="description">Descripción</Label>
                <Input
                  id="description"
                  value={formData.description}
                  onChange={(event) => updateField('description', event.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="barcode">Código de barras</Label>
                <Input
                  id="barcode"
                  value={formData.barcode}
                  onChange={(event) => updateField('barcode', event.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="brand">Marca</Label>
                <Input
                  id="brand"
                  value={formData.brand}
                  onChange={(event) => updateField('brand', event.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Departamento</Label>
                <Select value={formData.departmentId || 'none'} onValueChange={(value) => updateField('departmentId', value === 'none' ? '' : value)}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecciona un departamento" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Sin departamento</SelectItem>
                    {departments.map((department) => (
                      <SelectItem key={department.id} value={department.id}>
                        {department.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Proveedor</Label>
                <Select value={formData.supplierId || 'none'} onValueChange={(value) => updateField('supplierId', value === 'none' ? '' : value)}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecciona un proveedor" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Sin proveedor</SelectItem>
                    {suppliers.map((supplier) => (
                      <SelectItem key={supplier.id} value={supplier.id}>
                        {supplier.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <Label>Sub-departamento</Label>
                <Select value={formData.subDepartment || 'none'} onValueChange={(value) => updateField('subDepartment', value === 'none' ? '' : value)}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecciona un sub-departamento" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Sin sub-departamento</SelectItem>
                    {subDepartments
                      .filter((subDepartment) => subDepartment.departmentId === formData.departmentId)
                      .map((subDepartment) => (
                        <SelectItem key={subDepartment.id} value={subDepartment.name}>
                          {subDepartment.name}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid gap-4 md:grid-cols-3">
              <div className="space-y-2">
                <Label htmlFor="costPrice">Costo</Label>
                <Input id="costPrice" type="number" min="0" step="0.01" value={formData.costPrice} onChange={(event) => updateField('costPrice', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price1">Precio 1</Label>
                <Input id="price1" type="number" min="0" step="0.01" value={formData.price1} onChange={(event) => updateField('price1', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price2">Precio 2</Label>
                <Input id="price2" type="number" min="0" step="0.01" value={formData.price2} onChange={(event) => updateField('price2', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price3">Precio 3</Label>
                <Input id="price3" type="number" min="0" step="0.01" value={formData.price3} onChange={(event) => updateField('price3', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price4">Precio 4</Label>
                <Input id="price4" type="number" min="0" step="0.01" value={formData.price4} onChange={(event) => updateField('price4', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="price5">Precio 5</Label>
                <Input id="price5" type="number" min="0" step="0.01" value={formData.price5} onChange={(event) => updateField('price5', event.target.value)} />
              </div>
            </div>

            <div className="grid gap-4 md:grid-cols-4">
              <div className="space-y-2">
                <Label htmlFor="currentStock">Stock total</Label>
                <Input id="currentStock" type="number" min="0" step="1" value={formData.currentStock} onChange={(event) => updateField('currentStock', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="minStock">Stock mínimo</Label>
                <Input id="minStock" type="number" min="0" step="1" value={formData.minStock} onChange={(event) => updateField('minStock', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="unitsPerBulk">Unidades por bulto</Label>
                <Input id="unitsPerBulk" type="number" min="1" step="1" value={formData.unitsPerBulk} onChange={(event) => updateField('unitsPerBulk', event.target.value)} />
              </div>
              <div className="flex items-center gap-3 rounded-lg border px-4 py-3">
                <Checkbox
                  id="usesInventory"
                  checked={formData.usesInventory}
                  onCheckedChange={(checked) => updateField('usesInventory', Boolean(checked))}
                />
                <Label htmlFor="usesInventory" className="cursor-pointer">
                  Usa inventario
                </Label>
              </div>
            </div>

            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="stockBulks">Bultos</Label>
                <Input id="stockBulks" type="number" min="0" step="1" value={formData.stockBulks} onChange={(event) => updateField('stockBulks', event.target.value)} />
              </div>
              <div className="space-y-2">
                <Label htmlFor="stockUnits">Unidades sueltas</Label>
                <Input id="stockUnits" type="number" min="0" step="1" value={formData.stockUnits} onChange={(event) => updateField('stockUnits', event.target.value)} />
              </div>
            </div>

            <div className="flex justify-end">
              <Button type="submit" disabled={saving}>
                {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
                Guardar cambios
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

