import { FloatingActionButton } from "@/components/floating-action-button";
import { Card, CardContent } from "@/components/ui/card";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { Package, Shapes, Library, ChevronRight, Wrench, Download } from "lucide-react";
import * as XLSX from "xlsx";
import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState, useMemo } from 'react';
import apiClient from '@/services/api-client';
import { logError } from '@/lib/error-logger';
import { Link } from 'react-router-dom';
import { cn } from '@/lib/utils';
import { ImportProductsDialog } from '@/components/products/import-products-dialog';

interface Department {
    id: string;
    name: string;
}

interface SubDepartment {
    id: string;
    name: string;
    departmentId: string;
}

interface Product {
    id: string;
    barcode?: string;
    description: string;
    salePrice: number;
    currentStock: number;
    unitsPerBulk?: number;
    stockBulks?: number;
    stockUnits?: number;
    minStock: number;
    usesInventory: boolean;
    department?: string;
    subDepartment?: string;
}

function getStockBadgeVariant(currentStock: number, minStock: number) {
    if (currentStock === 0) return 'text-white bg-destructive hover:bg-destructive';
    if (currentStock <= minStock) return 'text-white bg-orange-500 hover:bg-orange-500';
    return 'text-white bg-green-600 hover:bg-green-600';
}

export default function ProductsPage() {
    const params = useParams();
    const storeId = params.storeId as string;
    const navigate = useNavigate();

    const [products, setProducts] = useState<Product[]>([]);
    const [departments, setDepartments] = useState<Department[]>([]);
    const [subDepartments, setSubDepartments] = useState<SubDepartment[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    const [selectedDepartment, setSelectedDepartment] = useState<Department | null>(null);
    const [selectedSubDepartment, setSelectedSubDepartment] = useState<SubDepartment | null>(null);
    const [reorganizationMode, setReorganizationMode] = useState(false);
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

    useEffect(() => {
        if (!storeId) return;

        let isMounted = true;
        setLoading(true);

        const fetchData = async () => {
            try {
                const [prodsRes, deptsRes, subDeptsRes] = await Promise.all([
                    apiClient.get('/products', { params: { storeId } }),
                    apiClient.get('/departments', { params: { storeId, type: 'main' } }),
                    apiClient.get('/sub-departments', { params: { storeId } }).catch(() => ({ data: [] })),
                ]);

                if (isMounted) {
                    setProducts(prodsRes.data as Product[]);
                    setDepartments(deptsRes.data.map((d: any) => ({ ...d, name: d.name || d.nombre })));
                    setSubDepartments((subDeptsRes.data || []).map((subDept: any) => ({
                        id: subDept.id,
                        name: subDept.name || subDept.nombre,
                        departmentId: subDept.departmentId || subDept.parentId || subDept.parent_id || '',
                    })));
                    setLoading(false);
                }
            } catch (err: any) {
                if (isMounted) {
                    logError(err, { location: 'products-page-fetch-api' });
                    setError('No se pudieron cargar los datos.');
                    setLoading(false);
                }
            }
        };

        fetchData();

        return () => {
            isMounted = false;
        };
    }, [storeId]);

    const unorganizedProducts = useMemo(() => {
        return products.filter(p => !p.department || p.department === '');
    }, [products]);

    const filteredProducts = useMemo(() => {
        if (selectedSubDepartment) {
            if (selectedSubDepartment.id === 'none') {
                return products.filter(p => p.department === selectedDepartment?.name && !p.subDepartment);
            }
            return products.filter(p => p.department === selectedDepartment?.name && p.subDepartment === selectedSubDepartment.name);
        }
        if (selectedDepartment) {
            return products.filter(p => p.department === selectedDepartment.name && !p.subDepartment);
        }
        return [];
    }, [products, selectedDepartment, selectedSubDepartment]);

    const filteredSubDepartments = useMemo(() => {
        if (!selectedDepartment) return [];
        return subDepartments.filter(sd => sd.departmentId === selectedDepartment.id);
    }, [subDepartments, selectedDepartment]);

    const handleEdit = () => {
        if (selectedProduct) {
            navigate(`/store/${storeId}/products/edit/${selectedProduct.id}`);
        }
    };

    const resetSelection = () => {
        setSelectedDepartment(null);
        setSelectedSubDepartment(null);
        setReorganizationMode(false);
    }

    const productCountsBySubDept = useMemo(() => {
        const counts = new Map<string, number>();
        products.forEach(product => {
            if (product.department && product.subDepartment) {
                const key = `${product.department}-${product.subDepartment}`;
                counts.set(key, (counts.get(key) || 0) + 1);
            }
        });
        return counts;
    }, [products]);

    const productCountsByDept = useMemo(() => {
        const counts = new Map<string, number>();
        products.forEach(product => {
            if (product.department && !product.subDepartment) {
                counts.set(product.department, (counts.get(product.department) || 0) + 1);
            }
        });
        return counts;
    }, [products]);

    const handleExport = () => {
        const dataToExport = products.map((p: any) => ({
            'Código de Barras': p.barcode || '',
            'Descripción': p.description,
            'Precio de Costo': p.costPrice || 0,
            'Precio de Venta': p.salePrice || 0,
            'Precio Mayorista': p.wholesalePrice || 0,
            'Precio 1': p.price1 || 0,
            'Precio 2': p.price2 || 0,
            'Precio 3': p.price3 || 0,
            'Precio 4': p.price4 || 0,
            'Precio 5': p.price5 || 0,
            'Departamento': p.department || '',
            'Subdepartamento': p.subDepartment || '',
            'Proveedor': p.supplierName || '',
            'Usa Inventario': p.usesInventory ? 'SI' : 'NO',
            'Stock Actual': p.currentStock || 0,
            'Stock Mínimo': p.minStock || 0,
        }));

        const worksheet = XLSX.utils.json_to_sheet(dataToExport);
        const workbook = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(workbook, worksheet, "Productos");
        XLSX.writeFile(workbook, "productos.xlsx");
    };

    const renderBreadcrumb = () => (
        <div className="flex items-center text-sm text-muted-foreground mb-4">
            <button onClick={resetSelection} className="hover:underline">Inicio</button>
            {reorganizationMode && (
                <>
                    <ChevronRight className="h-4 w-4 mx-1" />
                    <span className="font-semibold text-foreground">Reorganizar</span>
                </>
            )}
            {selectedDepartment && !reorganizationMode && (
                <>
                    <ChevronRight className="h-4 w-4 mx-1" />
                    <button onClick={() => setSelectedSubDepartment(null)} className="hover:underline">{selectedDepartment.name}</button>
                </>
            )}
            {selectedSubDepartment && !reorganizationMode && (
                <>
                    <ChevronRight className="h-4 w-4 mx-1" />
                    <span className="font-semibold text-foreground">{selectedSubDepartment.name}</span>
                </>
            )}
        </div>
    );

    const renderContent = () => {
        if (loading) {
            return (
                <div className="space-y-3">
                    {Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-20 w-full" />)}
                </div>
            )
        }

        if (error) {
            return (
                <Alert variant="destructive">
                    <Package className="h-4 w-4" />
                    <AlertTitle>Error</AlertTitle>
                    <AlertDescription>{error}</AlertDescription>
                </Alert>
            )
        }

        const productListContent = (productsToList: Product[]) => {
            if (productsToList.length === 0) {
                return <Alert><Package className="h-4 w-4" /><AlertTitle>No hay productos</AlertTitle><AlertDescription>No se encontraron productos en esta categoría.</AlertDescription></Alert>
            }
            return (
                <div className="space-y-3">
                    <AlertDialog>
                        {productsToList.map((product) => (
                            <AlertDialogTrigger asChild key={product.id} onClick={() => setSelectedProduct(product)}>
                                <Card className="hover:bg-muted/50 transition-colors cursor-pointer">
                                    <CardContent className="p-4 grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 items-center gap-4">
                                        <div className="col-span-2">
                                            <p className="font-semibold">{product.description}</p>
                                            {reorganizationMode && <p className="text-xs text-destructive">Departamento: {product.department || 'Ninguno'}</p>}
                                        </div>
                                        <div className="text-right sm:text-left">
                                            <p className="text-xs text-muted-foreground">Precio</p>
                                            <p className="font-medium">C$ {product.salePrice.toFixed(2)}</p>
                                        </div>
                                            <div className="text-right sm:text-left">
                                                <p className="text-xs text-muted-foreground">Stock</p>
                                                {product.usesInventory ? (
                                                    <div className="flex flex-col items-end sm:items-start">
                                                        <Badge variant="default" className={cn("text-base", getStockBadgeVariant(product.currentStock, product.minStock))}>
                                                            {product.currentStock} T
                                                        </Badge>
                                                        {(product.unitsPerBulk || 1) > 1 && (
                                                            <p className="text-xs text-muted-foreground mt-1">
                                                                {product.stockBulks || 0} Bulto{(product.stockBulks !== 1) ? 's' : ''}, {product.stockUnits || 0} U
                                                            </p>
                                                        )}
                                                    </div>
                                                ) : (
                                                    <Badge variant="secondary">N/A</Badge>
                                                )}
                                            </div>
                                    </CardContent>
                                </Card>
                            </AlertDialogTrigger>
                        ))}
                        <AlertDialogContent>
                            <AlertDialogHeader>
                                <AlertDialogTitle>¿Qué deseas hacer con &quot;{selectedProduct?.description}&quot;?</AlertDialogTitle>
                                <AlertDialogDescription>
                                    Selecciona una opción para continuar.
                                </AlertDialogDescription>
                            </AlertDialogHeader>
                            <AlertDialogFooter>
                                <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                <AlertDialogAction onClick={handleEdit}>
                                    Editar
                                </AlertDialogAction>
                            </AlertDialogFooter>
                        </AlertDialogContent>
                    </AlertDialog>
                </div>
            )
        }

        // View Reorganization
        if (reorganizationMode) {
            return productListContent(unorganizedProducts);
        }

        // View Products for a department (no sub-department) or a sub-department
        if (selectedSubDepartment || (selectedDepartment && filteredSubDepartments.length === 0)) {
            return productListContent(filteredProducts);
        }

        // View Sub-Departments for a department
        if (selectedDepartment) {
            const productsInDeptOnly = productCountsByDept.get(selectedDepartment.name) || 0;
            return (
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                    {filteredSubDepartments.map(subDept => {
                        const count = productCountsBySubDept.get(`${selectedDepartment.name}-${subDept.name}`) || 0;
                        return (
                            <Card key={subDept.id} className="hover:bg-muted/50 transition-colors cursor-pointer" onClick={() => setSelectedSubDepartment(subDept)}>
                                <CardContent className="p-4 flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <Library className="h-5 w-5 text-muted-foreground" />
                                        <p className="font-semibold">{subDept.name}</p>
                                        <Badge variant="secondary">{count}</Badge>
                                    </div>
                                    <ChevronRight className="h-5 w-5 text-muted-foreground" />
                                </CardContent>
                            </Card>
                        )
                    })}
                    {productsInDeptOnly > 0 && (
                        <Card className="hover:bg-muted/50 transition-colors cursor-pointer border-dashed" onClick={() => setSelectedSubDepartment({ id: 'none', name: 'Sin Sub-departamento', departmentId: selectedDepartment.id })}>
                            <CardContent className="p-4 flex items-center justify-between">
                                <div className="flex items-center gap-3">
                                    <Package className="h-5 w-5 text-muted-foreground" />
                                    <p className="font-semibold">Sin Sub-departamento</p>
                                    <Badge variant="secondary">{productsInDeptOnly}</Badge>
                                </div>
                                <ChevronRight className="h-5 w-5 text-muted-foreground" />
                            </CardContent>
                        </Card>
                    )}
                </div>
            )
        }

        // View Departments
        if (departments.length === 0) {
            return <Alert><Shapes className="h-4 w-4" /><AlertTitle>Sin departamentos</AlertTitle><AlertDescription>Crea un departamento para organizar productos.</AlertDescription></Alert>
        }

        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                {departments.map(dept => (
                    <Card key={dept.id} className="hover:bg-muted/50 transition-colors cursor-pointer" onClick={() => setSelectedDepartment(dept)}>
                        <CardContent className="p-4 flex items-center justify-between">
                            <div className="flex items-center gap-3">
                                <Shapes className="h-5 w-5 text-muted-foreground" />
                                <p className="font-semibold">{dept.name}</p>
                            </div>
                            <ChevronRight className="h-5 w-5 text-muted-foreground" />
                        </CardContent>
                    </Card>
                ))}
            </div>
        )
    }

    return (
        <div>
            <div className="mb-6">
                <h1 className="text-2xl font-bold tracking-tight">Productos</h1>
            </div>
            <div className="flex flex-wrap gap-2 mb-6">
                <Button variant="outline" asChild>
                    <Link to={`/store/${storeId}/products/departments`}>
                        <Shapes className="mr-2 h-4 w-4" />
                        Depart.
                    </Link>
                </Button>
                <Button variant="outline" asChild>
                    <Link to={`/store/${storeId}/products/sub-departments`}>
                        <Library className="mr-2 h-4 w-4" />
                        Sub-Depart.
                    </Link>
                </Button>
                <Button variant="outline" onClick={() => { setReorganizationMode(true); setSelectedDepartment(null); setSelectedSubDepartment(null); }} className="relative">
                    <Wrench className="mr-2 h-4 w-4" />
                    Reorganizar
                    {unorganizedProducts.length > 0 && (
                        <Badge variant="destructive" className="absolute -top-2 -right-2 px-2">
                            {unorganizedProducts.length}
                        </Badge>
                    )}
                </Button>
                <ImportProductsDialog storeId={storeId} departments={departments} />
                <Button variant="outline" onClick={handleExport} disabled={products.length === 0} className="border-green-600/30 text-green-700 hover:bg-green-50 dark:text-green-400 dark:hover:bg-green-950">
                    <Download className="mr-2 h-4 w-4" />
                    Exportar Excel
                </Button>
            </div>

            {renderBreadcrumb()}
            {renderContent()}

            <FloatingActionButton href={`/store/${storeId}/products/add`} />
        </div>
    );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { toast } from '@/lib/swalert';
import { Link, useParams } from 'react-router-dom';
import { ArrowLeft, Plus, Trash2, Edit, Check, X } from 'lucide-react';
import { useEffect, useState } from 'react';
import apiClient from '@/services/api-client';
import { logError } from '@/lib/error-logger';
import { Separator } from '@/components/ui/separator';
import { Skeleton } from '@/components/ui/skeleton';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

const subDepartmentFormSchema = z.object({
  name: z.string().min(2, {
    message: 'El nombre debe tener al menos 2 caracteres.',
  }),
  departmentId: z.string().min(1, 'Debe seleccionar un departamento padre.'),
});

interface Department {
  id: string;
  name: string;
}

interface SubDepartment {
  id: string;
  name: string;
  departmentId: string;
  departmentName?: string;
}

export default function SubDepartmentsPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const [isSaving, setIsSaving] = useState(false);
  const [departments, setDepartments] = useState<Department[]>([]);
  const [subDepartments, setSubDepartments] = useState<SubDepartment[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');

  const form = useForm<z.infer<typeof subDepartmentFormSchema>>({
    resolver: zodResolver(subDepartmentFormSchema),
    defaultValues: {
      name: '',
      departmentId: '',
    },
  });

  const fetchData = async () => {
    try {
      const [deptsRes, subDeptsRes] = await Promise.all([
        apiClient.get('/departments', { params: { storeId, type: 'main' } }),
        apiClient.get('/sub-departments', { params: { storeId } }).catch(() => ({ data: [] })),
      ]);
      const depts = deptsRes.data;
      setDepartments(depts);
      const departmentMap = new Map(depts.map((d: any) => [d.id, d.name]));
      const enriched = (subDeptsRes.data || []).map((sd: any) => ({
        ...sd,
        departmentId: sd.departmentId || sd.parentId || sd.parent_id || '',
        departmentName: departmentMap.get(sd.departmentId || sd.parentId || sd.parent_id) || 'Desconocido'
      }));
      setSubDepartments(enriched);
    } catch (error) {
      logError(error, { location: 'sub-departments-page-fetch' });
      toast.error('Error', 'No se pudieron cargar los datos.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!storeId) return;
    fetchData();
  }, [storeId]);


  async function onSubmit(values: z.infer<typeof subDepartmentFormSchema>) {
    setIsSaving(true);
    try {
      await apiClient.post('/departments', {
        name: values.name,
        storeId,
        parentId: values.departmentId,
      });
      fetchData();
      toast.success('Sub-departamento Creado', `El sub-departamento "${values.name}" ha sido creado.`);
      form.reset();
    } catch (error) {
      logError(error, {
        location: 'sub-departments-page-submit',
        additionalInfo: { formData: values, storeId },
      });
      toast.error('Error', 'No se pudo crear el sub-departamento.');
    } finally {
      setIsSaving(false);
    }
  }

  async function handleUpdateSubDepartment() {
    if (!editingId || !editingName) return;

    try {
      await apiClient.patch(`/departments/${editingId}`, { name: editingName });
      fetchData();
      toast.success('Sub-departamento Actualizado', 'El nombre del sub-departamento ha sido actualizado.');
      setEditingId(null);
      setEditingName('');
    } catch (error) {
      logError(error, {
        location: 'sub-departments-page-update',
        additionalInfo: { subDepartmentId: editingId, storeId },
      });
      toast.error('Error', 'No se pudo actualizar el sub-departamento.');
    }
  }

  async function deleteSubDepartment(id: string) {
    try {
      await apiClient.delete(`/departments/${id}`);
      fetchData();
      toast.success('Sub-departamento Eliminado', 'El sub-departamento ha sido eliminado correctamente.');
    } catch (error) {
      logError(error, {
        location: 'sub-departments-page-delete',
        additionalInfo: { subDepartmentId: id, storeId },
      });
      toast.error('Error', 'No se pudo eliminar el sub-departamento.');
    }
  }

  const handleEditClick = (subDept: SubDepartment) => {
    setEditingId(subDept.id);
    setEditingName(subDept.name);
  };

  const handleCancelEdit = () => {
    setEditingId(null);
    setEditingName('');
  };

  return (
    <div>
      <div className="mb-6">
        <Button variant="ghost" asChild>
          <Link to={`/store/${storeId}/products`}>
            <ArrowLeft className="mr-2" />
            Volver a Productos
          </Link>
        </Button>
      </div>
      <div className="flex justify-center">
        <Card className="w-full max-w-2xl">
          <CardHeader>
            <CardTitle>Gestionar Sub-departamentos</CardTitle>
            <CardDescription>
              Agrega, visualiza, edita y elimina los sub-departamentos de tu tienda.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                <FormField
                  control={form.control}
                  name="departmentId"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Departamento Padre</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Selecciona un departamento..." />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {departments.map((dept) => (
                            <SelectItem key={dept.id} value={dept.id}>
                              {dept.name}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem className="flex-grow">
                      <FormLabel>Nombre del Sub-departamento</FormLabel>
                      <FormControl>
                        <Input placeholder="Ej. Cloros" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <Button
                  type="submit"
                  className="w-full"
                  disabled={isSaving}
                >
                  {isSaving ? (
                    <svg className="animate-spin h-5 w-5 mr-2" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                  ) : (
                    <Plus className="mr-2 h-4 w-4" />
                  )}
                  Agregar Sub-departamento
                </Button>
              </form>
            </Form>

            <Separator className="my-6" />

            <div>
              <h3 className="text-lg font-medium mb-4">Sub-departamentos Existentes</h3>
              {loading ? (
                <div className="space-y-2">
                  <Skeleton className="h-10 w-full" />
                  <Skeleton className="h-10 w-full" />
                  <Skeleton className="h-10 w-full" />
                </div>
              ) : subDepartments.length > 0 ? (
                <ul className="space-y-2">
                  {subDepartments.map((subDept) => (
                    <li key={subDept.id} className="flex items-center justify-between p-2 rounded-md border group">
                      {editingId === subDept.id ? (
                        <Input
                          value={editingName}
                          onChange={(e) => setEditingName(e.target.value)}
                          className="h-8"
                        />
                      ) : (
                        <div>
                          <span className="text-sm font-medium">{subDept.name}</span>
                          <p className="text-xs text-muted-foreground">({subDept.departmentName})</p>
                        </div>
                      )}
                      <div className="flex items-center gap-1">
                        {editingId === subDept.id ? (
                          <>
                            <Button variant="ghost" size="icon" onClick={handleUpdateSubDepartment} className="h-8 w-8">
                              <Check className="h-4 w-4 text-green-600" />
                            </Button>
                            <Button variant="ghost" size="icon" onClick={handleCancelEdit} className="h-8 w-8">
                              <X className="h-4 w-4 text-gray-600" />
                            </Button>
                          </>
                        ) : (
                          <>
                            <Button variant="ghost" size="icon" onClick={() => handleEditClick(subDept)} className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                              <Edit className="h-4 w-4" />
                            </Button>
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <Trash2 className="h-4 w-4 text-destructive" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent>
                                <AlertDialogHeader>
                                  <AlertDialogTitle>¿Estás seguro?</AlertDialogTitle>
                                  <AlertDialogDescription>
                                    Esta acción no se puede deshacer. Esto eliminará permanentemente el sub-departamento &quot;{subDept.name}&quot;.
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                  <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => deleteSubDepartment(subDept.id)}>
                                    Eliminar
                                  </AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </>
                        )}
                      </div>
                    </li>
                  ))}
                </ul>
              ) : (
                <p className="text-sm text-muted-foreground text-center">No hay sub-departamentos agregados todavía.</p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import {
  CalendarCheck2,
  ChevronDown,
  FileText,
  Filter,
  Loader2,
  Search,
  Wallet,
} from 'lucide-react';
import { format, subDays } from 'date-fns';
import { es } from 'date-fns/locale';

import apiClient from '@/services/api-client';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible';

interface DailyClosing {
  id: string;
  storeId: string;
  ruteroId: string;
  ruteroName: string;
  totalSales: number;
  totalCollections: number;
  totalReturns: number;
  cashTotal: number;
  closingDate: string;
  notes: string | null;
  createdAt: string;
}

export default function AdminDailyClosingsPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const [closings, setClosings] = useState<DailyClosing[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchDate, setSearchDate] = useState(format(new Date(), 'yyyy-MM-dd'));

  const fetchClosings = async (date?: string) => {
    if (!storeId) return;
    setLoading(true);
    try {
      const params: any = { storeId };
      if (date) params.date = date;
      const res = await apiClient.get('/daily-closings', { params });
      setClosings(Array.isArray(res.data) ? res.data : []);
    } catch {
      setClosings([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchClosings(searchDate);
  }, [storeId]);

  const handleSearch = () => {
    fetchClosings(searchDate);
  };

  const handleShowAll = () => {
    setSearchDate('');
    fetchClosings();
  };

  const totals = closings.reduce(
    (acc, c) => ({
      sales: acc.sales + c.totalSales,
      collections: acc.collections + c.totalCollections,
      returns: acc.returns + c.totalReturns,
      cash: acc.cash + c.cashTotal,
    }),
    { sales: 0, collections: 0, returns: 0, cash: 0 },
  );

  return (
    <div className="space-y-6">
      {/* HEADER */}
      <section className="rounded-3xl bg-gradient-to-br from-slate-900 via-violet-900 to-fuchsia-800 p-6 text-white shadow-xl">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="space-y-3">
            <Badge className="w-fit border border-white/20 bg-white/10 text-white hover:bg-white/10">
              <FileText className="h-3 w-3 mr-1" /> Consolidado
            </Badge>
            <div className="space-y-1">
              <h1 className="text-3xl font-black tracking-tight">Cierres de Caja</h1>
              <p className="text-sm text-white/70">
                Historial de liquidaciones de todos los ruteros y vendedores.
              </p>
            </div>
          </div>

          {/* Summary chips */}
          <div className="grid gap-3 sm:grid-cols-4">
            <SummaryChip label="Ventas" value={`C$ ${totals.sales.toFixed(2)}`} />
            <SummaryChip label="Cobros" value={`C$ ${totals.collections.toFixed(2)}`} />
            <SummaryChip label="Devoluciones" value={`C$ ${totals.returns.toFixed(2)}`} />
            <SummaryChip label="Efectivo" value={`C$ ${totals.cash.toFixed(2)}`} highlight />
          </div>
        </div>
      </section>

      {/* FILTERS */}
      <Card className="rounded-2xl">
        <CardContent className="p-4">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
            <div className="flex items-center gap-2 flex-1">
              <Filter className="h-4 w-4 text-muted-foreground" />
              <Input
                type="date"
                value={searchDate}
                onChange={(e) => setSearchDate(e.target.value)}
                className="max-w-[200px] rounded-xl"
              />
              <Button onClick={handleSearch} size="sm" className="rounded-xl">
                <Search className="h-4 w-4 mr-1" /> Buscar
              </Button>
              <Button onClick={handleShowAll} variant="outline" size="sm" className="rounded-xl">
                Ver todo
              </Button>
            </div>
            <p className="text-sm text-muted-foreground">
              {closings.length} cierre(s) encontrado(s)
            </p>
          </div>
        </CardContent>
      </Card>

      {/* TABLE */}
      {loading ? (
        <div className="flex h-48 items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
        </div>
      ) : closings.length === 0 ? (
        <Card className="rounded-2xl">
          <CardContent className="flex flex-col items-center justify-center py-12 text-muted-foreground">
            <CalendarCheck2 className="h-12 w-12 mb-4 opacity-50" />
            <p className="text-lg font-bold">Sin cierres</p>
            <p className="text-sm">No hay cierres de caja registrados para esta fecha.</p>
          </CardContent>
        </Card>
      ) : (
        <Card className="rounded-2xl overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Fecha</TableHead>
                <TableHead>Rutero/Vendedor</TableHead>
                <TableHead className="text-right">Ventas</TableHead>
                <TableHead className="text-right">Cobros</TableHead>
                <TableHead className="text-right">Devoluciones</TableHead>
                <TableHead className="text-right font-black">Efectivo</TableHead>
                <TableHead>Notas</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {closings.map((c) => (
                <TableRow key={c.id}>
                  <TableCell className="font-medium">
                    {c.closingDate
                      ? format(new Date(c.closingDate + 'T12:00:00'), 'd MMM yyyy', { locale: es })
                      : '—'}
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-2">
                      <div className="h-8 w-8 rounded-full bg-primary/10 flex items-center justify-center text-xs font-bold text-primary">
                        {(c.ruteroName || '?')[0].toUpperCase()}
                      </div>
                      <span className="font-medium">{c.ruteroName || c.ruteroId?.substring(0, 8)}</span>
                    </div>
                  </TableCell>
                  <TableCell className="text-right font-mono">C$ {c.totalSales.toFixed(2)}</TableCell>
                  <TableCell className="text-right font-mono">C$ {c.totalCollections.toFixed(2)}</TableCell>
                  <TableCell className="text-right font-mono text-orange-600">
                    {c.totalReturns > 0 ? `-C$ ${c.totalReturns.toFixed(2)}` : 'C$ 0.00'}
                  </TableCell>
                  <TableCell className="text-right font-mono font-black text-lg">
                    C$ {c.cashTotal.toFixed(2)}
                  </TableCell>
                  <TableCell className="max-w-[200px] truncate text-xs text-muted-foreground">
                    {c.notes || '—'}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* TOTALS ROW */}
          <div className="border-t bg-slate-50 px-4 py-3 flex items-center justify-between">
            <p className="text-sm font-bold text-muted-foreground uppercase tracking-wide">
              Totales ({closings.length} cierres)
            </p>
            <div className="flex gap-6 text-sm font-mono">
              <span>Ventas: <strong>C$ {totals.sales.toFixed(2)}</strong></span>
              <span>Cobros: <strong>C$ {totals.collections.toFixed(2)}</strong></span>
              <span className="text-orange-600">Dev: <strong>-C$ {totals.returns.toFixed(2)}</strong></span>
              <span className="text-lg font-black">Efectivo: C$ {totals.cash.toFixed(2)}</span>
            </div>
          </div>
        </Card>
      )}
    </div>
  );
}

function SummaryChip({
  label,
  value,
  highlight,
}: {
  label: string;
  value: string;
  highlight?: boolean;
}) {
  return (
    <div className={`rounded-2xl border ${highlight ? 'border-white/30 bg-white/20' : 'border-white/10 bg-white/10'} p-3`}>
      <p className="text-[10px] uppercase tracking-[0.18em] text-white/60">{label}</p>
      <p className={`mt-1 text-lg font-black ${highlight ? 'text-white' : 'text-white/90'}`}>{value}</p>
    </div>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Cog, Zap, Layout, Printer, ShieldCheck, DollarSign, Save, Loader2 } from 'lucide-react';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormDescription,
} from '@/components/ui/form';
import {
  RadioGroup,
  RadioGroupItem,
} from '@/components/ui/radio-group';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Switch } from '@/components/ui/switch';
import { useParams } from 'react-router-dom';
import { useEffect, useState, useCallback } from 'react';
import apiClient from '@/services/api-client';
import { toast } from '@/lib/swalert';
import { Skeleton } from '@/components/ui/skeleton';
import { cn } from '@/lib/utils';

const settingsSchema = z.object({
  applyVAT: z.boolean(),
  exchangeRate: z.number().min(1),
  billingMode: z.enum(['scan-and-add', 'scan-and-prompt']),
  adminPin: z.string().min(4).max(8),
  enableDispatcherMode: z.boolean(),
  trackByBrand: z.boolean(),
  headerLine1: z.string(),
  headerLine2: z.string(),
  footerLine1: z.string(),
  fontSize: z.number().min(8),
  columns: z.number().min(20),
});

type SettingsFormValues = z.infer<typeof settingsSchema>;

export default function StoreSettingsPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  const form = useForm<SettingsFormValues>({
    resolver: zodResolver(settingsSchema),
    defaultValues: {
      applyVAT: false,
      exchangeRate: 36.60,
      billingMode: 'scan-and-add',
      adminPin: '0000',
      enableDispatcherMode: false,
      trackByBrand: false,
      headerLine1: 'MULTITIENDA LOS PINOS',
      headerLine2: 'Sucursal Central',
      footerLine1: '¡Gracias por su preferencia!',
      fontSize: 10,
      columns: 36,
    },
  });

  const fetchSettings = useCallback(async () => {
    if (!storeId) return;
    try {
      const response = await apiClient.get(`/stores/${storeId}`);
      if (response.data && response.data.settings) {
        form.reset(response.data.settings);
      }
    } catch (error) {
      console.error("Error fetching settings:", error);
    } finally {
      setLoading(false);
    }
  }, [storeId, form]);

  useEffect(() => {
    fetchSettings();
  }, [fetchSettings]);

  async function onSubmit(values: SettingsFormValues) {
    setIsSaving(true);
    try {
      await apiClient.patch(`/stores/${storeId}/settings`, values);
      toast.success('Configuración Guardada', 'Los ajustes de la tienda se han actualizado con éxito.');
    } catch (error) {
      toast.error('Error', 'No se pudo guardar la configuración.');
    } finally {
      setIsSaving(false);
    }
  }

  if (loading) {
    return (
      <div className="p-8 max-w-4xl mx-auto space-y-8">
        <Skeleton className="h-12 w-1/3 rounded-2xl" />
        <Skeleton className="h-64 w-full rounded-3xl" />
      </div>
    );
  }

  /**
   * Helper to fix TS issues with Control in FormField
   * by explicitly casting the generic Control.
   */
  const control = form.control as any;

  return (
    <div className="p-8 max-w-5xl mx-auto min-h-screen bg-slate-50/30">
      <div className="mb-10">
        <h1 className="text-4xl font-black italic uppercase tracking-tighter text-slate-800 leading-none">Ajustes del Sistema</h1>
        <p className="text-slate-400 font-bold uppercase tracking-widest text-sm mt-3 flex items-center gap-2">
          <Cog className="h-4 w-4 text-blue-500" /> Configuración Global de la Sucursal
        </p>
      </div>

      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
          <Tabs defaultValue="general" className="w-full">
            <TabsList className="bg-white p-1 rounded-2xl shadow-sm border border-slate-100 flex h-auto mb-8">
              <TabsTrigger value="general" className="flex-1 py-3 font-black uppercase text-xs rounded-xl data-[state=active]:bg-blue-600 data-[state=active]:text-white transition-all">
                <Zap className="w-4 h-4 mr-2" /> General
              </TabsTrigger>
              <TabsTrigger value="workflow" className="flex-1 py-3 font-black uppercase text-xs rounded-xl data-[state=active]:bg-blue-600 data-[state=active]:text-white transition-all">
                <Layout className="w-4 h-4 mr-2" /> Flujo
              </TabsTrigger>
              <TabsTrigger value="ticket" className="flex-1 py-3 font-black uppercase text-xs rounded-xl data-[state=active]:bg-blue-600 data-[state=active]:text-white transition-all">
                <Printer className="w-4 h-4 mr-2" /> Ticket
              </TabsTrigger>
              <TabsTrigger value="security" className="flex-1 py-3 font-black uppercase text-xs rounded-xl data-[state=active]:bg-blue-600 data-[state=active]:text-white transition-all">
                <ShieldCheck className="w-4 h-4 mr-2" /> Seguridad
              </TabsTrigger>
            </TabsList>

            {/* GENERAL TAB */}
            <TabsContent value="general" className="mt-0">
              <Card className="rounded-[40px] border-none shadow-2xl bg-white overflow-hidden">
                <CardHeader className="bg-slate-50/50 p-8">
                  <CardTitle className="text-2xl font-black uppercase text-slate-800">Impuestos y Divisas</CardTitle>
                  <CardDescription className="text-slate-400 font-bold uppercase text-xs">Manejo de IVA y Tasa de Cambio</CardDescription>
                </CardHeader>
                <CardContent className="p-8 space-y-6">
                  <FormField
                    control={control}
                    name="applyVAT"
                    render={({ field }) => (
                      <FormItem className="flex items-center justify-between p-6 bg-slate-50 rounded-3xl border-2 border-slate-100 shadow-inner">
                        <div className="space-y-0.5">
                          <FormLabel className="text-lg font-black text-slate-700 uppercase">Aplicar IVA (15%)</FormLabel>
                          <FormDescription className="font-bold text-slate-400">Calcular impuestos en facturación</FormDescription>
                        </div>
                        <FormControl>
                          <Switch checked={!!field.value} onCheckedChange={field.onChange} className="data-[state=checked]:bg-emerald-500 scale-125" />
                        </FormControl>
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={control}
                    name="exchangeRate"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel className="text-sm font-black text-slate-500 uppercase">Tasa de Cambio Oficial (C$1.00 USD)</FormLabel>
                        <div className="relative">
                          <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 h-6 w-6" />
                          <FormControl>
                            <Input type="number" step="0.01" className="h-16 pl-12 text-2xl font-black font-mono border-2 rounded-2xl bg-white shadow-sm focus:border-blue-500" {...field} />
                          </FormControl>
                        </div>
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>
            </TabsContent>

            {/* WORKFLOW TAB */}
            <TabsContent value="workflow" className="mt-0">
              <Card className="rounded-[40px] border-none shadow-2xl bg-white overflow-hidden">
                <CardHeader className="bg-slate-50/50 p-8">
                  <CardTitle className="text-2xl font-black uppercase text-slate-800">Modos de Operación</CardTitle>
                </CardHeader>
                <CardContent className="p-8 space-y-6">
                   <FormField
                    control={control}
                    name="billingMode"
                    render={({ field }) => (
                      <FormItem className="space-y-4">
                        <FormLabel className="text-lg font-black text-slate-700 uppercase">Modo de POS</FormLabel>
                        <FormControl>
                          <RadioGroup
                            onValueChange={field.onChange}
                            defaultValue={field.value}
                            className="grid grid-cols-1 md:grid-cols-2 gap-4"
                          >
                            <FormItem className={cn(
                              "flex items-center space-x-4 space-y-0 border-2 p-6 rounded-3xl transition-all cursor-pointer",
                              field.value === 'scan-and-add' ? "bg-blue-50 border-blue-500 shadow-lg" : "border-slate-100 bg-white"
                            )}>
                              <FormControl><RadioGroupItem value="scan-and-add" /></FormControl>
                              <FormLabel className="font-black text-slate-700 flex flex-col cursor-pointer">
                                <span>MODO DIRECTO</span>
                                <span className="text-[10px] font-bold text-slate-400 mt-1 uppercase">1 Escaneo = 1 Unidad (Supermercado)</span>
                              </FormLabel>
                            </FormItem>
                            <FormItem className={cn(
