import { Button } from "@/components/ui/button";
import { FloatingActionButton } from "@/components/floating-action-button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Users } from "lucide-react";
import { useEffect, useState } from "react";
import apiClient from '@/services/api-client';
import { Skeleton } from "@/components/ui/skeleton";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion';
import { Badge } from "@/components/ui/badge";
import { useParams, Link } from "react-router-dom";
import { toast, alert as swalert } from '@/lib/swalert';

interface User {
  uid: string;
  name: string;
  email: string;
  role: string;
  id?: string;
}

export default function StoreUsersPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchUsers = async () => {
    try {
      const response = await apiClient.get('/users', { params: { storeId } });
      setUsers(response.data);
      setLoading(false);
    } catch (err) {
      console.error("Error fetching store users:", err);
      setError("No se pudieron cargar los usuarios de la tienda.");
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!storeId) return;
    fetchUsers();
  }, [storeId]);

  const renderContent = () => {
    if (loading) {
      return (
        <div className="space-y-2">
          {Array.from({ length: 3 }).map((_, i) => (
            <Skeleton key={i} className="h-12 w-full" />
          ))}
        </div>
      );
    }

    if (error) {
      return (
        <Alert variant="destructive">
          <Users className="h-4 w-4" />
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      );
    }

    if (users.length === 0) {
      return (
        <Alert>
          <Users className="h-4 w-4" />
          <AlertTitle>No hay usuarios</AlertTitle>
          <AlertDescription>
            Aún no has agregado ningún usuario a esta tienda.
          </AlertDescription>
        </Alert>
      );
    }

    return (
      <div className="rounded-md border">
        <Accordion type="single" collapsible className="w-full">
          {users.map((user) => {
            const userId = user.uid || user.id || '';
            return (
              <AccordionItem value={userId} key={userId}>
                <AccordionTrigger className="px-6 py-4 hover:no-underline">
                  <div className="flex items-center justify-between w-full">
                    <span className="font-medium text-left">{user.name}</span>
                    <Badge variant="secondary">
                      {user.role}
                    </Badge>
                  </div>
                </AccordionTrigger>
                <AccordionContent className="px-6 pb-4 bg-muted/50">
                  <div className="flex flex-col gap-4">
                    <p className="text-sm">
                      <strong>Correo:</strong> {user.email}
                    </p>
                    <div className="flex gap-2">
                      <Button variant="outline" size="sm" asChild>
                        <Link to={`/store/${storeId}/users/edit/${userId}`}>
                          Editar
                        </Link>
                      </Button>
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={async () => {
                          const result = await swalert.confirm(`¿Estás seguro de que deseas eliminar a ${user.name}?`, 'Esta acción no se puede deshacer.');
                          if (result.isConfirmed) {
                            try {
                              await apiClient.delete(`/users/${userId}`);
                              toast.success("Usuario eliminado", "El usuario ha sido removido de la tienda.");
                              fetchUsers();
                            } catch (error) {
                              console.error("Error deleting user:", error);
                              toast.error("Error", "No se pudo eliminar al usuario.");
                            }
                          }
                        }}
                      >
                        Eliminar
                      </Button>
                    </div>
                  </div>
                </AccordionContent>
              </AccordionItem>
            )
          })}
        </Accordion>
      </div>
    )
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold tracking-tight">Usuarios</h1>
      </div>
      <Card>
        <CardHeader>
          <CardTitle>Personal</CardTitle>
        </CardHeader>
        <CardContent>
          {renderContent()}
        </CardContent>
      </Card>
      <FloatingActionButton href={`/store/${storeId}/users/add`} />
    </div>
  );
}

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { useState } from 'react';
import { ArrowLeft, Eye, EyeOff, Save, Loader2 } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import apiClient from '@/services/api-client';

const userFormSchema = z.object({
    name: z.string().min(3, 'El nombre debe tener al menos 3 caracteres.'),
    email: z.string().email('Correo electrónico inválido.'),
    password: z.string().min(6, 'La contraseña debe tener al menos 6 caracteres.'),
    role: z.enum(['Vendedor Ambulante', 'Gestor de Ventas', 'Rutero']),
});

export default function AddVendorPage() {
    const { toast } = useToast();
    const navigate = useNavigate();
    const { storeId } = useParams<{ storeId: string }>();
    const [isSaving, setIsSaving] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    const form = useForm<z.infer<typeof userFormSchema>>({ resolver: zodResolver(userFormSchema), defaultValues: { name: '', email: '', password: '', role: 'Vendedor Ambulante' } });

    async function onSubmit(values: z.infer<typeof userFormSchema>) {
        setIsSaving(true);
        try {
            await apiClient.post('/users', { ...values, storeId });
            toast({ title: 'Vendedor Creado', description: 'Creado exitosamente.' });
            navigate(`/store/${storeId}/vendors`);
        } catch (error: any) {
            toast({ variant: 'destructive', title: 'Error', description: error?.response?.data?.message || 'No se pudo crear.' });
        } finally { setIsSaving(false); }
    }

    return (
        <div>
            <div className="mb-6"><Button variant="ghost" asChild><Link to={`/store/${storeId}/vendors`}><ArrowLeft className="mr-2" />Volver a Vendedores</Link></Button></div>
            <div className="flex justify-center">
                <Card className="w-full max-w-2xl">
                    <CardHeader><CardTitle>Agregar Nuevo Personal de Ruta</CardTitle><CardDescription>Crea un nuevo usuario para ventas en calle.</CardDescription></CardHeader>
                    <CardContent>
                        <Form {...form}><form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                            <FormField control={form.control} name="name" render={({ field }) => (<FormItem><FormLabel>Nombre Completo</FormLabel><FormControl><Input placeholder="John Doe" {...field} /></FormControl><FormMessage /></FormItem>)} />
                            <FormField control={form.control} name="email" render={({ field }) => (<FormItem><FormLabel>Correo Electrónico</FormLabel><FormControl><Input type="email" placeholder="vendedor@ejemplo.com" {...field} /></FormControl><FormMessage /></FormItem>)} />
                            <FormField control={form.control} name="password" render={({ field }) => (
                                <FormItem><FormLabel>Contraseña</FormLabel><FormControl>
                                    <div className="relative"><Input type={showPassword ? 'text' : 'password'} placeholder="••••••••" {...field} />
                                        <Button type="button" variant="ghost" size="icon" className="absolute inset-y-0 right-0 h-full px-3 py-2 hover:bg-transparent" onClick={() => setShowPassword(!showPassword)}>
                                            {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                        </Button>
                                    </div>
                                </FormControl><FormMessage /></FormItem>
                            )} />
                            <FormField control={form.control} name="role" render={({ field }) => (
                                <FormItem><FormLabel>Rol</FormLabel>
                                    <Select onValueChange={field.onChange} defaultValue={field.value}><FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                                        <SelectContent><SelectItem value="Vendedor Ambulante">Vendedor Ambulante</SelectItem><SelectItem value="Gestor de Ventas">Gestor de Ventas</SelectItem><SelectItem value="Rutero">Rutero</SelectItem></SelectContent>
                                    </Select><FormMessage /></FormItem>
                            )} />
                            <Button type="submit" className="fixed bottom-8 right-8 h-14 w-14 rounded-full shadow-lg z-50 bg-accent text-accent-foreground hover:bg-accent/90" disabled={isSaving}>
                                {isSaving ? <Loader2 className="h-5 w-5 animate-spin" /> : <Save className="h-6 w-6" />}<span className="sr-only">Guardar</span>
                            </Button>
                        </form></Form>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

import apiClient from '@/services/api-client';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { ClipboardCheck, Route, Loader2 } from 'lucide-react';
import { useEffect, useState, useMemo } from 'react';
import { useParams } from 'react-router-dom';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Button } from '@/components/ui/button';
import { toast } from '@/lib/swalert';
import { logError } from '@/lib/error-logger';
import { Checkbox } from '@/components/ui/checkbox';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useAuth } from '@/contexts/auth-context';
import { normalizeUserRole } from '@/lib/user-role';

interface DeliveryItem { id: string; description: string; quantity: number; salePrice: number; }
interface PendingDelivery { id: string; clientName: string; clientAddress?: string; salesManagerName: string; items: DeliveryItem[]; total: number; paymentType: string; status: string; createdAt: string; }
interface Rutero { uid: string; name: string; }

export default function AssignRoutePage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const { user } = useAuth();

  const [deliveries, setDeliveries] = useState<PendingDelivery[]>([]);
  const [ruteros, setRuteros] = useState<Rutero[]>([]);
  const [selectedDeliveries, setSelectedDeliveries] = useState<Record<string, boolean>>({});
  const [selectedRutero, setSelectedRutero] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);

  useEffect(() => {
    if (!storeId) return;
    const fetchData = async () => {
      try {
        const [deliveriesRes, usersRes] = await Promise.all([
          apiClient.get('/pending-deliveries', { params: { storeId, status: 'Pendiente', unassigned: true } }),
          apiClient.get('/users', { params: { storeId } }),
        ]);
        setDeliveries(deliveriesRes.data || []);
        const ruterosUsers = (usersRes.data || []).filter((u: any) => normalizeUserRole(u.role) === 'rutero');
        setRuteros(ruterosUsers.map((r: any) => ({ uid: r.id || r.uid, name: r.name })));
      } catch (err) {
        logError(err, { location: 'assign-route-fetch' });
        toast.error('Error', 'No se pudieron cargar los datos.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [storeId]);

  const selectedCount = useMemo(() => Object.values(selectedDeliveries).filter(Boolean).length, [selectedDeliveries]);

  const handleAssignRoute = async () => {
    if (!selectedRutero || selectedCount === 0 || !user) {
      toast.error('Datos incompletos', 'Debes seleccionar al menos un pedido y un rutero.');
      return;
    }
    setIsProcessing(true);
    try {
      const deliveryIds = Object.entries(selectedDeliveries).filter(([, v]) => v).map(([k]) => k);
      const ruteroData = ruteros.find(r => r.uid === selectedRutero);
      await apiClient.post('/pending-deliveries/assign-route', {
        deliveryIds,
        ruteroId: selectedRutero,
        ruteroName: ruteroData?.name,
        assignedBy: user.name,
        storeId,
      });
      toast.success('Ruta Asignada', `${selectedCount} pedidos han sido asignados a ${ruteroData?.name}.`);
      setSelectedDeliveries({});
      setSelectedRutero(null);
      
      const res = await apiClient.get('/pending-deliveries', { params: { storeId, status: 'Pendiente', unassigned: true } });
      setDeliveries(res.data || []);
    } catch (error) {
      logError(error, { location: 'assign-route-submit' });
      toast.error('Error', 'No se pudo asignar la ruta.');
    } finally {
      setIsProcessing(false);
    }
  };

  const renderContent = () => {
    if (loading) return (<div className="space-y-2">{Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-20 w-full" />)}</div>);
    if (deliveries.length === 0) return (<Alert><ClipboardCheck className="h-4 w-4" /><AlertTitle>No hay pedidos por asignar</AlertTitle><AlertDescription>Todos los pedidos ya han sido asignados.</AlertDescription></Alert>);
    return (
      <div className="space-y-2">
        {deliveries.map((delivery) => (
          <div key={delivery.id} className="flex items-center gap-4 p-3 border rounded-md has-[:checked]:bg-muted has-[:checked]:border-primary transition-all">
            <Checkbox id={`delivery-${delivery.id}`} checked={!!selectedDeliveries[delivery.id]} onCheckedChange={(checked) => { setSelectedDeliveries(prev => ({...prev, [delivery.id]: !!checked})); }} />
            <label htmlFor={`delivery-${delivery.id}`} className="flex-grow cursor-pointer select-none">
              <div className="flex items-center justify-between w-full text-left">
                <div className="flex-grow">
                  <p className="font-bold text-slate-800 uppercase text-sm tracking-tight">{delivery.clientName}</p>
                  <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Pedido por {delivery.salesManagerName} - {delivery.createdAt ? format(new Date(delivery.createdAt), 'PPP', { locale: es }) : ''}</p>
                </div>
                <div className="font-black text-lg pr-4 text-slate-900 font-mono tracking-tighter">C$ {delivery.total.toFixed(2)}</div>
              </div>
            </label>
          </div>
        ))}
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Asignar Rutas de Entrega</h1>
        <p className="text-muted-foreground">Gestión logística y despacho de pedidos</p>
      </div>
      
      <div className="grid md:grid-cols-3 gap-6 flex-grow">
        <Card className="md:col-span-2">
          <CardHeader>
            <CardTitle>
              Pedidos Pendientes de Asignación
            </CardTitle>
          </CardHeader>
          <CardContent>
            {renderContent()}
          </CardContent>
        </Card>
        
        <div className="space-y-6 flex flex-col">
          <Card className="sticky top-24">
            <CardHeader>
              <CardTitle>Asignar a Rutero</CardTitle>
              <CardDescription>{selectedCount} pedido(s) seleccionado(s).</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <div className="space-y-2">
                <label className="text-sm font-medium">Personal de Ruta</label>
                <Select onValueChange={setSelectedRutero} value={selectedRutero || ''}>
                  <SelectTrigger>
                    <SelectValue placeholder="Selecciona un rutero..." />
                  </SelectTrigger>
                  <SelectContent>
                    {ruteros.map(r => (<SelectItem key={r.uid} value={r.uid}>{r.name}</SelectItem>))}
                  </SelectContent>
                </Select>
              </div>
              
              <Button 
                className="w-full" 
                disabled={isProcessing || selectedCount === 0 || !selectedRutero} 
                onClick={handleAssignRoute}
              >
                {isProcessing ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <Route className="mr-2 h-4 w-4" />
                )}
                Confirmar Asignación
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Plus, Search, Phone, MapPin } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Skeleton } from '@/components/ui/skeleton';
import apiClient from '@/services/api-client';
import { AddClientDialog } from '@/components/pos/add-client-dialog';
import { ClientHistoryDialog } from '@/components/pos/client-history-dialog';
import { normalizeUserRole } from '@/lib/user-role';

interface Client { id: string; name: string; phone?: string; address: string; vendorId?: string; zoneId?: string; isCreditClient?: boolean; }

export default function VendorClientsPage() {
    const { storeId } = useParams<{ storeId: string }>();
    const navigate = useNavigate();
    const [clients, setClients] = useState<Client[]>([]);
    const [vendors, setVendors] = useState<Record<string, string>>({});
    const [zones, setZones] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(true);
    const [headerFilters, setHeaderFilters] = useState({ name: '', phone: '', address: '', zone: '', vendor: '' });

    const fetchData = async () => {
        if (!storeId) return;
        try {
            const [usersRes, zonesRes, clientsRes] = await Promise.all([
                apiClient.get('/users', { params: { storeId } }),
                apiClient.get('/store-zones', { params: { storeId } }),
                apiClient.get('/clients', { params: { storeId } }),
            ]);
            const vendorMap: Record<string, string> = {};
            const vendors = (usersRes.data || []).filter((u: any) => normalizeUserRole(u.role) === 'vendor');
            vendors.forEach((v: any) => { vendorMap[v.id || v.uid] = v.name; });
            setVendors(vendorMap);
            const zoneMap: Record<string, string> = {};
            (zonesRes.data || []).forEach((z: any) => { zoneMap[z.id] = z.name; });
            setZones(zoneMap);
            setClients(clientsRes.data || []);
        } catch { 
            // silent
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (!storeId) return;
        fetchData();
    }, [storeId]);

    const filteredClients = clients.filter(c => {
        const vendorName = vendors[c.vendorId || ''] || 'No asignado';
        const zoneName = zones[c.zoneId || ''] || 'Sin zona';
        
        return (
            c.name.toLowerCase().includes(headerFilters.name.toLowerCase()) &&
            (c.phone || '').toLowerCase().includes(headerFilters.phone.toLowerCase()) &&
            c.address.toLowerCase().includes(headerFilters.address.toLowerCase()) &&
            zoneName.toLowerCase().includes(headerFilters.zone.toLowerCase()) &&
            vendorName.toLowerCase().includes(headerFilters.vendor.toLowerCase())
        );
    });

    const handleClientAdded = (client: Client) => {
        setClients((prev) => [...prev, client].sort((a, b) => a.name.localeCompare(b.name)));
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div><h1 className="text-3xl font-bold tracking-tight">Gestión de Clientes</h1><p className="text-muted-foreground">Listado de clientes vinculados.</p></div>
                <div className="flex items-center gap-2">
                    <AddClientDialog onClientAdded={handleClientAdded} />
                    <Button onClick={() => navigate(`/store/${storeId}/vendors/quick-sale`)}>
                        <Plus className="mr-2 h-4 w-4" />
                        Venta rápida
                    </Button>
                </div>
            </div>
            <Card>
                <CardHeader>
                    <CardTitle>Listado de Clientes</CardTitle>
                </CardHeader>
                <CardContent><div className="rounded-md border"><Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>
                                Nombre
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.name} onChange={e => setHeaderFilters({...headerFilters, name: e.target.value})} />
                            </TableHead>
                            <TableHead>
                                Contacto
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.phone} onChange={e => setHeaderFilters({...headerFilters, phone: e.target.value})} />
                            </TableHead>
                            <TableHead>
                                Dirección
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.address} onChange={e => setHeaderFilters({...headerFilters, address: e.target.value})} />
                            </TableHead>
                            <TableHead>
                                Zona
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.zone} onChange={e => setHeaderFilters({...headerFilters, zone: e.target.value})} />
                            </TableHead>
                            <TableHead>
                                Vendedor
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.vendor} onChange={e => setHeaderFilters({...headerFilters, vendor: e.target.value})} />
                            </TableHead>
                            <TableHead className="align-top pt-4">Crédito</TableHead>
                            <TableHead className="align-top pt-4 w-24 text-center">Historial</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {loading ? (Array.from({ length: 5 }).map((_, i) => (<TableRow key={i}><TableCell><Skeleton className="h-4 w-24" /></TableCell><TableCell><Skeleton className="h-4 w-32" /></TableCell><TableCell><Skeleton className="h-4 w-48" /></TableCell><TableCell><Skeleton className="h-4 w-24" /></TableCell><TableCell><Skeleton className="h-4 w-32" /></TableCell><TableCell><Skeleton className="h-4 w-16" /></TableCell><TableCell><Skeleton className="h-6 w-16" /></TableCell></TableRow>)))
                        : filteredClients.length === 0 ? (<TableRow><TableCell colSpan={7} className="h-24 text-center">No se encontraron clientes.</TableCell></TableRow>)
                        : (filteredClients.map((client) => (
                            <TableRow key={client.id}>
                                <TableCell className="font-medium">{client.name}</TableCell>
                                <TableCell><span className="flex items-center gap-1 text-sm"><Phone className="h-3 w-3" /> {client.phone || 'N/A'}</span></TableCell>
                                <TableCell><span className="flex items-center gap-1 text-sm"><MapPin className="h-3 w-3" /> {client.address}</span></TableCell>
                                <TableCell><Badge variant="outline">{client.zoneId ? (zones[client.zoneId] || '...') : 'Sin zona'}</Badge></TableCell>
                                <TableCell><Badge variant="secondary">{client.vendorId ? (vendors[client.vendorId] || '...') : 'No asignado'}</Badge></TableCell>
                                <TableCell>{client.isCreditClient ? (<Badge className="bg-green-600">Habilitado</Badge>) : (<Badge variant="outline">Inactivo</Badge>)}</TableCell>
                                <TableCell className="text-center">
                                    <ClientHistoryDialog 
                                        storeId={storeId!} 
                                        clientId={client.id} 
                                        clientName={client.name} 
                                    />
                                </TableCell>
                            </TableRow>
                        )))}
                    </TableBody>
                </Table></div></CardContent>
            </Card>
        </div>
    );
}

import { useEffect, useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import {
  CircleDollarSign,
  HandCoins,
  Info,
  Loader2,
  Search,
  UserRound,
  Wallet,
} from 'lucide-react';

import apiClient from '@/services/api-client';
import { useAuth } from '@/contexts/auth-context';
import { useToast } from '@/hooks/use-toast';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Separator } from '@/components/ui/separator';

interface Account {
  id: string;
  clientName: string;
  pendingAmount: number;
  description?: string;
  orderId?: string;
}

type PaymentMethod = 'Efectivo' | 'Transferencia';

export default function VendorCollectionsPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { user } = useAuth();
  const { toast } = useToast();

  const [accounts, setAccounts] = useState<Account[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [selectedAccount, setSelectedAccount] = useState<Account | null>(null);
  const [paymentAmount, setPaymentAmount] = useState<string>('');
  const [paymentMethod, setPaymentMethod] =
    useState<PaymentMethod>('Efectivo');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  const fetchAccounts = async () => {
    try {
      setLoading(true);
      const res = await apiClient.get('/accounts-receivable', {
        params: { storeId, pending: true },
      });
      setAccounts(Array.isArray(res.data) ? res.data : []);
    } catch {
      toast({
        variant: 'destructive',
        title: 'Error',
        description: 'No se pudieron cargar las cuentas pendientes.',
      });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (storeId) {
      void fetchAccounts();
    }
  }, [storeId]);

  const visibleAccounts = useMemo(() => {
    const normalizedSearch = search.trim().toLowerCase();
    const sorted = [...accounts].sort(
      (a, b) => b.pendingAmount - a.pendingAmount,
    );

    if (!normalizedSearch) {
      return sorted;
    }

    return sorted.filter((account) =>
      [account.clientName, account.description, account.orderId]
        .filter(Boolean)
        .join(' ')
        .toLowerCase()
        .includes(normalizedSearch),
    );
  }, [accounts, search]);

  const totalPending = useMemo(
    () => accounts.reduce((sum, account) => sum + account.pendingAmount, 0),
    [accounts],
  );

  const largestPending = useMemo(
    () =>
      accounts.reduce(
        (max, account) => Math.max(max, account.pendingAmount),
        0,
      ),
    [accounts],
  );

  const handleCollect = (account: Account) => {
    setSelectedAccount(account);
    setPaymentAmount(account.pendingAmount.toFixed(2));
    setPaymentMethod('Efectivo');
    setIsDialogOpen(true);
  };

  const processPayment = async () => {
    if (!selectedAccount || !user || !paymentAmount) return;

    const amount = parseFloat(paymentAmount);
    if (
      Number.isNaN(amount) ||
      amount <= 0 ||
      amount > selectedAccount.pendingAmount
    ) {
      toast({
        variant: 'destructive',
        title: 'Monto inválido',
        description: 'Revisa el monto antes de registrar el cobro.',
      });
      return;
    }

    setIsProcessing(true);
    try {
      await apiClient.post(`/accounts-receivable/${selectedAccount.id}/payments`, {
        amount,
        paymentMethod,
        vendorId: user.id,
        vendorName: user.name,
      });

      toast({
        title: 'Pago registrado',
        description: `Abono de C$ ${amount.toFixed(2)} para ${selectedAccount.clientName}.`,
      });
      setIsDialogOpen(false);
      setSelectedAccount(null);
      setPaymentAmount('');
      await fetchAccounts();
    } catch {
      toast({
        variant: 'destructive',
        title: 'Error al pagar',
        description: 'No se pudo registrar el cobro.',
      });
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6">
      <section className="rounded-3xl bg-gradient-to-br from-emerald-950 via-emerald-900 to-lime-700 p-6 text-white shadow-xl">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="space-y-3">
            <div className="space-y-1">
              <h1 className="text-2xl font-bold tracking-tight">
                Cobranza en ruta
              </h1>
            </div>
          </div>

          <div className="grid gap-3 sm:grid-cols-3">
            <MetricCard
              label="Cuentas"
              value={`${accounts.length}`}
              icon={UserRound}
            />
            <MetricCard
              label="Pendiente total"
              value={`C$ ${totalPending.toFixed(2)}`}
              icon={Wallet}
            />
            <MetricCard
              label="Saldo mayor"
              value={`C$ ${largestPending.toFixed(2)}`}
              icon={CircleDollarSign}
            />
          </div>
        </div>

        <div className="mt-5">
          <div className="relative max-w-md">
            <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-white/65" />
            <Input
              value={search}
              onChange={(event) => setSearch(event.target.value)}
              placeholder="Buscar cliente o referencia..."
              className="h-12 rounded-xl border-white/20 bg-white/10 pl-11 text-white placeholder:text-white/65"
            />
          </div>
        </div>
      </section>

      <div className="grid gap-6 xl:grid-cols-[minmax(0,1fr)_320px]">
        <div className="space-y-4">
          {loading ? (
            <Card className="border-dashed">
              <CardContent className="flex min-h-40 items-center justify-center">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
              </CardContent>
            </Card>
          ) : visibleAccounts.length === 0 ? (
            <Alert className="rounded-2xl border-emerald-200 bg-emerald-50">
              <Info className="h-4 w-4" />
              <AlertTitle>Todo al día</AlertTitle>
              <AlertDescription>
                No hay cuentas pendientes para el filtro actual.
              </AlertDescription>
            </Alert>
          ) : (
            visibleAccounts.map((account) => (
              <Card
                key={account.id}
                className="overflow-hidden rounded-3xl border-slate-200 shadow-sm transition-shadow hover:shadow-md"
              >
                <CardContent className="p-0">
                  <div className="flex flex-col gap-4 p-5 lg:flex-row lg:items-center lg:justify-between">
                    <div className="space-y-3">
                      <div className="flex flex-wrap items-center gap-2">
                        <Badge variant="secondary" className="rounded-full">
                          Cuenta pendiente
                        </Badge>
                        {account.orderId ? (
                          <Badge variant="outline" className="rounded-full">
                            Pedido {account.orderId.slice(0, 8)}
                          </Badge>
                        ) : null}
                      </div>

                      <div>
                        <h2 className="text-lg font-black tracking-tight text-slate-900">
                          {account.clientName}
                        </h2>
                        <p className="mt-1 text-sm text-muted-foreground">
                          {account.description || 'Cobro pendiente por pedido o crédito registrado.'}
                        </p>
                      </div>
                    </div>

                    <div className="flex min-w-[220px] flex-col gap-3 lg:items-end">
                      <div className="rounded-2xl bg-slate-50 px-4 py-3 text-right">
                        <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">
                          Saldo pendiente
                        </p>
                        <p className="text-2xl font-black text-slate-950">
                          C$ {account.pendingAmount.toFixed(2)}
                        </p>
                      </div>

                      <Button
                        size="lg"
                        className="w-full rounded-2xl font-bold lg:w-auto"
                        onClick={() => handleCollect(account)}
                      >
                        <HandCoins className="mr-2 h-4 w-4" />
                        Cobrar ahora
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))
          )}
        </div>

      </div>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="rounded-3xl sm:max-w-xl">
          <DialogHeader>
            <DialogTitle className="text-2xl font-black tracking-tight">
              Registrar cobro
            </DialogTitle>
            <DialogDescription>
              Confirma el monto y el método para {selectedAccount?.clientName}.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-5 py-2">
            <div className="rounded-2xl border bg-slate-50 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">
                Saldo actual
              </p>
              <p className="mt-2 text-3xl font-black text-slate-950">
                C$ {selectedAccount?.pendingAmount.toFixed(2)}
              </p>
            </div>

            <div className="space-y-3">
              <Label htmlFor="paymentAmount">Monto a cobrar</Label>
              <Input
                id="paymentAmount"
                type="number"
                value={paymentAmount}
                onChange={(event) => setPaymentAmount(event.target.value)}
                className="h-14 text-xl font-bold"
              />
              <div className="flex flex-wrap gap-2">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() =>
                    setPaymentAmount(
                      selectedAccount?.pendingAmount.toFixed(2) || '',
                    )
                  }
                >
                  Saldo completo
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() =>
                    setPaymentAmount(
                      ((selectedAccount?.pendingAmount || 0) / 2).toFixed(2),
                    )
                  }
                >
                  Mitad
                </Button>
              </div>
            </div>

            <Separator />

            <div className="space-y-3">
              <Label>Método de pago</Label>
              <div className="grid gap-3 sm:grid-cols-2">
                {(['Efectivo', 'Transferencia'] as PaymentMethod[]).map(
                  (method) => (
                    <Button
                      key={method}
                      type="button"
                      variant={
                        paymentMethod === method ? 'default' : 'outline'
                      }
                      className="h-12 justify-start rounded-2xl font-semibold"
                      onClick={() => setPaymentMethod(method)}
                    >
                      {method}
                    </Button>
                  ),
                )}
              </div>
            </div>
          </div>

          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="ghost" onClick={() => setIsDialogOpen(false)}>
              Cancelar
            </Button>
            <Button onClick={processPayment} disabled={isProcessing}>
              {isProcessing ? (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ) : (
                <HandCoins className="mr-2 h-4 w-4" />
              )}
              Confirmar cobro
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function MetricCard({
  label,
  value,
  icon: Icon,
}: {
  label: string;
  value: string;
  icon: React.ElementType;
}) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/10 p-4">
      <div className="flex items-center justify-between">
        <p className="text-xs uppercase tracking-[0.18em] text-white/70">
          {label}
        </p>
        <Icon className="h-4 w-4 text-white/75" />
      </div>
      <p className="mt-3 text-2xl font-black tracking-tight text-white">
        {value}
      </p>
    </div>
  );
}

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { MapPinned, Users, CheckCircle, History, Loader2, ScrollText, Search } from "lucide-react";
import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { format, isSameDay } from "date-fns";
import { es } from "date-fns/locale";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import apiClient from '@/services/api-client';

interface Client { id: string; name: string; address: string; zoneId: string; }
interface Zone { id: string; name: string; visitDay: string; }
interface VisitLog { clientId: string; date: string; status: string; }

export default function VendorDashboardPage() {
    const [storeName, setStoreName] = useState('');
    const [loading, setLoading] = useState(true);
    const [clients, setClients] = useState<Client[]>([]);
    const [zones, setZones] = useState<Record<string, Zone>>({});
    const [visitLogs, setVisitLogs] = useState<VisitLog[]>([]);
    const [isVisitDialogOpen, setIsVisitDialogOpen] = useState(false);
    const [selectedClient, setSelectedClient] = useState<Client | null>(null);
    const [visitNotes, setVisitNotes] = useState('');
    const [isSavingVisit, setIsSavingVisit] = useState(false);
    const [todaySearch, setTodaySearch] = useState('');
    const [pendingSearch, setPendingSearch] = useState('');

    const { storeId } = useParams<{ storeId: string }>();
    const navigate = useNavigate();
    const { toast } = useToast();

    const todayDayName = format(new Date(), 'eeee', { locale: es });
    const capitalizedToday = todayDayName.charAt(0).toUpperCase() + todayDayName.slice(1);

    useEffect(() => {
        if (!storeId) return;
        const fetchData = async () => {
            try {
                const [storeRes, zonesRes, clientsRes, logsRes] = await Promise.all([
                    apiClient.get(`/stores/${storeId}`),
                    apiClient.get(`/store-zones?storeId=${storeId}`),
                    apiClient.get(`/clients?storeId=${storeId}`),
                    apiClient.get(`/visit-logs?storeId=${storeId}&days=7`),
                ]);
                setStoreName(storeRes.data?.name || 'Tienda');
                const zoneMap: Record<string, Zone> = {};
                (zonesRes.data || []).forEach((z: any) => { zoneMap[z.id] = z; });
                setZones(zoneMap);
                setClients(clientsRes.data || []);
                setVisitLogs(logsRes.data || []);
            } catch { setStoreName('Tienda'); }
            finally { setLoading(false); }
        };
        fetchData();
    }, [storeId]);

    const getVisitStatus = (clientId: string, date: Date) => visitLogs.find(log => log.clientId === clientId && isSameDay(new Date(log.date), date));

    const todayVisits = useMemo(() => {
        const filtered = clients.filter(client => {
            const zone = zones[client.zoneId];
            if (!zone) return false;
            return zone.visitDay === capitalizedToday && !getVisitStatus(client.id, new Date());
        });
        if (!todaySearch) return filtered;
        const lowSearch = todaySearch.toLowerCase();
        return filtered.filter(c => c.name.toLowerCase().includes(lowSearch) || c.address.toLowerCase().includes(lowSearch));
    }, [clients, zones, visitLogs, capitalizedToday, todaySearch]);

    const pendingVisits = useMemo(() => {
        const filtered = clients.filter(client => {
            const zone = zones[client.zoneId];
            if (!zone || zone.visitDay === 'Ninguno' || zone.visitDay === capitalizedToday) return false;
            return !visitLogs.some(log => log.clientId === client.id);
        });
        if (!pendingSearch) return filtered;
        const lowSearch = pendingSearch.toLowerCase();
        return filtered.filter(c => c.name.toLowerCase().includes(lowSearch) || c.address.toLowerCase().includes(lowSearch));
    }, [clients, zones, visitLogs, capitalizedToday, pendingSearch]);

    const handleMarkVisited = async () => {
        if (!selectedClient) return;
        setIsSavingVisit(true);
        try {
            await apiClient.post('/visit-logs', { clientId: selectedClient.id, clientName: selectedClient.name, storeId, status: 'visited_no_order', notes: visitNotes });
            toast({ title: "Visita registrada correctamente" });
            setIsVisitDialogOpen(false); setVisitNotes('');
            const res = await apiClient.get(`/visit-logs?storeId=${storeId}&days=7`);
            setVisitLogs(res.data || []);
        } catch { toast({ title: "Error al registrar visita", variant: "destructive" }); }
        finally { setIsSavingVisit(false); }
    };

    if (loading) return (<div className="flex h-[400px] items-center justify-center"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>);

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div><h1 className="text-3xl font-bold tracking-tight">Panel Comercial - {storeName}</h1><p className="text-muted-foreground capitalize">Hoy es {format(new Date(), "EEEE d 'de' MMMM", { locale: es })}</p></div>
            </div>
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Clientes de Hoy</CardTitle><MapPinned className="h-4 w-4 text-muted-foreground" /></CardHeader><CardContent><div className="text-2xl font-bold">{todayVisits.length}</div><p className="text-xs text-muted-foreground">Programados para {capitalizedToday}</p></CardContent></Card>
                <Card><CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2"><CardTitle className="text-sm font-medium">Pendientes</CardTitle><Users className="h-4 w-4 text-destructive" /></CardHeader><CardContent><div className="text-2xl font-bold">{pendingVisits.length}</div><p className="text-xs text-muted-foreground">No visitados</p></CardContent></Card>
            </div>
            <div className="grid gap-6 md:grid-cols-2">
                <Card>
                    <CardHeader>
                        <div className="flex items-center justify-between">
                            <div><CardTitle className="flex items-center gap-2"><CheckCircle className="h-5 w-5 text-green-500" />Visitas para Hoy</CardTitle><CardDescription>Clientes del {capitalizedToday}</CardDescription></div>
                            <Input placeholder="Filtrar..." className="w-32 h-8 text-xs" value={todaySearch} onChange={e => setTodaySearch(e.target.value)} />
                        </div>
                    </CardHeader>
                    <CardContent><div className="space-y-4">
                        {todayVisits.length === 0 ? (<p className="text-sm text-muted-foreground text-center py-4">No hay visitas programadas.</p>) : todayVisits.map(client => (
                            <div key={client.id} className="flex items-center justify-between p-3 border rounded-lg bg-card">
                                <div className="flex-1 min-w-0 mr-4"><p className="font-medium truncate">{client.name}</p><p className="text-xs text-muted-foreground truncate">{client.address}</p></div>
                                <div className="flex gap-2 shrink-0">
                                    <Button size="sm" variant="outline" onClick={() => { setSelectedClient(client); setIsVisitDialogOpen(true); }}>Sin Pedido</Button>
                                    <Button size="sm" onClick={() => navigate(`/store/${storeId}/vendors/quick-sale?clientId=${client.id}`)}>Vender</Button>
                                </div>
                            </div>
                        ))}
                    </div></CardContent>
                </Card>
                <Card>
                    <CardHeader>
                        <div className="flex items-center justify-between">
                            <div><CardTitle className="flex items-center gap-2"><History className="h-5 w-5 text-orange-500" />Visitas Pendientes</CardTitle><CardDescription>Clientes sin visitar esta semana</CardDescription></div>
                            <Input placeholder="Filtrar..." className="w-32 h-8 text-xs" value={pendingSearch} onChange={e => setPendingSearch(e.target.value)} />
                        </div>
                    </CardHeader>
                    <CardContent><div className="space-y-4">
                        {pendingVisits.length === 0 ? (<p className="text-sm text-muted-foreground text-center py-4">¡Buen trabajo!</p>) : pendingVisits.map(client => (
                            <div key={client.id} className="flex items-center justify-between p-3 border rounded-lg bg-destructive/5 border-destructive/20">
                                <div className="flex-1 min-w-0 mr-4"><p className="font-medium truncate">{client.name}</p>
                                    <div className="flex items-center gap-2"><Badge variant="outline" className="text-[10px] h-4">{zones[client.zoneId]?.visitDay}</Badge><p className="text-[10px] text-muted-foreground truncate">{client.address}</p></div>
                                </div>
                                <div className="flex gap-2 shrink-0">
                                    <Button size="sm" variant="outline" onClick={() => { setSelectedClient(client); setIsVisitDialogOpen(true); }}>Visitar</Button>
                                    <Button size="sm" variant="secondary" onClick={() => navigate(`/store/${storeId}/vendors/quick-sale?clientId=${client.id}`)}>Vender</Button>
                                </div>
                            </div>
                        ))}
                    </div></CardContent>
                </Card>
            </div>
            <Dialog open={isVisitDialogOpen} onOpenChange={setIsVisitDialogOpen}>
                <DialogContent>
                    <DialogHeader><DialogTitle>Registrar Visita</DialogTitle><DialogDescription>Registra la visita a <strong>{selectedClient?.name}</strong> sin pedido.</DialogDescription></DialogHeader>
                    <div className="space-y-4 py-4"><div className="space-y-2"><Label htmlFor="notes">Notas (Opcional)</Label><Textarea id="notes" value={visitNotes} onChange={(e) => setVisitNotes(e.target.value)} placeholder="Ej: No se encontraba el dueño..." /></div></div>
                    <DialogFooter>
                        <Button variant="ghost" onClick={() => setIsVisitDialogOpen(false)}>Cancelar</Button>
                        <Button onClick={handleMarkVisited} disabled={isSavingVisit}>{isSavingVisit ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <ScrollText className="mr-2 h-4 w-4" />}Confirmar Visita</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useToast } from '@/hooks/use-toast';
import { useParams } from 'react-router-dom';
import { useEffect, useState, useMemo } from 'react';
import { useAuth } from '@/contexts/auth-context';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Send, Undo2, Loader2 } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { Label } from '@/components/ui/label';
import apiClient from '@/services/api-client';
import { normalizeUserRole } from '@/lib/user-role';

interface Product { id: string; barcode?: string; description: string; currentStock: number; vendorStock?: number; }
interface Vendor { uid: string; name: string; }

export default function VendorInventoryPage() {
    const { toast } = useToast();
    const { storeId } = useParams<{ storeId: string }>();
    const { user } = useAuth();
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
    const [products, setProducts] = useState<Product[]>([]);
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [loading, setLoading] = useState(true);
    const [isProcessing, setIsProcessing] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [assignQty, setAssignQty] = useState(0);
    const [returnQty, setReturnQty] = useState(0);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [usersRes, productsRes] = await Promise.all([
                    apiClient.get('/users', { params: { storeId } }),
                    apiClient.get('/products', { params: { storeId, usesInventory: true } }),
                ]);
                const vendorUsers = (usersRes.data || []).filter((u: any) => ['vendor', 'rutero'].includes(normalizeUserRole(u.role)));
                setVendors(vendorUsers.map((v: any) => ({ uid: v.id || v.uid, name: v.name })));
                setProducts(productsRes.data || []);
            } catch { }
            finally { setLoading(false); }
        };
        fetchData();
    }, [storeId]);

    useEffect(() => {
        if (!selectedProduct || !selectedVendor) { if (selectedProduct) setSelectedProduct(prev => ({ ...prev!, vendorStock: 0 })); return; }
        apiClient.get(`/vendor-inventories/${selectedVendor.uid}/${selectedProduct.id}`)
            .then(res => setSelectedProduct(prev => ({ ...prev!, vendorStock: res.data?.quantity || 0 })))
            .catch(() => setSelectedProduct(prev => ({ ...prev!, vendorStock: 0 })));
    }, [selectedProduct?.id, selectedVendor?.uid]);

    const filteredProducts = useMemo(() => {
        if (!searchTerm) return products;
        const lc = searchTerm.toLowerCase();
        return products.filter(p => p.description.toLowerCase().includes(lc) || p.barcode?.toLowerCase().includes(lc));
    }, [products, searchTerm]);

    const handleTransaction = async (type: 'assign' | 'return', quantity: number) => {
        if (!selectedProduct || !selectedVendor || !user || quantity <= 0) { toast({ variant: 'destructive', title: 'Datos incompletos' }); return; }
        setIsProcessing(true);
        try {
            await apiClient.post('/vendor-inventories/transaction', { type, quantity, storeId, vendorId: selectedVendor.uid, vendorName: selectedVendor.name, productId: selectedProduct.id, productDescription: selectedProduct.description, cashierName: user.name });
            toast({ title: 'Transacción completada' }); setSelectedProduct(null); setAssignQty(0); setReturnQty(0);
        } catch { toast({ variant: 'destructive', title: 'Error' }); }
        finally { setIsProcessing(false); }
    };

    return (
        <div>
            <div className="mb-6"><h1 className="text-2xl font-bold tracking-tight">Inventario de Vendedores</h1><p className="text-muted-foreground">Asigna y recibe productos de tus vendedores ambulantes.</p></div>
            <div className="mb-6">
                <Select onValueChange={(id) => setSelectedVendor(vendors.find(v => v.uid === id) || null)}>
                    <SelectTrigger><SelectValue placeholder="Selecciona un vendedor..." /></SelectTrigger>
                    <SelectContent>{vendors.map(v => (<SelectItem key={v.uid} value={v.uid}>{v.name}</SelectItem>))}</SelectContent>
                </Select>
            </div>
            {selectedVendor && (
                <div className="grid md:grid-cols-2 gap-6">
                    <Card className="flex flex-col"><CardHeader><Input placeholder="Buscar producto..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></CardHeader>
                        <CardContent className="flex-grow"><ScrollArea className="h-[500px]"><div className="space-y-2">
                            {loading ? Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-12 w-full" />) : filteredProducts.map(product => (
                                <div key={product.id} onClick={() => setSelectedProduct(product)} className={`p-3 rounded-md cursor-pointer border transition-colors ${selectedProduct?.id === product.id ? 'bg-muted ring-2 ring-primary' : 'hover:bg-muted/50'}`}>
                                    <p className="font-semibold">{product.description}</p><p className="text-sm text-muted-foreground">Stock: {product.currentStock}</p>
                                </div>
                            ))}
                        </div></ScrollArea></CardContent>
                    </Card>
                    <Card>
                        <CardHeader><CardTitle>Gestionar Producto</CardTitle><CardDescription>{selectedProduct ? selectedProduct.description : 'Selecciona un producto.'}</CardDescription></CardHeader>
                        <CardContent>{selectedProduct ? (
                            <div className="space-y-6">
                                <div className="space-y-2 p-4 border rounded-md bg-muted/20">
                                    <div className="flex justify-between"><span>Stock Tienda:</span><span className="font-bold">{selectedProduct.currentStock}</span></div>
                                    <div className="flex justify-between"><span>Stock Vendedor:</span><span className="font-bold">{selectedProduct.vendorStock ?? 0}</span></div>
                                </div>
                                <Separator />
                                <div className="space-y-2"><Label>Asignar a Vendedor</Label><div className="flex gap-2"><Input type="number" value={assignQty} onChange={(e) => setAssignQty(Number(e.target.value))} /><Button disabled={isProcessing} onClick={() => handleTransaction('assign', assignQty)}><Send className="h-4 w-4" /></Button></div></div>
                                <div className="space-y-2"><Label>Recibir del Vendedor (Retorno)</Label><div className="flex gap-2"><Input type="number" value={returnQty} onChange={(e) => setReturnQty(Number(e.target.value))} /><Button variant="secondary" disabled={isProcessing} onClick={() => handleTransaction('return', returnQty)}><Undo2 className="h-4 w-4" /></Button></div></div>
                            </div>
                        ) : (<div className="flex flex-col items-center justify-center text-center text-muted-foreground h-64"><p>Selecciona un vendedor y producto.</p></div>)}</CardContent>
                    </Card>
                </div>
            )}
        </div>
    );
}

import { useCallback, useEffect, useMemo, useState, useRef } from 'react';
import { useParams, useSearchParams, Link } from 'react-router-dom';
import {
  DollarSign,
  Loader2,
  MinusCircle,
  PlusCircle,
  Search,
  ShoppingBag,
  User,
  ListOrdered,
} from 'lucide-react';

import apiClient from '@/services/api-client';
import { useAuth } from '@/contexts/auth-context';
import { useToast } from '@/hooks/use-toast';
import { AddClientDialog } from '@/components/pos/add-client-dialog';
import { ClientSelectionDialog } from '@/components/pos/client-selection-dialog';
import { Badge } from '@/components/ui/badge';
import { Client, Product as GlobalProduct } from '@/types';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Separator } from '@/components/ui/separator';

interface CartItem extends GlobalProduct {
  quantity: number;
}

const genericClient: Client = {
  id: 'generic',
  storeId: '',
  name: 'Cliente Genérico',
  phone: '',
  address: '',
  email: '',
};

export default function VendorQuickSalePage() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [settings, setSettings] = useState<{ applyVAT: boolean }>({
    applyVAT: false,
  });
  const [selectedClient, setSelectedClient] =
    useState<Client>(genericClient);
  const [paymentType, setPaymentType] = useState<'Contado' | 'Crédito'>(
    'Contado',
  );
  const [isProcessing, setIsProcessing] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [allProducts, setAllProducts] = useState<GlobalProduct[]>([]);
  const [catalogLoading, setCatalogLoading] = useState(true);
  const searchRef = useRef<HTMLInputElement>(null);

  const { storeId } = useParams<{ storeId: string }>();
  const [searchParams] = useSearchParams();
  const { user } = useAuth();
  const { toast } = useToast();
  const clientId = searchParams.get('clientId');

  // Load store settings
  useEffect(() => {
    if (!storeId) return;
    apiClient
      .get(`/stores/${storeId}`)
      .then((res) => {
        if (res.data?.settings) {
          setSettings(res.data.settings);
        }
      })
      .catch(() => {});
  }, [storeId]);

  // Load full catalog once
  useEffect(() => {
    if (!storeId) return;
    setCatalogLoading(true);
    apiClient
      .get('/products', { params: { storeId, limit: 500 } })
      .then((res) => {
        setAllProducts(Array.isArray(res.data) ? res.data : []);
      })
      .catch(() => setAllProducts([]))
      .finally(() => setCatalogLoading(false));
  }, [storeId]);

  // Load pre-selected client from URL
  useEffect(() => {
    if (!clientId) return;
    let isMounted = true;
    apiClient
      .get(`/clients/${clientId}`)
      .then((res) => {
        if (isMounted && res.data) setSelectedClient(res.data);
      })
      .catch(() => {});
    return () => { isMounted = false; };
  }, [clientId]);

  // Filter products locally (instant, no API call)
  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return allProducts;
    const term = searchTerm.toLowerCase();
    return allProducts.filter(
      (p) =>
        p.description?.toLowerCase().includes(term) ||
        p.barcode?.toLowerCase().includes(term),
    );
  }, [searchTerm, allProducts]);

  const handleAddProduct = useCallback((product: GlobalProduct) => {
    setCart((prev) => {
      const existing = prev.find((item) => item.id === product.id);
      if (existing) {
        return prev.map((item) =>
          item.id === product.id
            ? { ...item, quantity: item.quantity + 1 }
            : item,
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  }, []);

  const handleQuantityChange = (productId: string, amount: number) => {
    setCart((prev) =>
      prev
        .map((item) =>
          item.id === productId
            ? { ...item, quantity: Math.max(0, item.quantity + amount) }
            : item,
        )
        .filter((item) => item.quantity > 0),
    );
  };

  const subtotal = useMemo(
    () => cart.reduce((acc, item) => acc + (Number(item.salePrice) || 0) * item.quantity, 0),
    [cart],
  );
  const tax = useMemo(
    () => (settings.applyVAT ? subtotal * 0.15 : 0),
    [settings, subtotal],
  );
  const total = useMemo(() => subtotal + tax, [subtotal, tax]);
  const totalItems = useMemo(
    () => cart.reduce((sum, item) => sum + item.quantity, 0),
    [cart],
  );

  const resetSale = () => {
    setCart([]);
    setSelectedClient(genericClient);
    setPaymentType('Contado');
  };

  const handleFinalizeSale = async () => {
    if (!user) {
      toast({ variant: 'destructive', title: 'Error', description: 'No se pudo identificar al vendedor.' });
      return;
    }
    if (cart.length === 0) {
      toast({ variant: 'destructive', title: 'Error', description: 'Agrega al menos un producto.' });
      return;
    }

    setIsProcessing(true);
    try {
      await apiClient.post('/orders', {
        storeId,
        vendorId: user.id,
        cashierName: user.name,
        clientId: selectedClient.id !== 'generic' ? selectedClient.id : undefined,
        clientName: selectedClient.name,
        items: cart.map(({ id, description, quantity, salePrice, costPrice }) => ({
          productId: id, description, quantity, unitPrice: salePrice, costPrice: costPrice || 0,
        })),
        subtotal, tax, total, paymentType,
        status: paymentType === 'Crédito' ? 'Pendiente de Pago' : 'Pagada',
        type: 'venta_directa',
      });

      toast({ title: 'Venta registrada', description: `C$ ${total.toFixed(2)} — ${selectedClient.name}` });
      resetSale();
    } catch (error: any) {
      toast({ variant: 'destructive', title: 'Error', description: error?.response?.data?.message || 'No se pudo registrar la venta.' });
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex flex-col gap-4 h-full">
      {/* TOP BAR: cliente + pago + link a historial */}
      <div className="flex flex-wrap items-center gap-3">
        <ClientSelectionDialog
          currentClient={selectedClient}
          onSelectClient={setSelectedClient}
          trigger={
            <Button variant="outline" className="gap-2 rounded-xl">
              <User className="h-4 w-4" />
              {selectedClient.name}
            </Button>
          }
        />
        <AddClientDialog
          onClientAdded={setSelectedClient}
          trigger={<Button variant="ghost" size="sm">+ Cliente</Button>}
        />

        <div className="flex gap-1 ml-auto">
          {(['Contado', 'Crédito'] as const).map((mode) => (
            <Button
              key={mode}
              size="sm"
              variant={paymentType === mode ? 'default' : 'outline'}
              className="rounded-xl"
              onClick={() => setPaymentType(mode)}
            >
              {mode}
            </Button>
          ))}
        </div>

        <Button variant="outline" size="sm" className="gap-2 rounded-xl" asChild>
          <Link to={`/store/${storeId}/vendors/sales`}>
            <ListOrdered className="h-4 w-4" /> Historial
          </Link>
        </Button>
      </div>

      {/* MAIN BODY: catalog left + cart right */}
      <div className="flex-1 grid gap-4 xl:grid-cols-[1fr_380px] min-h-0">
        {/* CATALOG */}
        <div className="flex flex-col min-h-0 rounded-2xl border bg-white">
          <div className="p-3 border-b">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                ref={searchRef}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Filtrar productos..."
                className="h-10 rounded-xl pl-10"
              />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-3">
            {catalogLoading ? (
              <div className="flex items-center justify-center h-40">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
              </div>
            ) : filteredProducts.length === 0 ? (
              <div className="text-center text-sm text-muted-foreground py-10">
                Sin resultados.
              </div>
            ) : (
              <div className="grid gap-2 sm:grid-cols-2 lg:grid-cols-3">
                {filteredProducts.map((product) => {
                  const inCart = cart.find((c) => c.id === product.id);
                  return (
                    <button
                      key={product.id}
                      type="button"
                      onClick={() => handleAddProduct(product)}
                      className={`relative rounded-xl border p-3 text-left transition-all hover:border-primary hover:bg-primary/5 ${
                        inCart ? 'border-primary bg-primary/5' : 'bg-white'
                      }`}
                    >
                      {inCart && (
                        <Badge className="absolute -top-2 -right-2 h-6 w-6 rounded-full p-0 flex items-center justify-center text-xs">
                          {inCart.quantity}
                        </Badge>
                      )}
                      <p className="font-semibold text-sm truncate text-slate-900">
                        {product.description}
                      </p>
                      <p className="text-primary font-bold mt-1">
                        C$ {product.salePrice.toFixed(2)}
                      </p>
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        </div>

        {/* CART PANEL */}
        <div className="flex flex-col min-h-0 rounded-2xl border bg-white">
          <div className="p-3 border-b flex items-center justify-between">
            <span className="font-bold text-sm">Pedido</span>
            {cart.length > 0 && (
              <Button variant="ghost" size="sm" className="text-xs text-destructive" onClick={() => setCart([])}>
                Vaciar
              </Button>
            )}
          </div>

          <div className="flex-1 overflow-y-auto p-3 space-y-2">
            {cart.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-muted-foreground">
                <ShoppingBag className="h-10 w-10 mb-2 opacity-40" />
                <p className="text-sm">Toca un producto para agregar.</p>
              </div>
            ) : (
              cart.map((item) => (
                <div key={item.id} className="flex items-center gap-3 rounded-xl border p-3 bg-slate-50">
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-sm truncate">{item.description}</p>
                    <p className="text-xs text-muted-foreground">C$ {item.salePrice.toFixed(2)}</p>
                  </div>
                  <div className="flex items-center gap-1">
                    <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleQuantityChange(item.id, -1)}>
                      <MinusCircle className="h-4 w-4" />
                    </Button>
                    <span className="w-8 text-center font-bold text-sm">{item.quantity}</span>
                    <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleQuantityChange(item.id, 1)}>
                      <PlusCircle className="h-4 w-4" />
                    </Button>
                  </div>
                  <span className="font-bold text-sm w-20 text-right">
                    C$ {(item.salePrice * item.quantity).toFixed(2)}
                  </span>
                </div>
              ))
            )}
          </div>

          {/* FOOTER: totals + register button */}
          <div className="border-t p-3 space-y-3 bg-slate-50">
            <div className="flex justify-between text-sm">
              <span className="text-muted-foreground">Subtotal ({totalItems} items)</span>
              <span className="font-semibold">C$ {subtotal.toFixed(2)}</span>
            </div>
            {settings.applyVAT && (
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">IVA</span>
                <span className="font-semibold">C$ {tax.toFixed(2)}</span>
              </div>
            )}
            <Separator />
            <div className="flex justify-between text-lg font-black">
              <span>Total</span>
              <span>C$ {total.toFixed(2)}</span>
            </div>
            <Button
              size="lg"
              className="h-12 w-full rounded-xl font-bold"
              disabled={cart.length === 0 || isProcessing}
              onClick={handleFinalizeSale}
            >
              {isProcessing ? (
                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
              ) : (
                <DollarSign className="mr-2 h-5 w-5" />
              )}
              Registrar
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useParams } from 'react-router-dom';
import {
