  barcode?: string;
  currentQuantity: number;
  currentBulks: number;
  currentUnits: number;
  unitsPerBulk: number;
  unitPrice: number;
}

interface ReturnItem {
  productId: string;
  productName: string;
  quantityBulks: number;
  quantityUnits: number;
