  totalUnits: number;
}

export default function VendorReturnsPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { user } = useAuth();
  const { toast } = useToast();

  const [inventory, setInventory] = useState<VendorProduct[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [returnItems, setReturnItems] = useState<ReturnItem[]>([]);
  const [notes, setNotes] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isConfirmOpen, setIsConfirmOpen] = useState(false);

  const fetchInventory = useCallback(async () => {
    if (!storeId || !user?.id) return;
    try {
      setLoading(true);
      const res = await apiClient.get('/vendor-inventories', {
        params: { vendorId: user.id, storeId },
      });
      const items = (Array.isArray(res.data) ? res.data : []).filter(
        (item: any) => (Number(item.currentQuantity) || Number(item.current_quantity) || 0) > 0,
      );
      setInventory(
        items.map((item: any) => ({
          productId: item.productId || item.product_id,
          productName: item.productName || item.product_name || item.description || 'Producto',
          barcode: item.barcode,
          currentQuantity: Number(item.currentQuantity || item.current_quantity) || 0,
          currentBulks: Number(item.currentBulks || item.current_bulks) || 0,
          currentUnits: Number(item.currentUnits || item.current_units) || 0,
          unitsPerBulk: Number(item.unitsPerBulk || item.units_per_bulk) || 1,
          unitPrice: Number(item.unitPrice || item.unit_price || item.salePrice || item.sale_price) || 0,
        })),
      );
    } catch {
      toast({ variant: 'destructive', title: 'Error', description: 'No se pudo cargar tu inventario.' });
    } finally {
      setLoading(false);
    }
  }, [storeId, user?.id]);

  useEffect(() => { fetchInventory(); }, [fetchInventory]);

  const filteredInventory = useMemo(() => {
    if (!search.trim()) return inventory;
    const term = search.toLowerCase();
    return inventory.filter(
      (p) => p.productName.toLowerCase().includes(term) || p.barcode?.toLowerCase().includes(term),
    );
  }, [inventory, search]);

  const handleAddToReturn = (product: VendorProduct) => {
    if (returnItems.some((r) => r.productId === product.productId)) return;
    setReturnItems((prev) => [
      ...prev,
      {
        productId: product.productId,
        productName: product.productName,
        quantityBulks: 0,
        quantityUnits: 0,
        unitPrice: product.unitPrice,
        totalUnits: 0,
      },
    ]);
  };

  const handleUpdateReturnItem = (productId: string, field: 'quantityBulks' | 'quantityUnits', value: number) => {
    setReturnItems((prev) =>
      prev.map((item) => {
        if (item.productId !== productId) return item;
        const updated = { ...item, [field]: Math.max(0, value) };
        const invItem = inventory.find((p) => p.productId === productId);
        const unitsPerBulk = invItem?.unitsPerBulk || 1;
        updated.totalUnits = updated.quantityBulks * unitsPerBulk + updated.quantityUnits;
        // No exceder el stock del vendedor
        const maxUnits = invItem?.currentQuantity || 0;
        if (updated.totalUnits > maxUnits) {
          updated.totalUnits = maxUnits;
          updated.quantityBulks = Math.floor(maxUnits / unitsPerBulk);
          updated.quantityUnits = maxUnits % unitsPerBulk;
        }
        return updated;
      }),
    );
  };

  const handleRemoveFromReturn = (productId: string) => {
    setReturnItems((prev) => prev.filter((r) => r.productId !== productId));
  };

  const validReturnItems = useMemo(() => returnItems.filter((r) => r.totalUnits > 0), [returnItems]);
  const totalReturnValue = useMemo(
    () => validReturnItems.reduce((sum, item) => sum + item.totalUnits * item.unitPrice, 0),
    [validReturnItems],
  );

  const handleSubmitReturn = async () => {
    if (!user || validReturnItems.length === 0) return;
    setIsProcessing(true);
    try {
      await apiClient.post('/returns', {
        storeId,
        ruteroId: user.id,
        notes: notes || `Devolución de mercancía por ${user.name}`,
        items: validReturnItems.map((item) => ({
          productId: item.productId,
          quantityBulks: item.quantityBulks,
          quantityUnits: item.quantityUnits,
          unitPrice: item.unitPrice,
        })),
      });
      toast({ title: 'Devolución registrada', description: `${validReturnItems.length} producto(s) devueltos a bodega. Total: C$ ${totalReturnValue.toFixed(2)}` });
      setReturnItems([]);
      setNotes('');
      setIsConfirmOpen(false);
      await fetchInventory();
    } catch (err: any) {
      toast({ variant: 'destructive', title: 'Error', description: err?.response?.data?.message || 'No se pudo registrar la devolución.' });
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* HEADER */}
      <section className="rounded-3xl bg-gradient-to-br from-orange-950 via-orange-900 to-amber-700 p-6 text-white shadow-xl">
        <div className="flex flex-col gap-6 xl:flex-row xl:items-end xl:justify-between">
          <div className="space-y-3">
            <Badge className="w-fit border border-white/20 bg-white/10 text-white hover:bg-white/10">
              Devolución de mercancía
            </Badge>
            <div className="space-y-2">
              <h1 className="text-3xl font-black tracking-tight">Devolver productos a bodega</h1>
              <p className="max-w-2xl text-sm text-orange-50/85">
                Selecciona los productos de tu inventario que deseas devolver. El stock será 
                transferido automáticamente de vuelta a la bodega central.
              </p>
            </div>
          </div>
          <div className="grid gap-3 sm:grid-cols-2">
            <div className="rounded-2xl border border-white/10 bg-white/10 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-white/70">Productos en mano</p>
              <p className="mt-3 text-2xl font-black tracking-tight text-white">{inventory.length}</p>
            </div>
            <div className="rounded-2xl border border-white/10 bg-white/10 p-4">
              <p className="text-xs uppercase tracking-[0.18em] text-white/70">Para devolver</p>
              <p className="mt-3 text-2xl font-black tracking-tight text-white">{validReturnItems.length}</p>
            </div>
          </div>
        </div>
        <div className="mt-5">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-white/65" />
            <Input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar producto por nombre o código..."
              className="h-12 rounded-2xl border-white/10 bg-white/10 pl-11 text-white placeholder:text-white/65"
            />
          </div>
        </div>
      </section>

      {/* BODY */}
      <div className="grid gap-6 xl:grid-cols-[minmax(0,1fr)_380px]">
        {/* INVENTORY LIST */}
        <div className="space-y-3">
          {loading ? (
            <Card className="border-dashed"><CardContent className="flex min-h-40 items-center justify-center"><Loader2 className="h-6 w-6 animate-spin text-primary" /></CardContent></Card>
          ) : filteredInventory.length === 0 ? (
            <Alert className="rounded-2xl">
              <Package className="h-4 w-4" />
              <AlertTitle>Sin inventario</AlertTitle>
              <AlertDescription>No tienes productos asignados con stock disponible.</AlertDescription>
            </Alert>
          ) : (
            filteredInventory.map((product) => {
              const inReturn = returnItems.find((r) => r.productId === product.productId);
              return (
                <Card
                  key={product.productId}
                  className={`overflow-hidden rounded-2xl transition-all ${inReturn ? 'border-orange-400 bg-orange-50/30' : 'hover:shadow-md'}`}
                >
                  <CardContent className="p-0">
                    <div className="flex flex-col gap-4 p-5 lg:flex-row lg:items-center lg:justify-between">
                      <div className="space-y-1 flex-grow">
                        <h3 className="font-bold text-slate-900">{product.productName}</h3>
                        <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
                          <Badge variant="outline" className="rounded-full text-xs">
                            {product.currentBulks} bultos + {product.currentUnits} uds
                          </Badge>
                          <span>({product.currentQuantity} uds total)</span>
                          {product.barcode && <span className="text-xs text-slate-400">| {product.barcode}</span>}
                        </div>
                      </div>

                      {inReturn ? (
                        <div className="flex items-center gap-3 flex-wrap">
                          <div className="flex items-center gap-2">
                            <Label className="text-xs font-bold">Bultos:</Label>
                            <div className="flex items-center gap-1">
                              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleUpdateReturnItem(product.productId, 'quantityBulks', inReturn.quantityBulks - 1)}>
                                <MinusCircle className="h-4 w-4" />
                              </Button>
                              <span className="w-8 text-center font-bold">{inReturn.quantityBulks}</span>
                              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleUpdateReturnItem(product.productId, 'quantityBulks', inReturn.quantityBulks + 1)}>
                                <PlusCircle className="h-4 w-4" />
                              </Button>
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <Label className="text-xs font-bold">Uds:</Label>
                            <div className="flex items-center gap-1">
                              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleUpdateReturnItem(product.productId, 'quantityUnits', inReturn.quantityUnits - 1)}>
                                <MinusCircle className="h-4 w-4" />
                              </Button>
                              <span className="w-8 text-center font-bold">{inReturn.quantityUnits}</span>
                              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleUpdateReturnItem(product.productId, 'quantityUnits', inReturn.quantityUnits + 1)}>
                                <PlusCircle className="h-4 w-4" />
                              </Button>
                            </div>
                          </div>
                          <Badge variant="secondary" className="font-bold">{inReturn.totalUnits} uds</Badge>
                          <Button variant="ghost" size="sm" className="text-destructive" onClick={() => handleRemoveFromReturn(product.productId)}>Quitar</Button>
                        </div>
                      ) : (
                        <Button variant="outline" className="rounded-xl font-bold gap-2" onClick={() => handleAddToReturn(product)}>
                          <Undo2 className="h-4 w-4" /> Devolver
                        </Button>
                      )}
                    </div>
                  </CardContent>
                </Card>
              );
            })
          )}
        </div>

        {/* SUMMARY PANEL */}
        <Card className="sticky top-24 rounded-3xl border-slate-200 bg-white shadow-xl h-fit">
          <CardHeader>
            <CardTitle className="text-xl font-black tracking-tight text-slate-900">Resumen de devolución</CardTitle>
            <CardDescription>{validReturnItems.length} producto(s) seleccionados</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {validReturnItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center text-center text-muted-foreground py-8">
                <ArrowLeftRight className="h-10 w-10 mb-3 opacity-30" />
                <p className="text-sm">Selecciona productos y ajusta las cantidades a devolver.</p>
              </div>
            ) : (
              <>
                <div className="space-y-2">
                  {validReturnItems.map((item) => (
                    <div key={item.productId} className="flex justify-between text-sm border-b pb-2">
                      <span className="font-medium truncate max-w-[200px]">{item.productName}</span>
                      <span className="font-bold whitespace-nowrap">x{item.totalUnits} = C$ {(item.totalUnits * item.unitPrice).toFixed(2)}</span>
                    </div>
                  ))}
                </div>
                <Separator />
                <div className="flex justify-between text-lg font-black">
                  <span>Total</span>
                  <span>C$ {totalReturnValue.toFixed(2)}</span>
                </div>
              </>
            )}

            <div className="space-y-2">
              <Label className="text-xs font-bold uppercase tracking-wide text-slate-400">Notas (opcional)</Label>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Ej: Producto dañado, sobrante del día..."
                className="rounded-xl"
              />
            </div>

            <Button
              size="lg"
              className="w-full h-14 rounded-2xl bg-orange-600 hover:bg-orange-700 text-white font-black uppercase tracking-widest shadow-lg transition-all active:scale-95 disabled:bg-slate-100 disabled:text-slate-300"
              disabled={validReturnItems.length === 0 || isProcessing}
              onClick={() => setIsConfirmOpen(true)}
            >
              <Undo2 className="mr-2 h-5 w-5" />
              Confirmar devolución
            </Button>
          </CardContent>
        </Card>
      </div>

      {/* CONFIRMATION DIALOG */}
      <Dialog open={isConfirmOpen} onOpenChange={setIsConfirmOpen}>
        <DialogContent className="rounded-3xl sm:max-w-md">
          <DialogHeader>
            <DialogTitle className="text-2xl font-black tracking-tight">¿Confirmar devolución?</DialogTitle>
            <DialogDescription>
              Esta acción devolverá {validReturnItems.length} producto(s) al inventario de bodega y reducirá tu stock personal.
            </DialogDescription>
          </DialogHeader>
          <div className="rounded-2xl border bg-orange-50 p-4 space-y-2">
            <div className="flex justify-between">
              <span className="text-sm text-muted-foreground">Productos</span>
              <span className="font-bold">{validReturnItems.length}</span>
            </div>
            <div className="flex justify-between">
              <span className="text-sm text-muted-foreground">Valor total</span>
              <span className="font-black text-xl">C$ {totalReturnValue.toFixed(2)}</span>
            </div>
          </div>
          <Alert className="rounded-xl">
            <AlertTriangle className="h-4 w-4" />
            <AlertTitle>Acción irreversible</AlertTitle>
            <AlertDescription>Los productos regresarán a bodega y se registrará en el Kardex.</AlertDescription>
          </Alert>
          <DialogFooter className="gap-2">
            <Button variant="ghost" onClick={() => setIsConfirmOpen(false)}>Cancelar</Button>
            <Button className="bg-orange-600 hover:bg-orange-700" onClick={handleSubmitReturn} disabled={isProcessing}>
              {isProcessing ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Check className="mr-2 h-4 w-4" />}
              Sí, devolver
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import apiClient from '@/services/api-client';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { Checkbox } from '@/components/ui/checkbox';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { CalendarIcon, Loader2, Save, Users, Route, ClipboardCheck, Truck, MapPin } from 'lucide-react';
import { cn } from '@/lib/utils';
import { normalizeUserRole } from '@/lib/user-role';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { toast } from '@/lib/swalert';
import { useParams } from 'react-router-dom';
import { useEffect, useState, useMemo } from 'react';
import { logError } from '@/lib/error-logger';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { useAuth } from '@/contexts/auth-context';

// ── Schema for visit planning ──
const routeFormSchema = z.object({
  vendorId: z.string().min(1, 'Debes seleccionar un vendedor.'),
  date: z.date(),
  clientIds: z.array(z.string()).min(1, 'Tienes que seleccionar al menos un cliente.'),
});

interface Vendor { uid: string; name: string; }
interface Client { id: string; name: string; }
interface DeliveryItem { id: string; description: string; quantity: number; salePrice: number; }
interface PendingDelivery { id: string; clientName: string; clientAddress?: string; salesManagerName: string; items: DeliveryItem[]; total: number; paymentType: string; status: string; createdAt: string; }

export default function VendorRoutesPage() {
  const params = useParams();
  const storeId = params.storeId as string;
  const { user } = useAuth();

  // ── Shared state ──
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [ruteros, setRuteros] = useState<Vendor[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [loading, setLoading] = useState(true);

  // ── Tab 1: Plan Visits ──
  const [isSaving, setIsSaving] = useState(false);
  const form = useForm<z.infer<typeof routeFormSchema>>({
    resolver: zodResolver(routeFormSchema),
    defaultValues: { date: new Date(), clientIds: [] },
  });

  // ── Tab 2: Dispatch ──
  const [deliveries, setDeliveries] = useState<PendingDelivery[]>([]);
  const [selectedDeliveries, setSelectedDeliveries] = useState<Record<string, boolean>>({});
  const [selectedRutero, setSelectedRutero] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [deliveryLoading, setDeliveryLoading] = useState(true);

  // ── Fetch shared data ──
  useEffect(() => {
    if (!storeId) return;
    const fetchData = async () => {
      try {
        const [usersRes, clientsRes] = await Promise.all([
          apiClient.get('/users', { params: { storeId } }),
          apiClient.get('/clients', { params: { storeId } }),
        ]);
        const allUsers = usersRes.data || [];
        const vendorUsers = allUsers.filter((u: any) => ['vendor', 'rutero'].includes(normalizeUserRole(u.role)));
        setVendors(vendorUsers.map((v: any) => ({ uid: v.id || v.uid, name: v.name })));
        const ruterosOnly = allUsers.filter((u: any) => normalizeUserRole(u.role) === 'rutero');
        setRuteros(ruterosOnly.map((r: any) => ({ uid: r.id || r.uid, name: r.name })));
        setClients((clientsRes.data || []).map((c: any) => ({ id: c.id, name: c.name })));
      } catch (err) {
        logError(err, { location: 'vendor-routes-fetch', additionalInfo: { storeId } });
        toast.error('Error', 'No se pudieron cargar los datos.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [storeId]);

  // ── Fetch pending deliveries for dispatch tab ──
  const fetchDeliveries = async () => {
    setDeliveryLoading(true);
    try {
      const res = await apiClient.get('/pending-deliveries', { params: { storeId, status: 'Pendiente', unassigned: true } });
      setDeliveries(res.data || []);
    } catch (err) {
      logError(err, { location: 'dispatch-fetch' });
    } finally {
      setDeliveryLoading(false);
    }
  };

  useEffect(() => {
    if (storeId) fetchDeliveries();
  }, [storeId]);

  // ── Tab 1: Submit visit plan ──
  async function onSubmitVisitPlan(values: z.infer<typeof routeFormSchema>) {
    setIsSaving(true);
    try {
      await apiClient.post('/routes', { ...values, storeId, status: 'pending' });
      toast.success('Ruta Creada', 'La ruta ha sido asignada y el vendedor notificado.');
      form.reset({ date: new Date(), clientIds: [] });
    } catch (error) {
      logError(error, { location: 'vendor-routes-submit', additionalInfo: { ...values } });
      toast.error('Error', 'No se pudo crear la ruta.');
    } finally {
      setIsSaving(false);
    }
  }

  // ── Tab 2: Assign deliveries to rutero ──
  const selectedCount = useMemo(() => Object.values(selectedDeliveries).filter(Boolean).length, [selectedDeliveries]);

  const handleAssignRoute = async () => {
    if (!selectedRutero || selectedCount === 0 || !user) {
      toast.error('Datos incompletos', 'Debes seleccionar al menos un pedido y un rutero.');
      return;
    }
    setIsProcessing(true);
    try {
      const deliveryIds = Object.entries(selectedDeliveries).filter(([, v]) => v).map(([k]) => k);
      const ruteroData = ruteros.find(r => r.uid === selectedRutero);
      await apiClient.post('/pending-deliveries/assign-route', {
        deliveryIds,
        ruteroId: selectedRutero,
        ruteroName: ruteroData?.name,
        assignedBy: user.name,
        storeId,
      });
      toast.success('Ruta Asignada', `${selectedCount} pedidos han sido asignados a ${ruteroData?.name}.`);
      setSelectedDeliveries({});
      setSelectedRutero(null);
      fetchDeliveries();
    } catch (error) {
      logError(error, { location: 'assign-route-submit' });
      toast.error('Error', 'No se pudo asignar la ruta.');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold tracking-tight">Rutas y Despacho</h1>
        <p className="text-muted-foreground">Planifica visitas de vendedores y asigna entregas a ruteros.</p>
      </div>

      <Tabs defaultValue="visits" className="w-full">
        <TabsList>
          <TabsTrigger value="visits" className="gap-2">
            <MapPin className="h-4 w-4" />
            Planear Visitas
          </TabsTrigger>
          <TabsTrigger value="dispatch" className="gap-2">
            <Truck className="h-4 w-4" />
            Despacho ({deliveries.length})
          </TabsTrigger>
        </TabsList>

        {/* ═══════════════════════ TAB 1: PLAN VISITS ═══════════════════════ */}
        <TabsContent value="visits" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Asignar Visitas del Día</CardTitle>
              <CardDescription>
                Selecciona un vendedor, fecha y los clientes que debe visitar.
              </CardDescription>
            </CardHeader>
            <CardContent className="p-6">
              <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmitVisitPlan)} className="space-y-8">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <FormField control={form.control} name="vendorId" render={({ field }) => (
                      <FormItem>
                        <FormLabel>Vendedor</FormLabel>
                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                          <FormControl>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecciona un vendedor" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {vendors.map((v) => (<SelectItem key={v.uid} value={v.uid}>{v.name}</SelectItem>))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )} />

                    <FormField control={form.control} name="date" render={({ field }) => (
                      <FormItem className="flex flex-col">
                        <FormLabel>Fecha</FormLabel>
                        <Popover>
                          <PopoverTrigger asChild>
                            <FormControl>
                              <Button variant={'outline'} className={cn('pl-3 text-left font-normal', !field.value && 'text-muted-foreground')}>
                                {field.value ? format(field.value, 'PPP', { locale: es }) : <span>Selecciona una fecha</span>}
                                <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                              </Button>
                            </FormControl>
                          </PopoverTrigger>
                          <PopoverContent className="w-auto p-0" align="start">
                            <Calendar mode="single" selected={field.value} onSelect={field.onChange} initialFocus locale={es} />
                          </PopoverContent>
                        </Popover>
                        <FormMessage />
                      </FormItem>
                    )} />
                  </div>

                  <FormField control={form.control} name="clientIds" render={() => (
                    <FormItem className="space-y-3">
                      <FormLabel className="text-base font-semibold flex items-center gap-2">
                        <Users className="h-4 w-4" />
                        Seleccionar Clientes ({form.watch('clientIds').length})
                      </FormLabel>
                      <FormControl>
                        <ScrollArea className="h-[300px] w-full rounded-lg border p-4">
                          {loading ? (
                            <div className="space-y-3">
                              {[...Array(5)].map((_, i) => <Skeleton key={i} className="h-12 w-full" />)}
                            </div>
                          ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                              {clients.map((client) => (
                                <FormField key={client.id} control={form.control} name="clientIds" render={({ field }) => (
                                  <FormItem key={client.id} className="flex flex-row items-center space-x-3 space-y-0 p-3 border rounded-lg bg-white hover:bg-muted/50 transition-colors cursor-pointer">
                                    <FormControl>
                                      <Checkbox
                                        checked={field.value?.includes(client.id)}
                                        onCheckedChange={(checked) => {
                                          return checked ? field.onChange([...(field.value || []), client.id]) : field.onChange(field.value?.filter((value) => value !== client.id));
                                        }}
                                      />
                                    </FormControl>
                                    <FormLabel className="font-medium cursor-pointer">{client.name}</FormLabel>
                                  </FormItem>
                                )} />
                              ))}
                            </div>
                          )}
                        </ScrollArea>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )} />

                  <div className="flex justify-end">
                    <Button type="submit" disabled={isSaving}>
                      {isSaving ? (
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      ) : (
                        <Save className="h-4 w-4 mr-2" />
                      )}
                      {isSaving ? 'Guardando...' : 'Crear Ruta'}
                    </Button>
                  </div>
                </form>
              </Form>
            </CardContent>
          </Card>
        </TabsContent>

        {/* ═══════════════════════ TAB 2: DISPATCH ═══════════════════════ */}
        <TabsContent value="dispatch" className="mt-4">
          <div className="grid md:grid-cols-3 gap-6">
            <Card className="md:col-span-2">
              <CardHeader>
                <CardTitle>Pedidos Pendientes de Entrega</CardTitle>
                <CardDescription>
                  Selecciona los pedidos que deseas asignar a un rutero para su entrega.
                </CardDescription>
              </CardHeader>
              <CardContent>
                {deliveryLoading ? (
                  <div className="space-y-2">
                    {Array.from({ length: 3 }).map((_, i) => <Skeleton key={i} className="h-16 w-full" />)}
                  </div>
                ) : deliveries.length === 0 ? (
                  <Alert>
                    <ClipboardCheck className="h-4 w-4" />
                    <AlertTitle>Sin pedidos pendientes</AlertTitle>
                    <AlertDescription>Todos los pedidos ya han sido asignados a un rutero.</AlertDescription>
                  </Alert>
                ) : (
                  <div className="space-y-2">
                    {deliveries.map((delivery) => (
                      <div key={delivery.id} className="flex items-center gap-4 p-3 border rounded-lg has-[:checked]:bg-muted has-[:checked]:border-primary transition-all">
                        <Checkbox
                          id={`delivery-${delivery.id}`}
                          checked={!!selectedDeliveries[delivery.id]}
                          onCheckedChange={(checked) => { setSelectedDeliveries(prev => ({ ...prev, [delivery.id]: !!checked })); }}
                        />
                        <label htmlFor={`delivery-${delivery.id}`} className="flex-grow cursor-pointer select-none">
                          <div className="flex items-center justify-between w-full text-left">
                            <div className="flex-grow">
                              <p className="font-semibold text-sm">{delivery.clientName}</p>
                              <p className="text-xs text-muted-foreground mt-0.5">
                                Pedido por {delivery.salesManagerName} — {delivery.createdAt ? format(new Date(delivery.createdAt), 'PPP', { locale: es }) : ''}
                              </p>
                            </div>
                            <div className="font-bold text-base pr-2 font-mono">C$ {delivery.total.toFixed(2)}</div>
                          </div>
                        </label>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>

            <Card className="sticky top-24 h-fit">
              <CardHeader>
                <CardTitle>Asignar a Rutero</CardTitle>
                <CardDescription>{selectedCount} pedido(s) seleccionado(s).</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium">Rutero</label>
                  <Select onValueChange={setSelectedRutero} value={selectedRutero || ''}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecciona un rutero..." />
                    </SelectTrigger>
                    <SelectContent>
                      {ruteros.map(r => (<SelectItem key={r.uid} value={r.uid}>{r.name}</SelectItem>))}
                    </SelectContent>
                  </Select>
                </div>
                <Button
                  className="w-full"
                  disabled={isProcessing || selectedCount === 0 || !selectedRutero}
                  onClick={handleAssignRoute}
                >
                  {isProcessing ? (
                    <Loader2 className="h-4 w-4 animate-spin mr-2" />
                  ) : (
                    <Route className="mr-2 h-4 w-4" />
                  )}
                  Confirmar Asignación
                </Button>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useAuth } from '@/contexts/auth-context';
import { useToast } from '@/hooks/use-toast';
import apiClient from '@/services/api-client';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Loader2, ArrowLeft, Eye, XCircle, Edit3, Search, Plus, Download } from 'lucide-react';
import { format } from 'date-fns';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Separator } from '@/components/ui/separator';
import { exportToExcel } from '@/lib/export-excel';

interface OrderItem {
  id: string;
  productId: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  subtotal: number;
}

interface Order {
  id: string;
  clientName: string;
  total: number;
  status: string;
  paymentType?: string;
  createdAt: string;
  items?: OrderItem[];
}

const statusColor: Record<string, string> = {
  RECIBIDO: 'bg-blue-100 text-blue-800',
  EN_PREPARACION: 'bg-amber-100 text-amber-800',
  ALISTADO: 'bg-sky-100 text-sky-800',
  CARGADO_CAMION: 'bg-emerald-100 text-emerald-800',
  EN_ENTREGA: 'bg-violet-100 text-violet-800',
  ENTREGADO: 'bg-green-100 text-green-800',
  CANCELADO: 'bg-red-100 text-red-800',
  Pagada: 'bg-emerald-100 text-emerald-800',
  'Pendiente de Pago': 'bg-amber-100 text-amber-800',
};

const statusLabel: Record<string, string> = {
  RECIBIDO: 'Recibido',
  EN_PREPARACION: 'Preparando',
  ALISTADO: 'Listo',
  CARGADO_CAMION: 'Cargado',
  EN_ENTREGA: 'En ruta',
  ENTREGADO: 'Entregado',
  CANCELADO: 'Cancelado',
  Pagada: 'Pagada',
  'Pendiente de Pago': 'Pendiente',
};

// Statuses the vendor can still cancel
const CANCELLABLE = ['RECIBIDO', 'EN_PREPARACION', 'Pendiente de Pago'];
// Statuses the vendor can still edit quantities
const EDITABLE = ['RECIBIDO'];

export default function VendorSalesPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { user } = useAuth();
  const { toast } = useToast();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [catalog, setCatalog] = useState<any[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [headerFilters, setHeaderFilters] = useState({ client: '', dateFrom: '', dateTo: '', status: '', payment: '' });

  // Detail dialog
  const [detailOrder, setDetailOrder] = useState<Order | null>(null);
  const [detailLoading, setDetailLoading] = useState(false);

  // Cancel dialog
  const [cancelOrderId, setCancelOrderId] = useState<string | null>(null);
  const [cancelLoading, setCancelLoading] = useState(false);

  // Edit mode
  const [editMode, setEditMode] = useState(false);
  const [editItems, setEditItems] = useState<OrderItem[]>([]);
  const [editSaving, setEditSaving] = useState(false);

  const fetchOrders = () => {
    if (!storeId || !user?.id) return;
    setLoading(true);
    apiClient
      .get('/orders', { params: { storeId, vendorId: user.id } })
      .then((res) => setOrders(Array.isArray(res.data) ? res.data : []))
      .catch(() => setOrders([]))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchOrders();
    if (storeId) {
      apiClient.get('/products', { params: { storeId, limit: 500 } })
        .then(res => setCatalog(Array.isArray(res.data) ? res.data : []))
        .catch(() => {});
    }
  }, [storeId, user?.id]);

  // OPEN DETAIL
  const handleViewDetail = async (order: Order) => {
    setDetailLoading(true);
    setEditMode(false);
    try {
      const res = await apiClient.get(`/orders/${order.id}`);
      setDetailOrder(res.data);
      setEditItems(res.data.items || []);
      setSearchQuery('');
    } catch {
      setDetailOrder({ ...order, items: [] });
      setEditItems([]);
      setSearchQuery('');
    } finally {
      setDetailLoading(false);
    }
  };

  // CANCEL ORDER
  const handleCancelOrder = async () => {
    if (!cancelOrderId) return;
    setCancelLoading(true);
    try {
      await apiClient.patch(`/orders/${cancelOrderId}/status`, {
        status: 'CANCELADO',
        updatedBy: user?.id,
      });
      toast({ title: 'Pedido cancelado' });
      setDetailOrder(null);
      setCancelOrderId(null);
      fetchOrders();
    } catch (err: any) {
      toast({
        variant: 'destructive',
        title: 'Error',
        description: err?.response?.data?.message || 'No se pudo cancelar.',
      });
    } finally {
      setCancelLoading(false);
    }
  };

  // EDIT: Change quantity locally
  const handleEditQty = (itemId: string, delta: number) => {
    setEditItems((prev) =>
      prev
        .map((it) =>
          it.id === itemId
            ? {
                ...it,
                quantity: Math.max(0, it.quantity + delta),
                subtotal: Math.max(0, it.quantity + delta) * it.unitPrice,
              }
            : it,
        )
        .filter((it) => it.quantity > 0),
    );
  };

  // EDIT: Add a totally new product to replacing order
  const handleAddNewProduct = (prod: any) => {
    const exists = editItems.find((i) => i.productId === prod.id);
    if (!exists) {
      const p = parseFloat(prod.salePrice || prod.price1 || 0);
      setEditItems([...editItems, {
        id: 'new-' + prod.id,
        productId: prod.id,
        productName: prod.description,
        quantity: 1,
        unitPrice: p,
        subtotal: p
      }]);
    } else {
      handleEditQty(exists.id, 1);
    }
    setSearchQuery('');
  };

  const filteredCatalog = searchQuery
    ? catalog.filter(p => p.description?.toLowerCase().includes(searchQuery.toLowerCase()) || p.barcode?.includes(searchQuery)).slice(0, 5)
    : [];

  // SAVE EDIT — re-create order (cancel old + create new)
  const handleSaveEdit = async () => {
    if (!detailOrder || editItems.length === 0) return;
    setEditSaving(true);
    try {
      // Cancel old
      await apiClient.patch(`/orders/${detailOrder.id}/status`, {
        status: 'CANCELADO',
        updatedBy: user?.id,
      });

      // Create replacement
      const newTotal = editItems.reduce((s, i) => s + i.subtotal, 0);
      await apiClient.post('/orders', {
        storeId,
        vendorId: user?.id,
        cashierName: user?.name,
        clientId: (detailOrder as any).clientId || undefined,
        clientName: detailOrder.clientName,
        items: editItems.map((i) => ({
          productId: i.productId,
          description: i.productName,
          quantity: i.quantity,
          unitPrice: i.unitPrice,
          costPrice: 0,
        })),
        subtotal: newTotal,
        tax: 0,
        total: newTotal,
        paymentType: detailOrder.paymentType || 'CONTADO',
        status: 'RECIBIDO',
        type: 'venta_directa',
      });

      toast({ title: 'Pedido actualizado' });
      setDetailOrder(null);
      setEditMode(false);
      fetchOrders();
    } catch (err: any) {
      toast({
        variant: 'destructive',
        title: 'Error',
        description:
          err?.response?.data?.message || 'No se pudo editar el pedido.',
      });
    } finally {
      setEditSaving(false);
    }
  };

  const totalVentas = orders
    .filter((o) => o.status !== 'CANCELADO')
    .reduce((sum, o) => sum + Number(o.total || 0), 0);

  const editTotal = editItems.reduce((s, i) => s + i.subtotal, 0);

  const filteredOrders = orders.filter((o) => {
    const fClient = headerFilters.client.toLowerCase();
    const fStatus = headerFilters.status.toLowerCase();
    const fPayment = headerFilters.payment.toLowerCase();
    const createdStr = format(new Date(o.createdAt), 'yyyy-MM-dd');
    const matchesFrom = headerFilters.dateFrom ? createdStr >= headerFilters.dateFrom : true;
    const matchesTo = headerFilters.dateTo ? createdStr <= headerFilters.dateTo : true;

    return (
      (o.clientName?.toLowerCase() || 'genérico').includes(fClient) &&
      (statusLabel[o.status] || o.status).toLowerCase().includes(fStatus) &&
      (o.paymentType?.toLowerCase() || '').includes(fPayment) &&
      matchesFrom && matchesTo
    );
  });

  return (
    <div className="space-y-4">
      {/* HEADER */}
      <div className="flex items-center gap-3 flex-wrap">
        <Button variant="ghost" size="sm" asChild>
          <Link to={`/store/${storeId}/vendors/quick-sale`}>
            <ArrowLeft className="h-4 w-4 mr-1" /> Venta rápida
          </Link>
        </Button>
        <h1 className="text-xl font-bold">Mis ventas</h1>
        <Badge variant="secondary" className="ml-auto">
          {orders.filter((o) => o.status !== 'CANCELADO').length} pedidos — C${' '}
          {totalVentas.toFixed(2)}
        </Badge>
        <Button
          variant="outline"
          size="sm"
          disabled={orders.length === 0}
          onClick={() => {
            const rows = orders.filter(o => o.status !== 'CANCELADO').map(o => ({
              'Cliente': o.clientName || 'Genérico',
              'Fecha': format(new Date(o.createdAt), 'dd/MM/yyyy HH:mm'),
              'Estado': statusLabel[o.status] || o.status,
              'Pago': o.paymentType || '—',
              'Total (C$)': Number(o.total).toFixed(2),
            }));
            exportToExcel(rows, `Mis_Ventas_${format(new Date(), 'dd-MM-yyyy')}`, 'Ventas');
          }}
        >
          <Download className="h-4 w-4 mr-1" />
          Excel
        </Button>
      </div>

      {/* TABLE */}
      {loading ? (
        <div className="flex justify-center py-16">
          <Loader2 className="h-6 w-6 animate-spin text-primary" />
        </div>
      ) : orders.length === 0 ? (
        <div className="text-center text-muted-foreground py-16">
          No hay ventas registradas aún.
        </div>
      ) : (
        <div className="rounded-xl border overflow-hidden">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>
                  Cliente
                  <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.client} onChange={e => setHeaderFilters({...headerFilters, client: e.target.value})} />
                </TableHead>
                <TableHead>
                  Fecha
                  <div className="flex flex-col gap-1 mt-1">
                    <Input type="date" className="h-6 text-xs p-1 font-normal w-full" value={headerFilters.dateFrom} onChange={e => setHeaderFilters({...headerFilters, dateFrom: e.target.value})} title="Desde" />
                    <Input type="date" className="h-6 text-xs p-1 font-normal w-full" value={headerFilters.dateTo} onChange={e => setHeaderFilters({...headerFilters, dateTo: e.target.value})} title="Hasta" />
                  </div>
                </TableHead>
                <TableHead>
                  Estado
                  <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.status} onChange={e => setHeaderFilters({...headerFilters, status: e.target.value})} />
                </TableHead>
                <TableHead>
                  Pago
                  <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.payment} onChange={e => setHeaderFilters({...headerFilters, payment: e.target.value})} />
                </TableHead>
                <TableHead className="text-right align-top pt-4">Total</TableHead>
                <TableHead className="w-24 text-center align-top pt-4">Acciones</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredOrders.map((order) => (
                <TableRow key={order.id}>
                  <TableCell className="font-medium">
                    {order.clientName || 'Genérico'}
                  </TableCell>
                  <TableCell className="text-sm text-muted-foreground">
                    {format(new Date(order.createdAt), 'dd/MM HH:mm')}
                  </TableCell>
                  <TableCell>
                    <Badge
                      className={`text-xs ${statusColor[order.status] || 'bg-slate-100 text-slate-800'}`}
                    >
                      {statusLabel[order.status] || order.status}
                    </Badge>
                  </TableCell>
                  <TableCell className="text-sm">
                    {order.paymentType || '—'}
                  </TableCell>
                  <TableCell className="text-right font-bold">
                    C$ {Number(order.total).toFixed(2)}
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center justify-center gap-1">
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                        title="Ver detalle"
                        onClick={() => handleViewDetail(order)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      {CANCELLABLE.includes(order.status) && (
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-8 w-8 text-destructive"
                          title="Cancelar"
                          onClick={() => setCancelOrderId(order.id)}
                        >
                          <XCircle className="h-4 w-4" />
                        </Button>
                      )}
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}

      {/* ─── DETAIL DIALOG ─── */}
      <Dialog
        open={!!detailOrder}
        onOpenChange={(open) => {
          if (!open) {
            setDetailOrder(null);
            setEditMode(false);
          }
        }}
      >
        <DialogContent className="max-w-lg">
          <DialogHeader>
            <div className="flex items-center justify-between gap-2">
              <DialogTitle>
                {detailOrder?.clientName || 'Pedido'}
              </DialogTitle>
              {detailOrder && (
                <Badge
                  className={`text-xs ${statusColor[detailOrder.status] || ''}`}
                >
                  {statusLabel[detailOrder.status] || detailOrder.status}
                </Badge>
              )}
            </div>
            <p className="text-xs text-muted-foreground">
              {detailOrder &&
                format(new Date(detailOrder.createdAt), 'dd/MM/yyyy HH:mm')}{' '}
              · {detailOrder?.paymentType}
            </p>
          </DialogHeader>

          {detailLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-5 w-5 animate-spin" />
            </div>
          ) : (
            <div className="space-y-4">
              {/* ITEMS TABLE */}
              {(editMode ? editItems : detailOrder?.items || []).length > 0 ? (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Producto</TableHead>
                      <TableHead className="text-right">Precio</TableHead>
                      <TableHead className="text-center w-24">
                        Cant.
                      </TableHead>
                      <TableHead className="text-right">Subtotal</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {(editMode ? editItems : detailOrder?.items || []).map(
                      (item) => (
                        <TableRow key={item.id || item.productId}>
                          <TableCell className="text-sm font-medium">
                            {item.productName}
                          </TableCell>
                          <TableCell className="text-right text-muted-foreground">
                            C$ {Number(item.unitPrice).toFixed(2)}
                          </TableCell>
                          <TableCell className="text-center">
                            {editMode ? (
                              <div className="flex items-center justify-center gap-1">
                                <Button
                                  variant="outline"
                                  size="icon"
                                  className="h-7 w-7"
                                  onClick={() =>
                                    handleEditQty(item.id, -1)
                                  }
                                >
                                  -
                                </Button>
                                <Input
                                  value={item.quantity}
                                  readOnly
                                  className="h-7 w-12 text-center text-sm"
                                />
                                <Button
                                  variant="outline"
                                  size="icon"
                                  className="h-7 w-7"
                                  onClick={() =>
                                    handleEditQty(item.id, 1)
                                  }
                                >
                                  +
                                </Button>
                              </div>
                            ) : (
                              item.quantity
                            )}
                          </TableCell>
                          <TableCell className="text-right font-medium">
                            C${' '}
                            {(editMode
                              ? item.subtotal
                              : item.unitPrice * item.quantity
                            ).toFixed(2)}
                          </TableCell>
                        </TableRow>
                      ),
                    )}
                  </TableBody>
                </Table>
              ) : (
                <p className="text-muted-foreground text-sm py-4">
                  Sin detalle de productos.
                </p>
              )}

              {/* PRODUCT SEARCH FOR EDIT MODE */}
              {editMode && (
                <div className="bg-muted/30 p-3 rounded-md mt-2 space-y-2 border">
                  <div className="relative">
                    <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Buscar producto para agregar..."
                      className="pl-8 bg-background"
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                    />
                  </div>
                  {searchQuery && filteredCatalog.length > 0 && (
                    <div className="flex flex-col gap-1 border bg-background rounded-md shadow-sm overflow-hidden">
                      {filteredCatalog.map(p => (
                        <div key={p.id} className="flex justify-between items-center p-2 hover:bg-muted cursor-pointer text-sm" onClick={() => handleAddNewProduct(p)}>
                          <div>
                            <p className="font-medium">{p.description}</p>
                            <p className="text-xs text-muted-foreground">C$ {parseFloat(p.salePrice || p.price1 || 0).toFixed(2)}</p>
                          </div>
                          <Button size="icon" variant="ghost" className="h-6 w-6"><Plus className="h-4 w-4"/></Button>
                        </div>
                      ))}
                    </div>
                  )}
                  {searchQuery && filteredCatalog.length === 0 && (
                    <p className="text-xs text-muted-foreground text-center py-2 bg-background border rounded-md">No se encontraron productos.</p>
                  )}
                </div>
              )}

              <Separator />

              {/* TOTAL */}
              <div className="flex justify-between font-bold text-lg">
                <span>Total</span>
                <span>
                  C${' '}
                  {editMode
                    ? editTotal.toFixed(2)
                    : Number(detailOrder?.total || 0).toFixed(2)}
                </span>
              </div>
            </div>
          )}

          {/* FOOTER ACTIONS */}
          {detailOrder && !detailLoading && (
            <DialogFooter className="flex-col sm:flex-row gap-2">
              {editMode ? (
                <>
                  <Button
                    variant="ghost"
                    onClick={() => {
                      setEditMode(false);
                      setEditItems(detailOrder.items || []);
                    }}
                  >
                    Cancelar edición
                  </Button>
                  <Button
                    onClick={handleSaveEdit}
                    disabled={editSaving || editItems.length === 0}
                  >
                    {editSaving && (
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    )}
                    Guardar cambios
                  </Button>
                </>
              ) : (
                <>
                  {EDITABLE.includes(detailOrder.status) && (
                    <Button
                      variant="outline"
                      className="gap-2"
                      onClick={() => setEditMode(true)}
                    >
                      <Edit3 className="h-4 w-4" /> Editar
                    </Button>
                  )}
                  {CANCELLABLE.includes(detailOrder.status) && (
                    <Button
                      variant="destructive"
                      className="gap-2"
                      onClick={() => setCancelOrderId(detailOrder.id)}
                    >
                      <XCircle className="h-4 w-4" /> Cancelar pedido
                    </Button>
                  )}
                </>
              )}
            </DialogFooter>
          )}
        </DialogContent>
      </Dialog>

      {/* ─── CANCEL CONFIRMATION ─── */}
      <AlertDialog
        open={!!cancelOrderId}
        onOpenChange={(open) => !open && setCancelOrderId(null)}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>¿Cancelar este pedido?</AlertDialogTitle>
            <AlertDialogDescription>
              El pedido pasará a estado "Cancelado" y no se podrá revertir.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={cancelLoading}>
              Volver
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleCancelOrder}
              disabled={cancelLoading}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {cancelLoading && (
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              )}
              Sí, cancelar
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardHeader, CardTitle, CardContent, CardDescription } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { useToast } from '@/hooks/use-toast';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogDescription } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { useParams } from 'react-router-dom';
import { Map, Plus, Edit2, Trash2, Loader2 } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import apiClient from '@/services/api-client';

interface StoreZone { id: string; name: string; description?: string; storeId: string; visitDay?: string; }
const VISIT_DAYS = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo', 'Mensual', 'Ninguno'];

export default function VendorZonesPage() {
    const { storeId } = useParams<{ storeId: string }>();
    const [zones, setZones] = useState<StoreZone[]>([]);
    const [loading, setLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [headerFilters, setHeaderFilters] = useState({ name: '', visitDay: '' });
    const [currentZone, setCurrentZone] = useState<Partial<StoreZone>>({});
    const { toast } = useToast();

    const fetchZones = async () => { try { const res = await apiClient.get(`/store-zones?storeId=${storeId}`); setZones(res.data || []); } catch { } finally { setLoading(false); } };
    useEffect(() => { if (storeId) fetchZones(); }, [storeId]);

    const handleSave = async () => {
        if (!currentZone.name) { toast({ title: "El nombre es obligatorio", variant: "destructive" }); return; }
        setIsSaving(true);
        try {
            const payload = { name: currentZone.name, description: currentZone.description || '', visitDay: currentZone.visitDay || 'Ninguno', storeId };
            if (currentZone.id) { await apiClient.patch(`/store-zones/${currentZone.id}`, payload); toast({ title: "Zona actualizada" }); }
            else { await apiClient.post('/store-zones', payload); toast({ title: "Zona creada" }); }
            setIsDialogOpen(false); setCurrentZone({}); fetchZones();
        } catch { toast({ title: "Error al guardar", variant: "destructive" }); }
        finally { setIsSaving(false); }
    };

    const handleDelete = async (id: string) => { if (!confirm("¿Eliminar zona?")) return; try { await apiClient.delete(`/store-zones/${id}`); toast({ title: "Zona eliminada" }); fetchZones(); } catch { toast({ title: "Error", variant: "destructive" }); } };

    if (loading) return (<div className="flex h-[400px] items-center justify-center"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>);

    const filteredZones = zones.filter((z) => {
        const fName = headerFilters.name.toLowerCase();
        const fVisit = headerFilters.visitDay.toLowerCase();
        return (z.name.toLowerCase().includes(fName) && (z.visitDay || 'ninguno').toLowerCase().includes(fVisit));
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div><h1 className="text-3xl font-bold tracking-tight">Gestión de Zonas</h1><p className="text-muted-foreground">Crea y administra zonas para clientes.</p></div>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild><Button onClick={() => setCurrentZone({})}><Plus className="mr-2 h-4 w-4" />Nueva Zona</Button></DialogTrigger>
                    <DialogContent>
                        <DialogHeader><DialogTitle>{currentZone.id ? 'Editar Zona' : 'Nueva Zona'}</DialogTitle><DialogDescription>Ingresa los detalles.</DialogDescription></DialogHeader>
                        <div className="space-y-4 py-4">
                            <div className="space-y-2"><Label>Nombre</Label><Input value={currentZone.name || ''} onChange={(e) => setCurrentZone({ ...currentZone, name: e.target.value })} placeholder="Ej: Zona Norte" /></div>
                            <div className="space-y-2"><Label>Descripción</Label><Input value={currentZone.description || ''} onChange={(e) => setCurrentZone({ ...currentZone, description: e.target.value })} /></div>
                            <div className="space-y-2"><Label>Día de Visita</Label>
                                <Select value={currentZone.visitDay || 'Ninguno'} onValueChange={(v) => setCurrentZone({ ...currentZone, visitDay: v })}>
                                    <SelectTrigger><SelectValue /></SelectTrigger>
                                    <SelectContent>{VISIT_DAYS.map((d) => (<SelectItem key={d} value={d}>{d}</SelectItem>))}</SelectContent>
                                </Select>
                            </div>
                            <Button onClick={handleSave} className="w-full" disabled={isSaving}>{isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Plus className="mr-2 h-4 w-4" />}{currentZone.id ? 'Actualizar' : 'Guardar'}</Button>
                        </div>
                    </DialogContent>
                </Dialog>
            </div>
            <Card>
                <CardHeader><CardTitle>Zonas Configuradas</CardTitle><CardDescription>Listado de zonas.</CardDescription></CardHeader>
                <CardContent><div className="overflow-x-auto"><Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>
                                Nombre
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.name} onChange={e => setHeaderFilters({...headerFilters, name: e.target.value})} />
                            </TableHead>
                            <TableHead className="align-top pt-4">Descripción</TableHead>
                            <TableHead>
                                Día de Visita
                                <Input placeholder="Filtrar..." className="h-6 mt-1 text-xs font-normal" value={headerFilters.visitDay} onChange={e => setHeaderFilters({...headerFilters, visitDay: e.target.value})} />
                            </TableHead>
                            <TableHead className="text-right align-top pt-4">Acciones</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {filteredZones.map((zone) => (<TableRow key={zone.id}>
                            <TableCell className="font-medium"><div className="flex items-center gap-2"><Map className="h-4 w-4 text-muted-foreground" />{zone.name}</div></TableCell>
                            <TableCell>{zone.description || 'Sin descripción'}</TableCell>
                            <TableCell><Badge variant="outline" className={zone.visitDay && zone.visitDay !== 'Ninguno' ? 'bg-primary/10 text-primary border-primary/20' : ''}>{zone.visitDay || 'No definido'}</Badge></TableCell>
                            <TableCell className="text-right space-x-2">
                                <Button variant="ghost" size="icon" onClick={() => { setCurrentZone(zone); setIsDialogOpen(true); }}><Edit2 className="h-4 w-4" /></Button>
                                <Button variant="ghost" size="icon" onClick={() => handleDelete(zone.id)} className="text-destructive hover:text-destructive hover:bg-destructive/10"><Trash2 className="h-4 w-4" /></Button>
                            </TableCell>
                        </TableRow>))}
                        {zones.length === 0 && (<TableRow><TableCell colSpan={4} className="text-center py-8 text-muted-foreground">No has creado ninguna zona todavía.</TableCell></TableRow>)}
                    </TableBody>
                </Table></div></CardContent>
            </Card>
        </div>
    );
}

import { FloatingActionButton } from "@/components/floating-action-button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { UsersRound } from "lucide-react";
import { useEffect, useState } from "react";
import { Skeleton } from "@/components/ui/skeleton";
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Badge } from "@/components/ui/badge";
import { useParams } from "react-router-dom";
import apiClient from '@/services/api-client';
import { normalizeUserRole } from '@/lib/user-role';

interface User { uid: string; name: string; email: string; role: string; }

export default function VendorsPage() {
    const { storeId } = useParams<{ storeId: string }>();
    const [vendors, setVendors] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!storeId) return;
        const fetchVendors = async () => {
            try {
                const res = await apiClient.get('/users', { params: { storeId } });
                const routeStaff = (res.data || []).filter((u: any) => {
                    const role = normalizeUserRole(u.role);
                    return role === 'vendor' || role === 'sales-manager' || role === 'rutero';
                });
                setVendors(routeStaff.map((u: any) => ({ uid: u.id || u.uid, name: u.name, email: u.email, role: u.role })));
            } catch (err) { setError("No se pudieron cargar los vendedores."); }
            finally { setLoading(false); }
        };
        fetchVendors();
    }, [storeId]);

    const renderContent = () => {
        if (loading) return (<div className="space-y-2">{Array.from({ length: 3 }).map((_, i) => (<Skeleton key={i} className="h-12 w-full" />))}</div>);
        if (error) return (<Alert variant="destructive"><UsersRound className="h-4 w-4" /><AlertTitle>Error</AlertTitle><AlertDescription>{error}</AlertDescription></Alert>);
        if (vendors.length === 0) return (<Alert><UsersRound className="h-4 w-4" /><AlertTitle>No hay vendedores</AlertTitle><AlertDescription>Aún no has agregado ningún vendedor.</AlertDescription></Alert>);
        return (
            <div className="rounded-md border">
                <Accordion type="single" collapsible className="w-full">
                    {vendors.map((vendor) => (
                        <AccordionItem value={vendor.uid} key={vendor.uid}>
                            <AccordionTrigger className="px-6 py-4 hover:no-underline">
                                <div className="flex items-center justify-between w-full"><span className="font-medium text-left">{vendor.name}</span><Badge variant="outline">{vendor.role}</Badge></div>
                            </AccordionTrigger>
                            <AccordionContent className="px-6 pb-4 bg-muted/50"><p className="text-sm"><strong>Correo:</strong> {vendor.email}</p></AccordionContent>
                        </AccordionItem>
                    ))}
                </Accordion>
            </div>
        );
    };

    return (
        <div>
            <div className="flex items-center justify-between mb-6">
                <div><h1 className="text-2xl font-bold tracking-tight">Gestión de Personal de Ruta</h1><p className="text-muted-foreground">Administra los vendedores, gestores de venta y ruteros.</p></div>
            </div>
            <Card><CardHeader><CardTitle>Lista de Personal</CardTitle><CardDescription>Administra el acceso del personal de ruta.</CardDescription></CardHeader><CardContent>{renderContent()}</CardContent></Card>
            <FloatingActionButton href={`/store/${storeId}/vendors/add`} />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import apiClient from '@/services/api-client';
import { User as UserType } from '@/types';
import { useRealTimeEvents } from '@/hooks/use-real-time-events';
import { ArrowRight, PackageOpen, Truck, CheckCircle2, User } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { format } from 'date-fns';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';

interface OrderItem {
  id: string;
  productId: string;
  productName: string;
  quantity: number;
  unitsPerBulk?: number;
  presentation?: string;
}

interface Order {
  id: string;
  clientName: string;
  vendorId?: string;
  vendorName?: string;
  total: number;
  status: string;
  createdAt: string;
}

interface OrderDetail extends Order {
  items: OrderItem[];
}

export default function WarehouseDashboardPage() {
  const { storeId } = useParams<{ storeId: string }>();
  const { toast } = useToast();
  const { lastEvent } = useRealTimeEvents(storeId);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  // Modals state
  const [pickingOrder, setPickingOrder] = useState<OrderDetail | null>(null);
  const [loadingModal, setLoadingModal] = useState(false);
  
  const [loadingOrder, setLoadingOrder] = useState<Order | null>(null);
  const [vendors, setVendors] = useState<UserType[]>([]);
  const [selectedVendorId, setSelectedVendorId] = useState<string>('');

  const fetchOrders = async () => {
    try {
      setLoading(true);
      // Fetch multiple status: we omit purely finalized ones to keep the board clean, or fetch all mapped.
      const res = await apiClient.get('/orders', { params: { storeId, limit: 100 } });
      const activeStates = ['RECIBIDO', 'EN_PREPARACION', 'ALISTADO', 'CARGADO_CAMION'];
      setOrders((res.data || []).filter((o: Order) => activeStates.includes(o.status)));
    } catch (err) {
      toast({ variant: 'destructive', title: 'Error', description: 'No se pudieron cargar los pedidos de bodega.' });
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (storeId) {
      fetchOrders();
      const interval = setInterval(fetchOrders, 15000); // Polling as backup for real-time
      return () => clearInterval(interval);
    }
  }, [storeId]);

  useEffect(() => {
    if (lastEvent && lastEvent.type !== 'PING') {
      fetchOrders();
    }
  }, [lastEvent]);

  const updateOrderStatus = async (id: string, status: string, additionalPayload: any = {}) => {
    try {
      await apiClient.patch(`/orders/${id}/status`, { status, ...additionalPayload });
      toast({ title: 'Éxito', description: `Pedido movido a ${status}` });
      fetchOrders();
      return true;
    } catch (err: any) {
      const msg = err.response?.data?.message || 'Error al actualizar el estado.';
      toast({ variant: 'destructive', title: 'Error', description: msg });
      return false;
    }
  };

  const handleStartPrep = (orderId: string) => updateOrderStatus(orderId, 'EN_PREPARACION');

  const handleOpenPicking = async (order: Order) => {
    try {
      setLoadingModal(true);
      const res = await apiClient.get(`/orders/${order.id}`);
      setPickingOrder(res.data);
    } catch (err) {
      toast({ variant: 'destructive', title: 'Error', description: 'Error al cargar detalle del pedido.' });
    } finally {
      setLoadingModal(false);
    }
  };

  const handleFinishPicking = async () => {
    if (!pickingOrder) return;
    const success = await updateOrderStatus(pickingOrder.id, 'ALISTADO');
    if (success) setPickingOrder(null);
  };

  const handleOpenLoading = async (order: Order) => {
    setLoadingOrder(order);
    setSelectedVendorId(order.vendorId || ''); // Prefill if already assigned
    // Fetch users for selector
    try {
      const usersRes = await apiClient.get('/users', { params: { storeId } });
      const ruterUsers = (usersRes.data || []).filter((u: UserType) => u.role === 'rutero' || u.role === 'vendor' || u.role === 'store-admin');
      setVendors(ruterUsers);
    } catch (err) {
      console.error(err);
    }
  };

  const handleFinishLoading = async () => {
    if (!loadingOrder) return;
    if (!selectedVendorId) {
      toast({ variant: 'destructive', title: 'Error', description: 'Debes seleccionar un vendedor o camión.' });
      return;
    }
    const success = await updateOrderStatus(loadingOrder.id, 'CARGADO_CAMION', { vendorId: selectedVendorId });
    if (success) setLoadingOrder(null);
  };

  const renderColumn = (title: string, status: string, icon: React.ReactNode, colorClass: string) => {
    const colOrders = orders.filter(o => o.status === status);
    return (
      <div className="flex flex-col flex-1 bg-muted/30 rounded-lg p-4 min-w-[300px]">
        <div className="flex items-center gap-2 mb-4">
          <div className={`p-2 rounded-full ${colorClass}`}>
            {icon}
          </div>
          <h2 className="font-bold text-lg">{title}</h2>
          <Badge variant="secondary" className="ml-auto">{colOrders.length}</Badge>
        </div>
        <div className="flex flex-col gap-3 overflow-y-auto max-h-[70vh] pr-2">
          {colOrders.map(order => (
            <Card key={order.id} className="shadow-sm hover:shadow-md transition-shadow">
              <CardHeader className="p-4 pb-2">
                <div className="flex justify-between items-start">
                  <div>
                    <CardTitle className="text-base font-semibold truncate max-w-[150px]" title={order.clientName}>{order.clientName}</CardTitle>
                    <p className="text-xs text-muted-foreground mt-1">ID: {order.id.slice(0, 8)}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-bold text-primary">C$ {Number(order.total).toFixed(2)}</p>
                    <p className="text-[10px] text-muted-foreground">{format(new Date(order.createdAt), 'HH:mm')}</p>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="p-4 pt-0">
                 {order.vendorName && (
                    <div className="flex items-center gap-1 mt-2 text-xs text-muted-foreground bg-muted p-1 rounded">
                      <User className="h-3 w-3" /> {order.vendorName}
                    </div>
                 )}
              </CardContent>
              <CardFooter className="p-3 pt-0 flex justify-end gap-2 bg-muted/10 border-t">
                {status === 'RECIBIDO' && (
                  <Button size="sm" className="w-full font-bold" onClick={() => handleStartPrep(order.id)}>
                    Preparar <ArrowRight className="ml-2 h-4 w-4" />
                  </Button>
                )}
                {status === 'EN_PREPARACION' && (
                  <Button size="sm" variant="secondary" className="w-full font-bold text-blue-700 bg-blue-100 hover:bg-blue-200" onClick={() => handleOpenPicking(order)}>
                    <PackageOpen className="mr-2 h-4 w-4" /> Picking List
                  </Button>
                )}
                {status === 'ALISTADO' && (
                  <Button size="sm" className="w-full font-bold text-emerald-700 bg-emerald-100 hover:bg-emerald-200" onClick={() => handleOpenLoading(order)}>
                    <Truck className="mr-2 h-4 w-4" /> Cargar Camión
                  </Button>
                )}
                {status === 'CARGADO_CAMION' && (
                  <Button size="sm" variant="ghost" disabled className="w-full font-bold text-muted-foreground">
                    <CheckCircle2 className="mr-2 h-4 w-4 text-green-500" /> Cargado
                  </Button>
                )}
              </CardFooter>
            </Card>
          ))}
          {colOrders.length === 0 && (
            <div className="text-center text-muted-foreground py-8 border-2 border-dashed rounded-lg bg-background">
              No hay pedidos
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="h-full flex flex-col">
      <div className="mb-6 flex justify-between items-center">
        <h1 className="text-2xl font-bold tracking-tight">Bodega</h1>
        <Button onClick={fetchOrders} variant="outline" className="gap-2">
          <ArrowRight className="h-4 w-4 rotate-180" /> Actualizar
        </Button>
      </div>

      {loading && orders.length === 0 ? (
        <div className="flex-1 flex justify-center items-center">
          <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full" />
        </div>
      ) : (
        <div className="flex flex-1 gap-4 overflow-x-auto pb-4">
            {renderColumn('Nuevos', 'RECIBIDO', <ArrowRight className="h-5 w-5 text-amber-600" />, 'bg-amber-100 text-amber-700 border border-amber-200')}
            {renderColumn('Picking', 'EN_PREPARACION', <PackageOpen className="h-5 w-5 text-blue-600" />, 'bg-blue-100 text-blue-700 border border-blue-200')}
            {renderColumn('Listo', 'ALISTADO', <CheckCircle2 className="h-5 w-5 text-emerald-600" />, 'bg-emerald-100 text-emerald-700 border border-emerald-200')}
            {renderColumn('Despachado', 'CARGADO_CAMION', <Truck className="h-5 w-5 text-gray-600" />, 'bg-gray-100 text-gray-700 border border-gray-200')}
        </div>
      )}

      {/* MODAL DE PICKING LIST CON BULTOS Y UNIDADES */}
      <Dialog open={!!pickingOrder} onOpenChange={(open) => !open && setPickingOrder(null)}>
        <DialogContent className="max-w-3xl">
          <DialogHeader>
            <DialogTitle className="text-xl flex items-center gap-2">
              <PackageOpen className="h-6 w-6 text-primary" />
              Picking List - Orden {pickingOrder?.id.slice(0, 8)}
            </DialogTitle>
            <DialogDescription>
              Cliente: <span className="font-bold text-foreground">{pickingOrder?.clientName}</span>
            </DialogDescription>
          </DialogHeader>
          
          <div className="max-h-[50vh] overflow-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Producto</TableHead>
                  <TableHead className="text-center bg-muted/50 rounded-tl-md">Cant. Solicitada</TableHead>
                  <TableHead className="text-center font-bold text-primary bg-primary/10">📦 Bultos Cerrados</TableHead>
                  <TableHead className="text-center font-bold text-primary bg-primary/10 rounded-tr-md">🧩 Unidades Sueltas</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {pickingOrder?.items.map(item => {
                  const upb = item.unitsPerBulk || 1;
                  const bulks = Math.floor(item.quantity / upb);
                  const units = item.quantity % upb;

                  return (
                    <TableRow key={item.id} className="text-base">
                      <TableCell>
                        <p className="font-semibold">{item.productName}</p>
                        <p className="text-xs text-muted-foreground">{item.presentation || 'Sin presentación'} | Caja de {upb}</p>
                      </TableCell>
                      <TableCell className="text-center">{item.quantity} u.</TableCell>
                      <TableCell className="text-center text-lg font-black">{bulks}</TableCell>
                      <TableCell className="text-center text-lg font-black">{units}</TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </div>

          <DialogFooter className="mt-6 border-t pt-4">
            <Button variant="outline" onClick={() => setPickingOrder(null)}>Cancelar</Button>
            <Button onClick={handleFinishPicking} className="gap-2">
              <CheckCircle2 className="h-4 w-4" /> Marcar Todo Alineado y Listo
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* MODAL DE CARGA A CAMIÓN (ASIGNACIÓN DE VENDEDOR) */}
      <Dialog open={!!loadingOrder} onOpenChange={(open) => !open && setLoadingOrder(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Truck className="h-5 w-5 text-emerald-600" /> Confirmar Carga al Camión
            </DialogTitle>
            <DialogDescription>
              Este paso descontará el inventario de la bodega y lo sumará al vehículo seleccionado.
            </DialogDescription>
          </DialogHeader>

          <div className="py-6">
            <label className="text-sm font-medium mb-2 block">
              Selecciona el Vendedor / Conductor responsable:
            </label>
            <Select value={selectedVendorId} onValueChange={setSelectedVendorId}>
              <SelectTrigger className="w-full h-12 text-lg">
                <SelectValue placeholder="Seleccionar rutero activo..." />
              </SelectTrigger>
              <SelectContent>
                {vendors.map(v => (
                  <SelectItem key={v.id} value={v.id}>
                    {v.name} ({v.role})
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <div className="mt-6 p-4 bg-emerald-50 text-emerald-900 border border-emerald-200 rounded-lg text-sm">
               ⚠️ <strong>Aviso:</strong> Confirmar esta acción generará un registro de transferencia formal (`INVENTORY_TRANSFER`). Una vez cargado el camión, las mermas o cambios son responsabilidad del vendedor.
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setLoadingOrder(null)}>Cancelar</Button>
            <Button onClick={handleFinishLoading} disabled={!selectedVendorId} className="bg-emerald-600 hover:bg-emerald-700 text-white gap-2">
              <Truck className="h-4 w-4" /> Cargar e Iniciar Ruta
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import axios from 'axios';
import { API_BASE_URL, withAppBase } from '@/lib/runtime-config';

const apiClient = axios.create({
  baseURL: API_BASE_URL,
});

// CACHE EN MEMORIA PARA MÁXIMA VELOCIDAD
const memoryCache = new Map<string, { data: any; timestamp: number }>();
const CACHE_TTL = 5000; // 5 segundos para invalidación rápida

// Interceptor para incluir el token JWT en cada petición
apiClient.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  
  // Si la petición es un GET y está en caché, la interceptamos después
  return config;
});

// Interceptor para manejar errores globales y CACHÉ
apiClient.interceptors.response.use(
  (response) => {
    // Solo cacheamos peticiones GET exitosas
    if (response.config.method === 'get') {
      const cacheKey = `${response.config.url}${JSON.stringify(response.config.params || {})}`;
      memoryCache.set(cacheKey, {
        data: response.data,
        timestamp: Date.now()
      });
    }
    return response;
  },
  (error) => {
    if (error.response?.status === 401) {
      localStorage.clear();
      window.location.assign(withAppBase('/login'));
    }
    return Promise.reject(error);
  }
);

// Wrapper para inyectar caché antes de la petición real
const originalGet = apiClient.get;
apiClient.get = async function (url, config) {
  const cacheKey = `${url}${JSON.stringify(config?.params || {})}`;
  const cached = memoryCache.get(cacheKey);
  
  if (cached && (Date.now() - cached.timestamp < CACHE_TTL)) {
    return { data: cached.data } as any;
  }
  
  return originalGet.call(this, url, config);
};

export const clearCache = () => memoryCache.clear();

export default apiClient;

import { jsPDF } from 'jspdf';
import { format } from 'date-fns';

interface TicketData {
  id: string;
  items: any[];
  total: number;
  subtotal: number;
  discount: number;
  clientName?: string;
  cashierName: string;
  storeName: string;
  paymentMethod: string;
  amountReceived: number;
  change: number;
  settings?: any;
}

export class TicketService {
  static async generateAndPrint(data: TicketData) {
    const { settings = {} } = data;
    const doc = new jsPDF({
      unit: 'mm',
      format: [80, 200], // Ancho estándar térmica 80mm
    });

    const margin = 5;
    let y = 10;
    const pageWidth = doc.internal.pageSize.width;
    const centerX = pageWidth / 2;

    // Configuración de Fuente
    doc.setFont(settings.fontFamily || 'Courier', settings.useBoldFont ? 'bold' : 'normal');
    const fontSize = settings.fontSize || 10;
    doc.setFontSize(fontSize);

    // --- ENCABEZADO ---
    doc.text(settings.headerLine1 || data.storeName.toUpperCase(), centerX, y, { align: 'center' });
    y += 5;
    if (settings.headerLine2) {
      doc.setFontSize(fontSize - 2);
      doc.text(settings.headerLine2, centerX, y, { align: 'center' });
      y += 4;
    }
    y += 2;
    doc.text('--------------------------------', centerX, y, { align: 'center' });
    y += 5;

    // --- INFO VENTA ---
    doc.setFontSize(fontSize - 1);
    doc.text(`TICKET: #${data.id}`, margin, y);
    y += 4;
    doc.text(`FECHA: ${format(new Date(), 'dd/MM/yyyy HH:mm')}`, margin, y);
    y += 4;
    doc.text(`CAJERO: ${data.cashierName.toUpperCase()}`, margin, y);
    y += 4;
    if (data.clientName) {
      doc.text(`CLIENTE: ${data.clientName.toUpperCase()}`, margin, y);
      y += 4;
    }
    y += 2;
    doc.text('--------------------------------', centerX, y, { align: 'center' });
    y += 5;

    // --- ITEMS ---
    doc.setFontSize(fontSize - 1);
    data.items.forEach((item) => {
      const desc = item.description.substring(0, 20);
      const qty = item.quantity.toString().padStart(3, ' ');
      const price = item.salePrice.toFixed(0).padStart(6, ' ');
      const sub = (item.quantity * item.salePrice).toFixed(0).padStart(7, ' ');
      
      doc.text(`${qty} ${desc}`, margin, y);
      doc.text(`${sub}`, pageWidth - margin, y, { align: 'right' });
      y += 4;
    });

    y += 2;
    doc.text('--------------------------------', centerX, y, { align: 'center' });
    y += 6;

    // --- TOTALES ---
    doc.setFontSize(fontSize + 2);
    doc.setFont(doc.getFont().fontName, 'bold');
    doc.text('TOTAL:', margin, y);
    doc.text(`C$ ${data.total.toFixed(2)}`, pageWidth - margin, y, { align: 'right' });
    
    y += 8;
    doc.setFontSize(fontSize - 2);
    doc.setFont(doc.getFont().fontName, 'normal');
    doc.text(`RECIBIDO: ${data.amountReceived.toFixed(2)}`, margin, y);
    y += 4;
    doc.text(`CAMBIO:   ${data.change.toFixed(2)}`, margin, y);
    y += 4;
    doc.text(`METODO:   ${data.paymentMethod.toUpperCase()}`, margin, y);

    // --- PIE DE PAGINA ---
    y += 10;
    doc.setFontSize(fontSize - 1);
    doc.text(settings.footerLine1 || '¡GRACIAS POR SU COMPRA!', centerX, y, { align: 'center' });
    
    // --- ACCION ---
    // En lugar de guardar, abrimos el diálogo de impresión
    doc.autoPrint();
    window.open(doc.output('bloburl'), '_blank');
  }
}

